import { ColumnMapping, SheetConfig } from './types';

export const DEFAULT_MAPPING: ColumnMapping = {
  uid: 'UID',
  ringStatus: 'RING STATUS',
  date: 'DATE',
  batchNo: 'BATCH NO',
  inward: 'INWARD',
  sku: 'SKU',
  reason: 'REASON'
};

