};

import Papa from 'papaparse';
import { DashboardRow } from '../types';

export const fetchSheetData = async (url: string, sheetName: string): Promise<{ data: DashboardRow[]; headers: string[] }> => {
  try {
    // Extract Spreadsheet ID from typical URLs
    const match = url.match(/\/d\/(.*?)(\/|$)/);
    if (!match) throw new Error("Invalid Google Sheet URL. Please ensure it follows the standard format.");
    const spreadsheetId = match[1];

    // Construct CSV export URL
    const csvUrl = `https://docs.google.com/spreadsheets/d/${spreadsheetId}/gviz/tq?tqx=out:csv&sheet=${encodeURIComponent(sheetName)}`;

    const response = await fetch(csvUrl);
    if (!response.ok) throw new Error("Failed to fetch sheet. Ensure it is shared as 'Anyone with the link can view'.");

    const csvText = await response.text();

    return new Promise((resolve, reject) => {
      Papa.parse(csvText, {
        header: true,
        skipEmptyLines: true,
        complete: (results) => {
          if (results.errors.length > 0 && results.data.length === 0) {
            reject(new Error("CSV parsing failed: " + results.errors[0].message));
          } else {
            resolve({
              data: results.data as DashboardRow[],
              headers: results.meta.fields || []
            });
          }
        },
        error: (error: Error) => reject(error)
      });
    });
  } catch (error: any) {
    throw new Error(error.message || "An error occurred while fetching data.");
  }
};

export const parseDate = (dateStr: string): Date | null => {
  if (!dateStr) return null;
  // Try to handle common formats like DD/MM/YYYY, MM/DD/YYYY, or YYYY-MM-DD
  const d = new Date(dateStr);
  if (!isNaN(d.getTime())) return d;

  // Custom parsing for common G-Sheets style DD/MM/YYYY
  const parts = dateStr.match(/(\d+)/g);
  if (parts && parts.length >= 3) {
    const day = parseInt(parts[0], 10);
    const month = parseInt(parts[1], 10) - 1;
    const year = parts[2].length === 2 ? 2000 + parseInt(parts[2], 10) : parseInt(parts[2], 10);
    const parsed = new Date(year, month, day);
    if (!isNaN(parsed.getTime())) return parsed;
  }

  return null;
};

import React, { useState } from 'react';
import { Settings, X, RefreshCw, ChevronDown } from 'lucide-react';
import { SheetConfig, ColumnMapping } from '../types';

interface SettingsMenuProps {
  config: SheetConfig;
  headers: string[];
  onUpdate: (newConfig: SheetConfig) => void;
  isOpen: boolean;
  setIsOpen: (open: boolean) => void;
  isRefreshing: boolean;
}

const SettingsMenu: React.FC<SettingsMenuProps> = ({ 
  config, 
  headers, 
  onUpdate, 
  isOpen, 
  setIsOpen,
  isRefreshing
}) => {
  const [localConfig, setLocalConfig] = useState(config);

  const handleSave = () => {
    onUpdate(localConfig);
    setIsOpen(false);
  };

  const handleMappingChange = (key: keyof ColumnMapping, value: string) => {
    setLocalConfig(prev => ({
      ...prev,
      mapping: { ...prev.mapping, [key]: value }
    }));
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 overflow-hidden">
      <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setIsOpen(false)} />
      <div className="absolute inset-y-0 right-0 max-w-md w-full bg-white shadow-2xl flex flex-col">
        <div className="p-6 border-b flex justify-between items-center bg-slate-50">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <Settings className="w-5 h-5 text-indigo-600" />
            Dashboard Settings
          </h2>
          <button onClick={() => setIsOpen(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          {/* Source Settings */}
          <section className="space-y-4">
            <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Sheet Source</h3>
            <div className="space-y-3">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Google Sheet URL</label>
                <input 
                  type="text" 
                  className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                  placeholder="https://docs.google.com/spreadsheets/d/..."
                  value={localConfig.url}
                  onChange={e => setLocalConfig({...localConfig, url: e.target.value})}
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Sheet Name</label>
                  <input 
                    type="text" 
                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                    value={localConfig.sheetName}
                    onChange={e => setLocalConfig({...localConfig, sheetName: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Range</label>
                  <input 
                    type="text" 
                    className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                    value={localConfig.range}
                    onChange={e => setLocalConfig({...localConfig, range: e.target.value})}
                  />
                </div>
              </div>
            </div>
          </section>

          {/* Column Mapping */}
          <section className="space-y-4">
            <div className="flex items-center justify-between">
              <h3 className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Column Mapping</h3>
