import React, { useState } from 'react';
import { Calendar, Filter, Check, ChevronDown, Clock } from 'lucide-react';
import { format, subDays, startOfMonth, endOfMonth, isWithinInterval } from 'date-fns';

interface FilterSectionProps {
  batches: string[];
  selectedBatches: string[];
  setSelectedBatches: (batches: string[]) => void;
  dateRange: { start: Date | null; end: Date | null };
  setDateRange: (range: { start: Date | null; end: Date | null }) => void;
}

const FilterSection: React.FC<FilterSectionProps> = ({
  batches,
  selectedBatches,
  setSelectedBatches,
  dateRange,
  setDateRange
}) => {
  const [isBatchOpen, setIsBatchOpen] = useState(false);

  const presets = [
    { label: 'All Time', value: 'all' },
    { label: 'Today', value: 'today' },
    { label: 'Last 7 Days', value: '7d' },
    { label: 'Last 30 Days', value: '30d' },
    { label: 'This Month', value: 'month' },
  ];

  const handlePreset = (type: string) => {
    const today = new Date();
    switch (type) {
      case 'today':
        setDateRange({ start: today, end: today });
        break;
      case '7d':
        setDateRange({ start: subDays(today, 7), end: today });
        break;
      case '30d':
        setDateRange({ start: subDays(today, 30), end: today });
        break;
      case 'month':
        setDateRange({ start: startOfMonth(today), end: endOfMonth(today) });
        break;
      default:
        setDateRange({ start: null, end: null });
    }
  };

  const toggleBatch = (batch: string) => {
    if (selectedBatches.includes(batch)) {
      setSelectedBatches(selectedBatches.filter(b => b !== batch));
    } else {
      setSelectedBatches([...selectedBatches, batch]);
    }
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-4 items-end mb-6 bg-white p-4 rounded-xl shadow-sm border border-slate-200">
      {/* Date Filter */}
      <div className="lg:col-span-8 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-slate-500 uppercase flex items-center gap-1.5">
            <Clock className="w-3.5 h-3.5" /> Quick Presets
          </label>
          <div className="flex flex-wrap gap-2">
            {presets.map(p => (
              <button
                key={p.value}
                onClick={() => handlePreset(p.value)}
                className="px-3 py-1.5 text-xs font-medium rounded-lg border bg-slate-50 hover:bg-slate-100 hover:border-slate-300 transition-all text-slate-700"
              >
                {p.label}
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-slate-500 uppercase flex items-center gap-1.5">
            <Calendar className="w-3.5 h-3.5" /> Start Date
          </label>
          <input
            type="date"
            className="w-full px-3 py-2 text-sm border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-slate-50"
            value={dateRange.start ? format(dateRange.start, 'yyyy-MM-dd') : ''}
            onChange={(e) => setDateRange({ ...dateRange, start: e.target.value ? new Date(e.target.value) : null })}
          />
        </div>

        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-slate-500 uppercase flex items-center gap-1.5">
            <Calendar className="w-3.5 h-3.5" /> End Date
          </label>
          <input
            type="date"
            className="w-full px-3 py-2 text-sm border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none bg-slate-50"
            value={dateRange.end ? format(dateRange.end, 'yyyy-MM-dd') : ''}
            onChange={(e) => setDateRange({ ...dateRange, end: e.target.value ? new Date(e.target.value) : null })}
          />
        </div>
      </div>

      {/* Batch Filter */}
      <div className="lg:col-span-4 space-y-1.5">
        <label className="text-xs font-semibold text-slate-500 uppercase flex items-center gap-1.5">
          <Filter className="w-3.5 h-3.5" /> Batch No
        </label>
        <div className="relative">
          <button
            onClick={() => setIsBatchOpen(!isBatchOpen)}
            className="w-full flex items-center justify-between px-3 py-2 text-sm border rounded-lg bg-slate-50 hover:border-slate-300 transition-colors"
          >
            <span className="truncate">
              {selectedBatches.length === batches.length 
                ? 'All Batches Selected' 
                : selectedBatches.length === 0 
                  ? 'No Batches Selected' 
                  : `${selectedBatches.length} Batches Selected`}
            </span>
            <ChevronDown className="w-4 h-4 text-slate-400" />
          </button>

          {isBatchOpen && (
            <>
              <div className="fixed inset-0 z-10" onClick={() => setIsBatchOpen(false)} />
              <div className="absolute z-20 top-full left-0 right-0 mt-1 bg-white border rounded-lg shadow-xl max-h-60 overflow-y-auto">
                <div className="sticky top-0 bg-slate-50 border-b p-2 flex gap-2">
                  <button 
                    onClick={() => setSelectedBatches(batches)}
                    className="flex-1 px-2 py-1 text-[10px] font-bold uppercase tracking-wider text-indigo-600 bg-indigo-50 rounded hover:bg-indigo-100"
                  >
                    Select All
                  </button>
                  <button 
                    onClick={() => setSelectedBatches([])}
                    className="flex-1 px-2 py-1 text-[10px] font-bold uppercase tracking-wider text-slate-600 bg-slate-100 rounded hover:bg-slate-200"
                  >
                    Deselect All
                  </button>
                </div>
                {batches.map(batch => (
                  <label key={batch} className="flex items-center px-3 py-2 hover:bg-slate-50 cursor-pointer text-sm">
                    <div className="relative flex items-center">
                      <input
                        type="checkbox"
                        className="sr-only"
                        checked={selectedBatches.includes(batch)}
                        onChange={() => toggleBatch(batch)}
                      />
                      <div className={`w-4 h-4 border rounded mr-3 flex items-center justify-center transition-colors ${selectedBatches.includes(batch) ? 'bg-indigo-600 border-indigo-600' : 'bg-white border-slate-300'}`}>
                        {selectedBatches.includes(batch) && <Check className="w-3 h-3 text-white" />}
                      </div>
                    </div>
                    {batch || '(Blank Batch)'}
                  </label>
                ))}
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default FilterSection;

import React from 'react';
import { Layers, CheckCircle, XCircle, Clock, Percent } from 'lucide-react';
import { KPIStats } from '../types';

interface KPIGridProps {
  stats: KPIStats;
}

const KPIGrid: React.FC<KPIGridProps> = ({ stats }) => {
  const cards = [
    { label: 'TOTAL ITEMS', value: stats.total, icon: Layers, color: 'indigo' },
    { label: 'ACCEPTED', value: stats.accepted, icon: CheckCircle, color: 'emerald' },
    { label: 'REJECTED', value: stats.rejected, icon: XCircle, color: 'rose' },
    { label: 'WIP (Inward - Total)', value: stats.wip, icon: Clock, color: 'amber' },
    { label: 'YIELD', value: `${stats.yield.toFixed(1)}%`, icon: Percent, color: 'cyan' },
  ];

  const getColorClasses = (color: string) => {
    switch(color) {
      case 'indigo': return 'bg-indigo-50 text-indigo-700 border-indigo-100';
      case 'emerald': return 'bg-emerald-50 text-emerald-700 border-emerald-100';
      case 'rose': return 'bg-rose-50 text-rose-700 border-rose-100';
      case 'amber': return 'bg-amber-50 text-amber-700 border-amber-100';
      case 'cyan': return 'bg-cyan-50 text-cyan-700 border-cyan-100';
      default: return 'bg-slate-50 text-slate-700 border-slate-100';
    }
  };

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-8">
      {cards.map((card, idx) => (
        <div 
          key={idx} 
          className={`p-5 rounded-2xl border shadow-sm transition-all hover:shadow-md bg-white`}
        >
          <div className="flex items-center justify-between mb-3">
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{card.label}</span>
            <div className={`p-2 rounded-lg ${getColorClasses(card.color).split(' ').slice(0, 2).join(' ')}`}>
              <card.icon className="w-5 h-5" />
            </div>
          </div>
          <div className="flex items-baseline gap-2">
            <h3 className="text-3xl font-bold text-slate-900 tracking-tight">{card.value}</h3>
          </div>
        </div>
      ))}
    </div>
  );
};

export default KPIGrid;

