import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu, AlertCircle, ExternalLink, RefreshCw, BarChart3, Database } from 'lucide-react';
import { INITIAL_CONFIG, DEFAULT_MAPPING } from './constants';
import { SheetConfig, DashboardRow, KPIStats, ChartData } from './types';
import { fetchSheetData, parseDate } from './services/sheetService';
import KPIGrid from './components/KPIGrid';
import FilterSection from './components/FilterSection';
import ChartsSection from './components/ChartsSection';
import SettingsMenu from './components/SettingsMenu';
import { isWithinInterval, startOfDay, endOfDay } from 'date-fns';

const App: React.FC = () => {
  // State
  const [config, setConfig] = useState<SheetConfig>(() => {
    const saved = localStorage.getItem('qc_dashboard_config');
    return saved ? JSON.parse(saved) : INITIAL_CONFIG;
  });

  const [data, setData] = useState<DashboardRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // Filters State
  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });

  // Load data
  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("Please configure a Google Sheet URL in the settings menu.");
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const { data: rawData, headers: sheetHeaders } = await fetchSheetData(config.url, config.sheetName);
      setData(rawData);
      setHeaders(sheetHeaders);

      // Auto-update batch filter with all unique batches initially
      const batchCol = config.mapping.batchNo;
      if (batchCol) {
        const uniqueBatches = Array.from(new Set(rawData.map(r => String(r[batchCol] || '').trim())));
        setSelectedBatches(uniqueBatches);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [config.url, config.sheetName, config.mapping.batchNo]);

  useEffect(() => {
    loadData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleConfigUpdate = (newConfig: SheetConfig) => {
    setConfig(newConfig);
    localStorage.setItem('qc_dashboard_config', JSON.stringify(newConfig));
    // Trigger reload
    setTimeout(() => {
       loadData();
    }, 100);
  };

  // --------------------------------------------------------------------
  // FILTER -> CALCULATE -> DISPLAY
  // --------------------------------------------------------------------

  const filteredData = useMemo(() => {
    const { mapping } = config;
    return data.filter(row => {
      // 1. Date Filter
      if (dateRange.start || dateRange.end) {
        const rowDateStr = String(row[mapping.date] || '');
        const rowDate = parseDate(rowDateStr);
        if (!rowDate) return false;

        const start = dateRange.start ? startOfDay(dateRange.start) : new Date(0);
        const end = dateRange.end ? endOfDay(dateRange.end) : new Date(8640000000000000);

        if (!isWithinInterval(rowDate, { start, end })) return false;
      }

      // 2. Batch Filter
      const rowBatch = String(row[mapping.batchNo] || '').trim();
      if (!selectedBatches.includes(rowBatch)) return false;

      return true;
    });
  }, [data, config, dateRange, selectedBatches]);

  // Unique batches for the filter dropdown
  const allUniqueBatches = useMemo(() => {
    const batchCol = config.mapping.batchNo;
    return Array.from(new Set(data.map(r => String(r[batchCol] || '').trim()))).sort();
  }, [data, config.mapping.batchNo]);

  // KPI Calculations
  const stats: KPIStats = useMemo(() => {
    const { mapping } = config;

    // Total: Count non-empty UID
    const totalData = filteredData.filter(r => String(r[mapping.uid] || '').trim() !== '');
    const total = totalData.length;

    // Accepted: Status === "Accepted"
    const accepted = totalData.filter(r => 
      String(r[mapping.ringStatus] || '').trim().toLowerCase() === 'accepted'
    ).length;

    // Rejected: Status === "Rejected"
    const rejected = totalData.filter(r => 
      String(r[mapping.ringStatus] || '').trim().toLowerCase() === 'rejected'
    ).length;

    // WIP = Inward - Total
    // logic: Count non-empty INWARD − Count non-empty UID
    const inwardCount = filteredData.filter(r => String(r[mapping.inward] || '').trim() !== '').length;
    let wip = inwardCount - total;
    if (wip < 0) wip = 0;

    // Yield = (Accepted / Total) * 100
    const yieldVal = total > 0 ? (accepted / total) * 100 : 0;

    return { total, accepted, rejected, wip, yield: yieldVal };
  }, [filteredData, config]);

  // Chart Data Preparation
  const chartData = useMemo(() => {
    const { mapping } = config;

    // Chart 1: Accepted SKU
    const acceptedRows = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' &&
      String(r[mapping.ringStatus] || '').trim().toLowerCase() === 'accepted'
    );
    const skuAcceptedCounts: Record<string, number> = {};
    acceptedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown').trim();
      skuAcceptedCounts[sku] = (skuAcceptedCounts[sku] || 0) + 1;
    });
    const acceptedSku: ChartData[] = Object.entries(skuAcceptedCounts)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 10);

    // Chart 2: Rejected SKU
    const rejectedRows = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' &&
      String(r[mapping.ringStatus] || '').trim().toLowerCase() === 'rejected'
    );
    const skuRejectedCounts: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown').trim();
      skuRejectedCounts[sku] = (skuRejectedCounts[sku] || 0) + 1;
    });
    const rejectedSku: ChartData[] = Object.entries(skuRejectedCounts)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 10);

    // Chart 3: Rejection Details
    const reasonCounts: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const reason = String(r[mapping.reason] || 'Not Specified').trim();
      reasonCounts[reason] = (reasonCounts[reason] || 0) + 1;
    });
    const rejectionReasons: ChartData[] = Object.entries(reasonCounts)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);

    return { acceptedSku, rejectedSku, rejectionReasons };
  }, [filteredData, config]);

  // Main UI
  return (
    <div className="min-h-screen pb-12">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
