            <div className="flex items-center gap-3">
              <div className="p-2 bg-indigo-600 rounded-lg">
                <BarChart3 className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-lg font-bold text-slate-900 leading-tight">Quality Control</h1>
                <p className="text-[10px] font-medium text-slate-500 uppercase tracking-widest">Master Dashboard</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              {config.url && (
                <button 
                  onClick={loadData}
                  className="hidden sm:flex items-center gap-2 px-3 py-2 text-sm font-medium text-slate-600 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                  disabled={loading}
                >
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  Refresh
                </button>
              )}
              <button 
                onClick={() => setIsSettingsOpen(true)}
                className="p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"
              >
                <Menu className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-6">
        {/* Error State */}
        {error && (
          <div className="mb-8 p-4 bg-rose-50 border border-rose-200 rounded-2xl flex items-start gap-3 animate-in fade-in slide-in-from-top-2">
            <AlertCircle className="w-5 h-5 text-rose-600 shrink-0 mt-0.5" />
            <div className="flex-1">
              <h4 className="text-sm font-bold text-rose-800">Connection Error</h4>
              <p className="text-sm text-rose-700 mt-1">{error}</p>
              <button 
                onClick={() => setIsSettingsOpen(true)}
                className="mt-3 text-sm font-bold text-rose-600 underline hover:text-rose-800 flex items-center gap-1"
              >
                Open Settings to Fix Mapping <ExternalLink className="w-3 h-3" />
              </button>
            </div>
          </div>
        )}

        {/* Empty State / Config Needed */}
        {!config.url && !loading && (
          <div className="py-20 flex flex-col items-center justify-center text-center">
            <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center mb-6">
              <Database className="w-10 h-10 text-indigo-600" />
            </div>
            <h2 className="text-2xl font-bold text-slate-900 mb-2">Connect Your Data Source</h2>
            <p className="text-slate-500 max-w-md mx-auto mb-8">
              Paste your public Google Sheet URL in the settings to start tracking your QC metrics in real-time.
            </p>
            <button 
              onClick={() => setIsSettingsOpen(true)}
              className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-lg shadow-indigo-200 transition-all active:scale-95"
            >
              Configure Now
            </button>
          </div>
        )}

        {/* Loading state overlay */}
        {loading && data.length > 0 && (
          <div className="fixed bottom-8 right-8 z-50 bg-indigo-600 text-white px-4 py-2 rounded-full shadow-xl flex items-center gap-3 animate-bounce">
            <RefreshCw className="w-4 h-4 animate-spin" />
            <span className="text-sm font-bold">Updating Data...</span>
          </div>
        )}

        {/* Dashboard Content */}
        {data.length > 0 && (
          <div className={`${loading && data.length === 0 ? 'opacity-50' : 'opacity-100'} transition-opacity duration-300`}>
            {/* Filter Panel */}
            <FilterSection 
              batches={allUniqueBatches}
              selectedBatches={selectedBatches}
              setSelectedBatches={setSelectedBatches}
              dateRange={dateRange}
              setDateRange={setDateRange}
            />

            {/* KPI Cards */}
            <KPIGrid stats={stats} />

            {/* Filter Results Info */}
            <div className="mb-6 flex items-center justify-between">
              <p className="text-sm text-slate-500">
                Showing results for <span className="font-bold text-slate-800">{filteredData.length}</span> rows
              </p>
              <div className="h-px flex-1 mx-4 bg-slate-200" />
              <p className="text-xs text-slate-400 font-medium italic">Auto-calculated from {config.sheetName}</p>
            </div>

            {/* Chart Sections */}
            <ChartsSection 
              acceptedSku={chartData.acceptedSku}
              rejectedSku={chartData.rejectedSku}
              rejectionReasons={chartData.rejectionReasons}
            />

            {filteredData.length === 0 && (
              <div className="py-12 bg-white rounded-2xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-400">
                <AlertCircle className="w-8 h-8 mb-3" />
                <p className="font-medium">No data matches your current filters.</p>
                <button 
                  onClick={() => { setSelectedBatches(allUniqueBatches); setDateRange({start: null, end: null}); }}
                  className="mt-4 text-indigo-600 font-bold hover:underline"
                >
                  Clear All Filters
                </button>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Settings Side Panel */}
      <SettingsMenu 
        config={config}
        headers={headers}
        onUpdate={handleConfigUpdate}
        isOpen={isSettingsOpen}
        setIsOpen={setIsSettingsOpen}
        isRefreshing={loading}
      />
    </div>
  );
};

export default App;

