  url: string;
  sheetName: string;
  range: string;
  mapping: ColumnMapping;
}

export interface ColumnMapping {
  uid: string;
  ringStatus: string;
  date: string;
  batchNo: string;
  inward: string;
  sku: string;
  reason: string;
  quantity: string; // New field for summing values
}

