          </label>
          <div className="flex flex-wrap gap-2">
            {presets.map(p => (
              <button
                key={p.value}
                onClick={() => handlePreset(p.value)}
                className="px-3 py-1.5 text-[11px] font-bold rounded-lg border border-slate-700 bg-slate-900/50 hover:bg-indigo-600/20 hover:border-indigo-500/50 transition-all text-slate-300 uppercase tracking-tighter"
              >
                {p.label}
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
            <Calendar className="w-3 h-3 text-cyan-400" /> Start
          </label>
          <input
            type="date"
            className="w-full px-3 py-2 text-sm border border-slate-700 rounded-xl focus:ring-2 focus:ring-cyan-500/50 outline-none bg-slate-900 text-slate-100 mono"
            value={dateRange.start ? format(dateRange.start, 'yyyy-MM-dd') : ''}
            onChange={(e) => setDateRange({ ...dateRange, start: e.target.value ? new Date(e.target.value) : null })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
            <Calendar className="w-3 h-3 text-cyan-400" /> End
