          <input
            type="date"
            className="w-full px-3 py-2 text-sm border border-slate-700 rounded-xl focus:ring-2 focus:ring-cyan-500/50 outline-none bg-slate-900 text-slate-100 mono"
            value={dateRange.end ? format(dateRange.end, 'yyyy-MM-dd') : ''}
            onChange={(e) => setDateRange({ ...dateRange, end: e.target.value ? new Date(e.target.value) : null })}
          />
        </div>
      </div>

      <div className="lg:col-span-4 space-y-2">
        <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
          <Filter className="w-3 h-3 text-cyan-400" /> Batch Filter
        </label>
        <div className="relative">
          <button
            onClick={() => setIsBatchOpen(!isBatchOpen)}
            className="w-full flex items-center justify-between px-4 py-2 text-sm border border-slate-700 rounded-xl bg-slate-900 hover:border-slate-500 transition-colors text-slate-100"
          >
            <span className="truncate font-medium">
              {selectedBatches.length === batches.length ? 'ALL BATCHES ACTIVE' : `${selectedBatches.length} SELECTED`}
            </span>
            <ChevronDown className="w-4 h-4 text-slate-500" />
          </button>

          {isBatchOpen && (
            <>
              <div className="fixed inset-0 z-10" onClick={() => setIsBatchOpen(false)} />
              <div className="absolute z-20 top-full left-0 right-0 mt-2 bg-[#16161a] border border-slate-700 rounded-xl shadow-2xl max-h-60 overflow-y-auto p-2 space-y-1">
                <div className="flex gap-2 p-1 mb-1">
                  <button onClick={() => setSelectedBatches(batches)} className="flex-1 py-1.5 text-[10px] font-bold uppercase tracking-widest text-cyan-400 bg-cyan-900/20 rounded-lg hover:bg-cyan-900/40">All</button>
                  <button onClick={() => setSelectedBatches([])} className="flex-1 py-1.5 text-[10px] font-bold uppercase tracking-widest text-slate-400 bg-slate-800 rounded-lg hover:bg-slate-700">None</button>
                </div>
                {batches.map(batch => (
                  <label key={batch} className="flex items-center px-3 py-2 hover:bg-slate-800 rounded-lg cursor-pointer text-sm text-slate-300">
                    <input type="checkbox" className="sr-only" checked={selectedBatches.includes(batch)} onChange={() => {
                      if (selectedBatches.includes(batch)) setSelectedBatches(selectedBatches.filter(b => b !== batch));
                      else setSelectedBatches([...selectedBatches, batch]);
                    }} />
                    <div className={`w-4 h-4 border rounded mr-3 flex items-center justify-center ${selectedBatches.includes(batch) ? 'bg-cyan-500 border-cyan-500' : 'bg-slate-950 border-slate-700'}`}>
                      {selectedBatches.includes(batch) && <Check className="w-3 h-3 text-slate-950" />}
                    </div>
                    {batch || '(Blank)'}
