      <rect 
        x={x} 
        y={y + 2} 
        width={width} 
        height={height - 4} 
        fill="rgba(0,0,0,0.3)" 
        rx={radius}
      />
      {/* Main Bar */}
      <rect 
        x={x} 
        y={y + 2} 
        width={width} 
        height={height - 4} 
        fill={fill} 
        rx={radius} 
        filter={glowId}
        style={{ opacity: 1 }}
