  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });

  // Improved case-insensitive column detection
  const findHeaderMatch = (availableHeaders: string[], searchTerms: string[]): string | undefined => {
    return availableHeaders.find(h => {
      const normalized = h.toLowerCase().replace(/[^a-z]/g, '');
      return searchTerms.some(term => normalized === term.toLowerCase().replace(/[^a-z]/g, ''));
    });
  };

  const autoDetectMapping = useCallback((availableHeaders: string[]) => {
    const mapping = { ...config.mapping };

    // Define aliases for key columns
    const aliases = {
      sku: ['sku', 'skuno', 'itemsku', 'partno', 'productsku', 'itemcode'],
      batchNo: ['batch', 'batchno', 'batchid', 'lotno', 'lot'],
      ringStatus: ['status', 'ringstatus', 'qualitystatus', 'qcstatus', 'result'],
      uid: ['uid', 'id', 'serial', 'serialno', 'slno'],
      date: ['date', 'timestamp', 'createdat'],
    };

    // Update mapping if current ones aren't found
    (Object.entries(aliases) as [keyof typeof aliases, string[]][]).forEach(([key, terms]) => {
      const currentVal = mapping[key as keyof typeof mapping];
      if (!availableHeaders.includes(currentVal)) {
        const detected = findHeaderMatch(availableHeaders, terms);
        if (detected) {
          (mapping as any)[key] = detected;
        }
      }
    });

    return mapping;
  }, [config.mapping]);

  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("CONFIGURATION REQUIRED: Please provide a public Google Sheet URL.");
      return;
