              </div>
              <ChartsSection 
                skuTotal={chartData.skuTotal} 
                isMissingSkuColumn={isSkuColumnMissing}
              />
            </div>
          )
        )}
      </main>

      <SettingsMenu config={headers.length > 0 ? config : {...config, mapping: autoDetectMapping(headers)}} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

