                  <p className="hidden md:block text-[10px] font-bold text-slate-500 uppercase tracking-[0.3em] mono border-l border-slate-800 pl-6">
                    Last Updated: <span className="text-slate-300">{new Date().toLocaleTimeString()}</span>
                  </p>
                </div>
                <p className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.3em] mono">
                  Matched Records: <span className="text-white bg-slate-800 px-2 py-0.5 rounded">{filteredData.length}</span>
                </p>
              </div>
              <ChartsSection 
                skuTotal={chartData.skuTotal} 
                isMissingSkuColumn={isSkuColumnMissing}
              />
            </div>
          )
        )}
      </main>

      <SettingsMenu config={config} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

