import React, { useState, useMemo } from 'react';
import { Search, ChevronUp, ChevronDown, Table as TableIcon } from 'lucide-react';
import { SKUDetail } from '../types';

interface SKUDetailsSectionProps {
  skuDetails: SKUDetail[];
}

type SortConfig = {
  key: keyof SKUDetail;
  direction: 'asc' | 'desc';
};

const SKUDetailsSection: React.FC<SKUDetailsSectionProps> = ({ skuDetails }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: 'total', direction: 'desc' });

  const handleSort = (key: keyof SKUDetail) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc'
    }));
  };

  const filteredAndSortedData = useMemo(() => {
    let data = [...skuDetails];

    // Filter
    if (searchTerm) {
      data = data.filter(item => 
        item.sku.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    // Sort
    data.sort((a, b) => {
      const aVal = a[sortConfig.key];
      const bVal = b[sortConfig.key];

      if (typeof aVal === 'string' && typeof bVal === 'string') {
        return sortConfig.direction === 'asc' 
          ? aVal.localeCompare(bVal) 
          : bVal.localeCompare(aVal);
      }

      return sortConfig.direction === 'asc' 
        ? (aVal as number) - (bVal as number) 
        : (bVal as number) - (aVal as number);
    });

    return data;
  }, [skuDetails, searchTerm, sortConfig]);

  const SortIndicator = ({ column }: { column: keyof SKUDetail }) => {
    if (sortConfig.key !== column) return <div className="w-4 h-4 opacity-0" />;
    return sortConfig.direction === 'asc' 
      ? <ChevronUp className="w-4 h-4 text-indigo-400" /> 
      : <ChevronDown className="w-4 h-4 text-indigo-400" />;
  };

  return (
    <div className="bg-[#0a0a0b] p-8 rounded-2xl border border-slate-900 shadow-2xl mt-10 relative overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="absolute top-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-indigo-500/20 to-transparent" />

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
        <div className="flex items-center gap-4">
          <div className="w-1.5 h-6 bg-indigo-500 rounded-sm shadow-[0_0_15px_rgba(99,102,241,0.8)]" />
          <h3 className="text-sm font-bold text-slate-50 uppercase tracking-[0.3em] mono">
            Detailed SKU Performance
          </h3>
        </div>

        <div className="relative w-full md:w-64">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
          <input
            type="text"
            placeholder="Search SKU..."
            className="w-full pl-10 pr-4 py-2 bg-slate-900/50 border border-slate-800 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder:text-slate-600"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-x-auto rounded-xl border border-slate-800/50">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-900/50 border-b border-slate-800">
              {(['sku', 'total', 'accepted', 'rejected', 'yield'] as const).map((key) => (
                <th 
                  key={key}
                  onClick={() => handleSort(key)}
                  className="px-6 py-4 text-[10px] font-bold text-slate-500 uppercase tracking-widest cursor-pointer hover:bg-slate-800/50 transition-colors group"
                >
                  <div className="flex items-center gap-2">
                    {key.replace(/([A-Z])/g, ' $1')}
                    <SortIndicator column={key} />
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/30">
            {filteredAndSortedData.length > 0 ? (
              filteredAndSortedData.map((item, idx) => (
                <tr key={idx} className="hover:bg-indigo-500/[0.02] transition-colors group">
                  <td className="px-6 py-4 text-sm font-bold text-slate-200 mono">
                    {item.sku}
                  </td>
                  <td className="px-6 py-4 text-sm font-medium text-slate-300 mono">
                    {item.total.toLocaleString()}
                  </td>
                  <td className="px-6 py-4 text-sm font-medium text-emerald-400 mono">
                    {item.accepted.toLocaleString()}
                  </td>
                  <td className="px-6 py-4 text-sm font-medium text-rose-400 mono">
                    {item.rejected.toLocaleString()}
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="flex-1 h-1.5 bg-slate-800 rounded-full overflow-hidden max-w-[100px] hidden sm:block">
                        <div 
                          className={`h-full transition-all duration-1000 ${item.yield > 95 ? 'bg-emerald-500' : item.yield > 80 ? 'bg-amber-500' : 'bg-rose-500'}`}
                          style={{ width: `${item.yield}%` }}
                        />
                      </div>
                      <span className={`text-sm font-bold mono ${item.yield > 95 ? 'text-emerald-400' : item.yield > 80 ? 'text-amber-400' : 'text-rose-400'}`}>
                        {item.yield.toFixed(1)}%
                      </span>
                    </div>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={5} className="px-6 py-12 text-center text-slate-600 italic uppercase text-xs tracking-widest">
                  No matching SKU records identified
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {filteredAndSortedData.length > 0 && (
        <div className="mt-4 flex items-center justify-between px-2">
          <p className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">
            Showing {filteredAndSortedData.length} entries
          </p>
          <div className="flex items-center gap-1 text-[10px] font-bold text-slate-600 uppercase tracking-widest">
            <TableIcon className="w-3 h-3" /> System Export Available
          </div>
        </div>
      )}
    </div>
  );
};

