import React, { useState } from 'react';
import { Calendar, Filter, Check, ChevronDown, Clock } from 'lucide-react';
import { format, subDays, startOfMonth, endOfMonth } from 'date-fns';

interface FilterSectionProps {
  batches: string[];
  selectedBatches: string[];
  setSelectedBatches: (batches: string[]) => void;
  dateRange: { start: Date | null; end: Date | null };
  setDateRange: (range: { start: Date | null; end: Date | null }) => void;
}

const FilterSection: React.FC<FilterSectionProps> = ({
  batches,
  selectedBatches,
  setSelectedBatches,
  dateRange,
  setDateRange
}) => {
  const [isBatchOpen, setIsBatchOpen] = useState(false);

  const presets = [
    { label: 'All Time', value: 'all' },
    { label: 'Yesterday', value: 'yesterday' },
    { label: 'Today', value: 'today' },
    { label: 'Last 7 Days', value: '7d' },
    { label: 'Last 30 Days', value: '30d' },
    { label: 'This Month', value: 'month' },
  ];

  const handlePreset = (type: string) => {
    const today = new Date();
    switch (type) {
      case 'yesterday': {
        const yesterday = subDays(today, 1);
        setDateRange({ start: yesterday, end: yesterday });
        break;
      }
      case 'today': setDateRange({ start: today, end: today }); break;
      case '7d': setDateRange({ start: subDays(today, 7), end: today }); break;
      case '30d': setDateRange({ start: subDays(today, 30), end: today }); break;
      case 'month': setDateRange({ start: startOfMonth(today), end: endOfMonth(today) }); break;
      default: setDateRange({ start: null, end: null });
    }
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-6 items-end mb-8 bg-[#16161a] p-6 rounded-2xl border border-slate-800/50 shadow-2xl">
      <div className="lg:col-span-8 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="space-y-2 lg:col-span-2">
          <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
            <Clock className="w-3 h-3 text-cyan-400" /> Quick Presets
          </label>
          <div className="flex flex-wrap gap-2">
            {presets.map(p => (
              <button
                key={p.value}
                onClick={() => handlePreset(p.value)}
                className="px-3 py-1.5 text-[11px] font-bold rounded-lg border border-slate-700 bg-slate-900/50 hover:bg-indigo-600/20 hover:border-indigo-500/50 transition-all text-slate-300 uppercase tracking-tighter"
              >
                {p.label}
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
            <Calendar className="w-3 h-3 text-cyan-400" /> Start
          </label>
          <input
            type="date"
            className="w-full px-3 py-2 text-sm border border-slate-700 rounded-xl focus:ring-2 focus:ring-cyan-500/50 outline-none bg-slate-900 text-slate-100 mono"
            value={dateRange.start ? format(dateRange.start, 'yyyy-MM-dd') : ''}
            onChange={(e) => setDateRange({ ...dateRange, start: e.target.value ? new Date(e.target.value) : null })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
            <Calendar className="w-3 h-3 text-cyan-400" /> End
          </label>
          <input
            type="date"
            className="w-full px-3 py-2 text-sm border border-slate-700 rounded-xl focus:ring-2 focus:ring-cyan-500/50 outline-none bg-slate-900 text-slate-100 mono"
            value={dateRange.end ? format(dateRange.end, 'yyyy-MM-dd') : ''}
            onChange={(e) => setDateRange({ ...dateRange, end: e.target.value ? new Date(e.target.value) : null })}
          />
        </div>
      </div>

      <div className="lg:col-span-4 space-y-2">
        <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
          <Filter className="w-3 h-3 text-cyan-400" /> Batch Filter
        </label>
        <div className="relative">
          <button
            onClick={() => setIsBatchOpen(!isBatchOpen)}
            className="w-full flex items-center justify-between px-4 py-2 text-sm border border-slate-700 rounded-xl bg-slate-900 hover:border-slate-500 transition-colors text-slate-100"
          >
            <span className="truncate font-medium">
              {selectedBatches.length === batches.length ? 'ALL BATCHES ACTIVE' : `${selectedBatches.length} SELECTED`}
            </span>
            <ChevronDown className="w-4 h-4 text-slate-500" />
          </button>

          {isBatchOpen && (
            <>
              <div className="fixed inset-0 z-10" onClick={() => setIsBatchOpen(false)} />
              <div className="absolute z-20 top-full left-0 right-0 mt-2 bg-[#16161a] border border-slate-700 rounded-xl shadow-2xl max-h-60 overflow-y-auto p-2 space-y-1">
                <div className="flex gap-2 p-1 mb-1">
                  <button onClick={() => setSelectedBatches(batches)} className="flex-1 py-1.5 text-[10px] font-bold uppercase tracking-widest text-cyan-400 bg-cyan-900/20 rounded-lg hover:bg-cyan-900/40">All</button>
                  <button onClick={() => setSelectedBatches([])} className="flex-1 py-1.5 text-[10px] font-bold uppercase tracking-widest text-slate-400 bg-slate-800 rounded-lg hover:bg-slate-700">None</button>
                </div>
                {batches.map(batch => (
                  <label key={batch} className="flex items-center px-3 py-2 hover:bg-slate-800 rounded-lg cursor-pointer text-sm text-slate-300">
                    <input type="checkbox" className="sr-only" checked={selectedBatches.includes(batch)} onChange={() => {
                      if (selectedBatches.includes(batch)) setSelectedBatches(selectedBatches.filter(b => b !== batch));
                      else setSelectedBatches([...selectedBatches, batch]);
                    }} />
                    <div className={`w-4 h-4 border rounded mr-3 flex items-center justify-center ${selectedBatches.includes(batch) ? 'bg-cyan-500 border-cyan-500' : 'bg-slate-950 border-slate-700'}`}>
                      {selectedBatches.includes(batch) && <Check className="w-3 h-3 text-slate-950" />}
                    </div>
                    {batch || '(Blank)'}
                  </label>
                ))}
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default FilterSection;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
