          <div className="flex flex-wrap gap-2">
            {presets.map(p => (
              <button
                key={p.value}
                onClick={() => handlePreset(p.value)}
                className="px-3 py-1.5 text-[11px] font-bold rounded-lg border border-[#0d4032] bg-[#041c14] hover:bg-emerald-600/20 hover:border-emerald-500/50 transition-all text-slate-300 uppercase tracking-tighter"
              >
                {p.label}
              </button>
            ))}
          </div>
        </div>

        <div className="space-y-2">
