interface SKUDetailsSectionProps {
  skuDetails: SKUDetail[];
}

type SortConfig = {
  key: keyof SKUDetail;
  direction: 'asc' | 'desc';
};

const SKUDetailsSection: React.FC<SKUDetailsSectionProps> = ({ skuDetails }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: 'total', direction: 'desc' });

  const handleSort = (key: keyof SKUDetail) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc'
    }));
  };

  const filteredAndSortedData = useMemo(() => {
    let data = [...skuDetails];

    // Filter
    if (searchTerm) {
      data = data.filter(item => 
        item.sku.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    // Sort
    data.sort((a, b) => {
      const aVal = a[sortConfig.key];
      const bVal = b[sortConfig.key];

      if (typeof aVal === 'string' && typeof bVal === 'string') {
        return sortConfig.direction === 'asc' 
          ? aVal.localeCompare(bVal) 
          : bVal.localeCompare(aVal);
      }

      return sortConfig.direction === 'asc' 
        ? (aVal as number) - (bVal as number) 
        : (bVal as number) - (aVal as number);
    });

    return data;
  }, [skuDetails, searchTerm, sortConfig]);

  const SortIndicator = ({ column }: { column: keyof SKUDetail }) => {
    if (sortConfig.key !== column) return <div className="w-4 h-4 opacity-0" />;
    return sortConfig.direction === 'asc' 
      ? <ChevronUp className="w-4 h-4 text-emerald-400" /> 
      : <ChevronDown className="w-4 h-4 text-emerald-400" />;
  };

  return (
    <div className="bg-[#041c14] p-8 rounded-2xl border border-[#0d4032] shadow-2xl mt-10 relative overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="absolute top-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-emerald-500/20 to-transparent" />

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
        <div className="flex items-center gap-4">
          <div className="w-1.5 h-6 bg-emerald-500 rounded-sm shadow-[0_0_15px_rgba(16,185,129,0.8)]" />
          <h3 className="text-sm font-bold text-slate-50 uppercase tracking-[0.3em] mono">
            Detailed SKU Performance
          </h3>
        </div>

        <div className="relative w-full md:w-64">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-emerald-700" />
          <input
            type="text"
            placeholder="Search SKU..."
            className="w-full pl-10 pr-4 py-2 bg-[#062c1e] border border-[#0d4032] rounded-xl text-sm focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all placeholder:text-emerald-800"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-x-auto rounded-xl border border-[#0d4032]/50">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-[#062c1e]/50 border-b border-[#0d4032]">
              {(['sku', 'total', 'accepted', 'rejected', 'yield'] as const).map((key) => (
                <th 
                  key={key}
                  onClick={() => handleSort(key)}
                  className="px-6 py-4 text-[10px] font-bold text-emerald-500/60 uppercase tracking-widest cursor-pointer hover:bg-[#083d2a] transition-colors group"
                >
                  <div className="flex items-center gap-2">
                    {key.replace(/([A-Z])/g, ' $1')}
                    <SortIndicator column={key} />
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-emerald-900/10">
            {filteredAndSortedData.length > 0 ? (
              filteredAndSortedData.map((item, idx) => (
                <tr key={idx} className="hover:bg-emerald-500/[0.03] transition-colors group">
                  <td className="px-6 py-4 text-sm font-bold text-slate-200 mono">
                    {item.sku}
                  </td>
                  <td className="px-6 py-4 text-sm font-medium text-slate-300 mono">
                    {item.total.toLocaleString()}
                  </td>
                  <td className="px-6 py-4 text-sm font-medium text-emerald-400 mono">
                    {item.accepted.toLocaleString()}
                  </td>
                  <td className="px-6 py-4 text-sm font-medium text-rose-400 mono">
                    {item.rejected.toLocaleString()}
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="flex-1 h-1.5 bg-[#021410] rounded-full overflow-hidden max-w-[100px] hidden sm:block">
