export default RemainingQtySection;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu, AlertCircle, ExternalLink, RefreshCw, BarChart3, Database, Copy, Check } from 'lucide-react';
import { INITIAL_CONFIG } from './constants';
import { SheetConfig, DashboardRow, KPIStats, SKUDetail, RemainingQtyItem } from './types';
import { fetchSheetData, parseDate } from './services/sheetService';
import KPIGrid from './components/KPIGrid';
import FilterSection from './components/FilterSection';
import SKUDetailsSection from './components/SKUDetailsSection';
import RemainingQtySection from './components/RemainingQtySection';
import SettingsMenu from './components/SettingsMenu';
import { isWithinInterval, startOfDay, endOfDay } from 'date-fns';

const App: React.FC = () => {
  const [config, setConfig] = useState<SheetConfig>(() => {
    const saved = localStorage.getItem('qc_dashboard_config');
    return saved ? JSON.parse(saved) : INITIAL_CONFIG;
  });

  const [data, setData] = useState<DashboardRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showCopyToast, setShowCopyToast] = useState(false);

  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });

  // Robust column detection with priority on SKU
  const findHeaderMatch = useCallback((availableHeaders: string[], searchTerms: string[]): string | undefined => {
    if (!availableHeaders.length) return undefined;

    const lowerHeaders = availableHeaders.map(h => h.trim().toLowerCase());

    for (const term of searchTerms) {
      const idx = lowerHeaders.indexOf(term.toLowerCase());
      if (idx !== -1) return availableHeaders[idx];
    }

    const contains = availableHeaders.find(h => 
      searchTerms.some(term => h.toLowerCase().includes(term.toLowerCase()))
    );
    if (contains) return contains;

    return availableHeaders.find(h => {
      const normalized = h.toLowerCase().replace(/[^a-z0-9]/g, '');
      return searchTerms.some(term => {
        const termNorm = term.toLowerCase().replace(/[^a-z0-9]/g, '');
        return normalized.includes(termNorm) || termNorm.includes(normalized);
      });
    });
  }, []);

  const autoDetectMapping = useCallback((availableHeaders: string[]) => {
    const mapping = { ...config.mapping };

    const aliases = {
      sku: ['sku', 'item', 'part', 'article', 'model', 'product', 'code'],
      batchNo: ['batch', 'lot', 'serial'],
      ringStatus: ['status', 'result', 'outcome', 'quality'],
      uid: ['uid', 'id', 'barcode', 'serial'],
      date: ['date', 'time', 'timestamp'],
      inward: ['inward', 'qty', 'count', 'total'],
    };

    (Object.entries(aliases) as [keyof typeof aliases, string[]][]).forEach(([key, terms]) => {
      const currentVal = mapping[key as keyof typeof mapping];
      if (!currentVal || !availableHeaders.includes(currentVal)) {
        const detected = findHeaderMatch(availableHeaders, terms);
        if (detected) {
          (mapping as any)[key] = detected;
        }
      }
    });

    return mapping;
  }, [config.mapping, findHeaderMatch]);

  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("CONFIGURATION REQUIRED: Please link a valid public Google Sheet.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const { data: rawData, headers: sheetHeaders } = await fetchSheetData(config.url, config.sheetName);
      setHeaders(sheetHeaders);

      const updatedMapping = autoDetectMapping(sheetHeaders);
      if (JSON.stringify(updatedMapping) !== JSON.stringify(config.mapping)) {
        setConfig(prev => ({ ...prev, mapping: updatedMapping }));
      }

      setData(rawData);

      const batchCol = updatedMapping.batchNo;
      if (batchCol && sheetHeaders.includes(batchCol)) {
        const uniqueBatches = Array.from(new Set(rawData.map(r => String(r[batchCol] || '').trim())))
          .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
        setSelectedBatches(uniqueBatches);
      } else {
        setSelectedBatches([]);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [config.url, config.sheetName, autoDetectMapping]);

  useEffect(() => { 
    if (config.url) loadData(); 
  }, [config.url, config.sheetName]);

  const handleConfigUpdate = (newConfig: SheetConfig) => {
    setConfig(newConfig);
    localStorage.setItem('qc_dashboard_config', JSON.stringify(newConfig));
  };

  const allUniqueBatches = useMemo(() => {
    const batchCol = config.mapping.batchNo;
    if (!batchCol || !headers.includes(batchCol)) return [];
    return Array.from(new Set(data.map(r => String(r[batchCol] || '').trim())))
      .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
  }, [data, config.mapping.batchNo, headers]);

  const filteredData = useMemo(() => {
    const { mapping } = config;
    if (data.length === 0) return [];

    return data.filter(row => {
      if (dateRange.start || dateRange.end) {
        const rowDateStr = String(row[mapping.date] || '');
        const rowDate = parseDate(rowDateStr);
        if (!rowDate) return false;
        const start = dateRange.start ? startOfDay(dateRange.start) : new Date(0);
        const end = dateRange.end ? endOfDay(dateRange.end) : new Date(8640000000000000);
        if (!isWithinInterval(rowDate, { start, end })) return false;
      }
      const batchCol = mapping.batchNo;
      if (batchCol && headers.includes(batchCol) && selectedBatches.length > 0 && selectedBatches.length < allUniqueBatches.length) {
        const rowBatch = String(row[batchCol] || '').trim();
        if (!selectedBatches.includes(rowBatch)) return false;
      }
      return true;
    });
  }, [data, config, dateRange, selectedBatches, headers, allUniqueBatches]);

  const stats: KPIStats = useMemo(() => {
    const { mapping } = config;
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );
    const total = totalData.length;

    const accepted = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    }).length;

    const rejected = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    }).length;

    const inwardCount = filteredData.filter(r => String(r[mapping.inward] || '').trim() !== '').length;
    const wip = Math.max(0, inwardCount - total);
    const yieldVal = total > 0 ? (accepted / total) * 100 : 0;
    return { total, accepted, rejected, wip, yield: yieldVal };
  }, [filteredData, config]);

  const skuDetails = useMemo(() => {
    const { mapping } = config;
    const skuMap: Record<string, { total: number; accepted: number; rejected: number }> = {};

    let skuKey = mapping.sku;
    if (!headers.includes(skuKey)) {
      skuKey = findHeaderMatch(headers, ['sku', 'item', 'part', 'model']) || (headers.length > 0 ? headers[0] : '');
    }

    if (filteredData.length === 0 || !skuKey) {
      return [];
    }

    filteredData.forEach(r => {
      const val = r[skuKey];
      if (val !== undefined && val !== null) {
        const sku = String(val).trim().replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        if (sku !== '') {
          if (!skuMap[sku]) {
            skuMap[sku] = { total: 0, accepted: 0, rejected: 0 };
          }
          skuMap[sku].total += 1;

          const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
          if (['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status)) {
            skuMap[sku].accepted += 1;
          } else if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
            skuMap[sku].rejected += 1;
          }
        }
      }
    });

    return Object.entries(skuMap).map(([sku, s]) => ({
      sku,
      total: s.total,
      accepted: s.accepted,
      rejected: s.rejected,
      yield: s.total > 0 ? (s.accepted / s.total) * 100 : 0
    }));
  }, [filteredData, config, headers, findHeaderMatch]);

  const remainingQtyData = useMemo<RemainingQtyItem[] | null>(() => {
    const hasSkus = headers.includes('SKUs');
    const hasRemainingQty = headers.includes('REMAINING QTY');

    if (!hasSkus || !hasRemainingQty) return null;

    return data
      .map(row => ({
        sku: String(row['SKUs'] || '').trim(),
        qty: Number(row['REMAINING QTY']) || 0
      }))
      .filter(item => item.sku !== '');
  }, [data, headers]);

  const handleCopyReport = () => {
    if (stats.total === 0) {
      alert("No data available");
      return;
    }

    const { mapping } = config;

    // Exact filtering matches used for stats
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );

    // Grouping Accepted SKU details
    const acceptedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    });

    const acceptedGroups: Record<string, number> = {};
    acceptedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown SKU').trim();
      acceptedGroups[sku] = (acceptedGroups[sku] || 0) + 1;
    });

    const acceptedDetailsStr = Object.entries(acceptedGroups)
      .map(([sku, count]) => `${sku}: ${count}`)
      .join('\n');

    // Grouping Rejection Reasons
    const rejectedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    });

    const rejectedGroups: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const reason = String(r[mapping.reason] || 'No Reason Specified').trim();
      rejectedGroups[reason] = (rejectedGroups[reason] || 0) + 1;
    });

    const rejectedDetailsStr = Object.entries(rejectedGroups)
      .map(([reason, count]) => `${reason}: ${count}`)
      .join('\n');

    const reportText = `------------------------------------
BATCH REPORT

TOTAL : ${stats.total}
ACCEPTED : ${stats.accepted}
REJECTED : ${stats.rejected}
YIELD : ${stats.yield.toFixed(1)}%

ACCEPTED DETAILS
${acceptedDetailsStr || 'None'}

REJECTION DETAILS
${rejectedDetailsStr || 'None'}
------------------------------------`;

    navigator.clipboard.writeText(reportText).then(() => {
      setShowCopyToast(true);
      setTimeout(() => setShowCopyToast(false), 3000);
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  return (
    <div className="min-h-screen pb-12">
      <header className="sticky top-0 z-40 bg-[#010a1f]/80 backdrop-blur-xl border-b border-[#0a215c] shadow-2xl">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-blue-600 rounded-xl shadow-[0_0_20px_rgba(37,99,235,0.4)]">
                <BarChart3 className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-bold text-white leading-tight tracking-tight uppercase">Quality Analytics</h1>
                <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.4em] mono">Production Intel Engine</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              {data.length > 0 && (
                <button 
                  onClick={handleCopyReport}
                  className="flex items-center gap-2 px-4 py-2 text-xs font-bold text-slate-100 bg-blue-600/20 hover:bg-blue-600/40 rounded-xl transition-all border border-blue-500/30"
                >
                  <Copy className="w-4 h-4" />
                  COPY BATCH REPORT
                </button>
              )}
              {config.url && (
                <button onClick={loadData} className="hidden sm:flex items-center gap-2 px-4 py-2 text-xs font-bold text-blue-400 hover:text-blue-300 hover:bg-blue-950/30 rounded-xl transition-all border border-transparent hover:border-blue-900/50" disabled={loading}>
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  SYNC DATA
                </button>
              )}
              <button onClick={() => setIsSettingsOpen(true)} className="p-3 bg-[#04143a] text-blue-400 hover:text-white hover:bg-blue-900/50 rounded-xl border border-[#0a215c] transition-all">
                <Menu className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-10">
        {error && (
          <div className="mb-10 p-6 bg-rose-950/30 border border-rose-500/30 rounded-2xl flex items-start gap-4 animate-pulse">
            <AlertCircle className="w-6 h-6 text-rose-500 shrink-0 mt-1" />
            <div className="flex-1">
              <h4 className="text-sm font-bold text-rose-400 uppercase tracking-widest">Protocol Failure</h4>
              <p className="text-sm text-slate-300 mt-2 font-medium">{error}</p>
              <button onClick={() => setIsSettingsOpen(true)} className="mt-4 text-xs font-bold text-rose-500 underline hover:text-rose-400 flex items-center gap-2">
                RE-CONFIGURE MAPPING <ExternalLink className="w-3 h-3" />
              </button>
            </div>
          </div>
        )}

        {(!config.url && !loading) ? (
          <div className="py-32 flex flex-col items-center justify-center text-center">
            <div className="w-24 h-24 bg-[#04143a] rounded-3xl flex items-center justify-center mb-8 border border-[#0a215c] shadow-[0_0_30px_rgba(0,0,0,0.5)]">
              <Database className="w-10 h-10 text-blue-400" />
            </div>
            <h2 className="text-3xl font-bold text-white mb-4 uppercase tracking-tighter">Initialize Stream</h2>
            <p className="text-blue-500/60 max-w-sm mx-auto mb-10 text-sm leading-relaxed">
              System standby. Established connection to public Google Sheets required for analytical rendering.
            </p>
            <button onClick={() => setIsSettingsOpen(true)} className="px-10 py-4 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-2xl shadow-[0_10px_30px_rgba(37,99,235,0.3)] transition-all hover:-translate-y-1">
              OPEN CONFIGURATION
            </button>
          </div>
        ) : (
          data.length > 0 && (
            <div className="animate-in fade-in duration-700">
              <FilterSection batches={allUniqueBatches} selectedBatches={selectedBatches} setSelectedBatches={setSelectedBatches} dateRange={dateRange} setDateRange={setDateRange} />
              <KPIGrid stats={stats} />
              <div className="mb-8 flex items-center justify-between px-2 bg-[#04143a]/30 p-4 rounded-xl border border-blue-900/20">
                <div className="flex items-center gap-6">
                  <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono">
                    Sheet: <span className="text-blue-400">{config.sheetName}</span> | Status: <span className="text-blue-500 underline decoration-blue-500/30">ONLINE</span>
                  </p>
                  <p className="hidden md:block text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono border-l border-blue-900/30 pl-6">
                    Last Updated: <span className="text-slate-300">{new Date().toLocaleTimeString()}</span>
                  </p>
                </div>
                <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono">
                  Records Found: <span className="text-white bg-[#04143a] px-2 py-0.5 rounded border border-blue-900/30">{filteredData.length}</span>
                </p>
              </div>
              <SKUDetailsSection skuDetails={skuDetails} />
              <RemainingQtySection data={remainingQtyData} />
            </div>
          )
        )}
      </main>

      {/* Copy Toast Notification */}
      {showCopyToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-4 fade-in duration-300">
          <div className="px-6 py-3 bg-[#04143a] border border-blue-500/50 rounded-2xl shadow-[0_0_30px_rgba(59,130,246,0.3)] flex items-center gap-3 backdrop-blur-xl">
            <div className="w-8 h-8 rounded-full bg-blue-500/20 flex items-center justify-center">
              <Check className="w-4 h-4 text-blue-400" />
            </div>
            <span className="text-sm font-bold text-slate-100 uppercase tracking-widest">Batch Report Copied</span>
          </div>
        </div>
      )}

      <SettingsMenu config={config} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu, AlertCircle, ExternalLink, RefreshCw, BarChart3, Database, Copy, Check } from 'lucide-react';
import { INITIAL_CONFIG } from './constants';
import { SheetConfig, DashboardRow, KPIStats, SKUDetail, RemainingQtyItem } from './types';
import { fetchSheetData, parseDate } from './services/sheetService';
import KPIGrid from './components/KPIGrid';
import FilterSection from './components/FilterSection';
import SKUDetailsSection from './components/SKUDetailsSection';
import RemainingQtySection from './components/RemainingQtySection';
import RejectionDetailsSection from './components/RejectionDetailsSection';
import SettingsMenu from './components/SettingsMenu';
import { isWithinInterval, startOfDay, endOfDay } from 'date-fns';

const App: React.FC = () => {
  const [config, setConfig] = useState<SheetConfig>(() => {
    const saved = localStorage.getItem('qc_dashboard_config');
    return saved ? JSON.parse(saved) : INITIAL_CONFIG;
  });

  const [data, setData] = useState<DashboardRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showCopyToast, setShowCopyToast] = useState(false);

  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });

  // Robust column detection with priority on SKU
  const findHeaderMatch = useCallback((availableHeaders: string[], searchTerms: string[]): string | undefined => {
    if (!availableHeaders.length) return undefined;

    const lowerHeaders = availableHeaders.map(h => h.trim().toLowerCase());

    for (const term of searchTerms) {
      const idx = lowerHeaders.indexOf(term.toLowerCase());
      if (idx !== -1) return availableHeaders[idx];
    }

    const contains = availableHeaders.find(h => 
      searchTerms.some(term => h.toLowerCase().includes(term.toLowerCase()))
    );
    if (contains) return contains;

    return availableHeaders.find(h => {
      const normalized = h.toLowerCase().replace(/[^a-z0-9]/g, '');
      return searchTerms.some(term => {
        const termNorm = term.toLowerCase().replace(/[^a-z0-9]/g, '');
        return normalized.includes(termNorm) || termNorm.includes(normalized);
      });
    });
  }, []);

  const autoDetectMapping = useCallback((availableHeaders: string[]) => {
    const mapping = { ...config.mapping };

    const aliases = {
      sku: ['sku', 'item', 'part', 'article', 'model', 'product', 'code'],
      batchNo: ['batch', 'lot', 'serial'],
      ringStatus: ['status', 'result', 'outcome', 'quality'],
      uid: ['uid', 'id', 'barcode', 'serial'],
      date: ['date', 'time', 'timestamp'],
      inward: ['inward', 'qty', 'count', 'total'],
      reason: ['reason', 'rejection', 'defect', 'cause', 'fault'],
    };

    (Object.entries(aliases) as [keyof typeof aliases, string[]][]).forEach(([key, terms]) => {
      const currentVal = mapping[key as keyof typeof mapping];
      if (!currentVal || !availableHeaders.includes(currentVal)) {
        const detected = findHeaderMatch(availableHeaders, terms);
        if (detected) {
          (mapping as any)[key] = detected;
        }
      }
    });

    return mapping;
  }, [config.mapping, findHeaderMatch]);

  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("CONFIGURATION REQUIRED: Please link a valid public Google Sheet.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const { data: rawData, headers: sheetHeaders } = await fetchSheetData(config.url, config.sheetName);
      setHeaders(sheetHeaders);

      const updatedMapping = autoDetectMapping(sheetHeaders);
      if (JSON.stringify(updatedMapping) !== JSON.stringify(config.mapping)) {
        setConfig(prev => ({ ...prev, mapping: updatedMapping }));
      }

      setData(rawData);

      const batchCol = updatedMapping.batchNo;
      if (batchCol && sheetHeaders.includes(batchCol)) {
        const uniqueBatches = Array.from(new Set(rawData.map(r => String(r[batchCol] || '').trim())))
          .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
        setSelectedBatches(uniqueBatches);
      } else {
        setSelectedBatches([]);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [config.url, config.sheetName, autoDetectMapping]);

  useEffect(() => { 
    if (config.url) loadData(); 
  }, [config.url, config.sheetName]);

  const handleConfigUpdate = (newConfig: SheetConfig) => {
    setConfig(newConfig);
    localStorage.setItem('qc_dashboard_config', JSON.stringify(newConfig));
  };

  const allUniqueBatches = useMemo(() => {
    const batchCol = config.mapping.batchNo;
    if (!batchCol || !headers.includes(batchCol)) return [];
    return Array.from(new Set(data.map(r => String(r[batchCol] || '').trim())))
      .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
  }, [data, config.mapping.batchNo, headers]);

  const filteredData = useMemo(() => {
    const { mapping } = config;
    if (data.length === 0) return [];

    return data.filter(row => {
      if (dateRange.start || dateRange.end) {
        const rowDateStr = String(row[mapping.date] || '');
        const rowDate = parseDate(rowDateStr);
        if (!rowDate) return false;
        const start = dateRange.start ? startOfDay(dateRange.start) : new Date(0);
        const end = dateRange.end ? endOfDay(dateRange.end) : new Date(8640000000000000);
        if (!isWithinInterval(rowDate, { start, end })) return false;
      }
      const batchCol = mapping.batchNo;
      if (batchCol && headers.includes(batchCol) && selectedBatches.length > 0 && selectedBatches.length < allUniqueBatches.length) {
        const rowBatch = String(row[batchCol] || '').trim();
        if (!selectedBatches.includes(rowBatch)) return false;
      }
      return true;
    });
  }, [data, config, dateRange, selectedBatches, headers, allUniqueBatches]);

  const stats: KPIStats = useMemo(() => {
    const { mapping } = config;
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );
    const total = totalData.length;

    const accepted = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    }).length;

    const rejected = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    }).length;

    const inwardCount = filteredData.filter(r => String(r[mapping.inward] || '').trim() !== '').length;
    const wip = Math.max(0, inwardCount - total);
    const yieldVal = total > 0 ? (accepted / total) * 100 : 0;
    return { total, accepted, rejected, wip, yield: yieldVal };
  }, [filteredData, config]);

  const skuDetails = useMemo(() => {
    const { mapping } = config;
    const skuMap: Record<string, { total: number; accepted: number; rejected: number }> = {};

    let skuKey = mapping.sku;
    if (!headers.includes(skuKey)) {
      skuKey = findHeaderMatch(headers, ['sku', 'item', 'part', 'model']) || (headers.length > 0 ? headers[0] : '');
    }

    if (filteredData.length === 0 || !skuKey) {
      return [];
    }

    filteredData.forEach(r => {
      const val = r[skuKey];
      if (val !== undefined && val !== null) {
        const sku = String(val).trim().replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        if (sku !== '') {
          if (!skuMap[sku]) {
            skuMap[sku] = { total: 0, accepted: 0, rejected: 0 };
          }
          skuMap[sku].total += 1;

          const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
          if (['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status)) {
            skuMap[sku].accepted += 1;
          } else if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
            skuMap[sku].rejected += 1;
          }
        }
      }
    });

    return Object.entries(skuMap).map(([sku, s]) => ({
      sku,
      total: s.total,
      accepted: s.accepted,
      rejected: s.rejected,
      yield: s.total > 0 ? (s.accepted / s.total) * 100 : 0
    }));
  }, [filteredData, config, headers, findHeaderMatch]);

  const remainingQtyData = useMemo<RemainingQtyItem[] | null>(() => {
    const hasSkus = headers.includes('SKUs');
    const hasRemainingQty = headers.includes('REMAINING QTY');

    if (!hasSkus || !hasRemainingQty) return null;

    return data
      .map(row => ({
        sku: String(row['SKUs'] || '').trim(),
        qty: Number(row['REMAINING QTY']) || 0
      }))
      .filter(item => item.sku !== '');
  }, [data, headers]);

  const handleCopyReport = () => {
    if (stats.total === 0) {
      alert("No data available");
      return;
    }

    const { mapping } = config;

    // Exact filtering matches used for stats
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );

    // Grouping Accepted SKU details
    const acceptedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    });

    const acceptedGroups: Record<string, number> = {};
    acceptedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown SKU').trim();
      acceptedGroups[sku] = (acceptedGroups[sku] || 0) + 1;
    });

    const acceptedDetailsStr = Object.entries(acceptedGroups)
      .map(([sku, count]) => `${sku}: ${count}`)
      .join('\n');

    // Grouping Rejection Reasons
    const rejectedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    });

    const rejectedGroups: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const reason = String(r[mapping.reason] || 'No Reason Specified').trim();
      rejectedGroups[reason] = (rejectedGroups[reason] || 0) + 1;
    });

    const rejectedDetailsStr = Object.entries(rejectedGroups)
      .map(([reason, count]) => `${reason}: ${count}`)
      .join('\n');

    const reportText = `------------------------------------
BATCH REPORT

TOTAL : ${stats.total}
ACCEPTED : ${stats.accepted}
REJECTED : ${stats.rejected}
YIELD : ${stats.yield.toFixed(1)}%

ACCEPTED DETAILS
${acceptedDetailsStr || 'None'}

REJECTION DETAILS
${rejectedDetailsStr || 'None'}
------------------------------------`;

    navigator.clipboard.writeText(reportText).then(() => {
      setShowCopyToast(true);
      setTimeout(() => setShowCopyToast(false), 3000);
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  return (
    <div className="min-h-screen pb-12">
      <header className="sticky top-0 z-40 bg-[#010a1f]/80 backdrop-blur-xl border-b border-[#0a215c] shadow-2xl">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-blue-600 rounded-xl shadow-[0_0_20px_rgba(37,99,235,0.4)]">
                <BarChart3 className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-bold text-white leading-tight tracking-tight uppercase">Quality Analytics</h1>
                <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.4em] mono">Production Intel Engine</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              {data.length > 0 && (
                <button 
                  onClick={handleCopyReport}
                  className="flex items-center gap-2 px-4 py-2 text-xs font-bold text-slate-100 bg-blue-600/20 hover:bg-blue-600/40 rounded-xl transition-all border border-blue-500/30"
                >
                  <Copy className="w-4 h-4" />
                  COPY BATCH REPORT
                </button>
              )}
              {config.url && (
                <button onClick={loadData} className="hidden sm:flex items-center gap-2 px-4 py-2 text-xs font-bold text-blue-400 hover:text-blue-300 hover:bg-blue-950/30 rounded-xl transition-all border border-transparent hover:border-blue-900/50" disabled={loading}>
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  SYNC DATA
                </button>
              )}
              <button onClick={() => setIsSettingsOpen(true)} className="p-3 bg-[#04143a] text-blue-400 hover:text-white hover:bg-blue-900/50 rounded-xl border border-[#0a215c] transition-all">
                <Menu className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-10">
        {error && (
          <div className="mb-10 p-6 bg-rose-950/30 border border-rose-500/30 rounded-2xl flex items-start gap-4 animate-pulse">
            <AlertCircle className="w-6 h-6 text-rose-500 shrink-0 mt-1" />
            <div className="flex-1">
              <h4 className="text-sm font-bold text-rose-400 uppercase tracking-widest">Protocol Failure</h4>
              <p className="text-sm text-slate-300 mt-2 font-medium">{error}</p>
              <button onClick={() => setIsSettingsOpen(true)} className="mt-4 text-xs font-bold text-rose-500 underline hover:text-rose-400 flex items-center gap-2">
                RE-CONFIGURE MAPPING <ExternalLink className="w-3 h-3" />
              </button>
            </div>
          </div>
        )}

        {(!config.url && !loading) ? (
          <div className="py-32 flex flex-col items-center justify-center text-center">
            <div className="w-24 h-24 bg-[#04143a] rounded-3xl flex items-center justify-center mb-8 border border-[#0a215c] shadow-[0_0_30px_rgba(0,0,0,0.5)]">
              <Database className="w-10 h-10 text-blue-400" />
            </div>
            <h2 className="text-3xl font-bold text-white mb-4 uppercase tracking-tighter">Initialize Stream</h2>
            <p className="text-blue-500/60 max-w-sm mx-auto mb-10 text-sm leading-relaxed">
              System standby. Established connection to public Google Sheets required for analytical rendering.
            </p>
            <button onClick={() => setIsSettingsOpen(true)} className="px-10 py-4 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-2xl shadow-[0_10px_30px_rgba(37,99,235,0.3)] transition-all hover:-translate-y-1">
              OPEN CONFIGURATION
            </button>
          </div>
        ) : (
          data.length > 0 && (
            <div className="animate-in fade-in duration-700 space-y-10">
              <FilterSection batches={allUniqueBatches} selectedBatches={selectedBatches} setSelectedBatches={setSelectedBatches} dateRange={dateRange} setDateRange={setDateRange} />
              <KPIGrid stats={stats} />
              <div className="flex items-center justify-between px-2 bg-[#04143a]/30 p-4 rounded-xl border border-blue-900/20">
                <div className="flex items-center gap-6">
                  <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono">
                    Sheet: <span className="text-blue-400">{config.sheetName}</span> | Status: <span className="text-blue-500 underline decoration-blue-500/30">ONLINE</span>
                  </p>
                  <p className="hidden md:block text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono border-l border-blue-900/30 pl-6">
                    Last Updated: <span className="text-slate-300">{new Date().toLocaleTimeString()}</span>
                  </p>
                </div>
                <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono">
                  Records Found: <span className="text-white bg-[#04143a] px-2 py-0.5 rounded border border-blue-900/30">{filteredData.length}</span>
                </p>
              </div>
              <SKUDetailsSection skuDetails={skuDetails} />
              <RemainingQtySection data={remainingQtyData} />
              <RejectionDetailsSection filteredData={filteredData} mapping={config.mapping} headers={headers} />
            </div>
          )
        )}
      </main>

      {/* Copy Toast Notification */}
      {showCopyToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-4 fade-in duration-300">
          <div className="px-6 py-3 bg-[#04143a] border border-blue-500/50 rounded-2xl shadow-[0_0_30px_rgba(59,130,246,0.3)] flex items-center gap-3 backdrop-blur-xl">
            <div className="w-8 h-8 rounded-full bg-blue-500/20 flex items-center justify-center">
              <Check className="w-4 h-4 text-blue-400" />
            </div>
            <span className="text-sm font-bold text-slate-100 uppercase tracking-widest">Batch Report Copied</span>
          </div>
        </div>
      )}

      <SettingsMenu config={config} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Search, AlertTriangle, ChevronUp, ChevronDown, ListFilter } from 'lucide-react';
import { DashboardRow, ColumnMapping } from '../types';

interface RejectionDetailsSectionProps {
  filteredData: DashboardRow[];
  mapping: ColumnMapping;
  headers: string[];
}

interface RejectionReasonGroup {
  reason: string;
  count: number;
}

const RejectionDetailsSection: React.FC<RejectionDetailsSectionProps> = ({ filteredData, mapping, headers }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('desc');

  // Logic to process the current filtered dataset for rejections
  const rejectionGroups = useMemo(() => {
    const reasonKey = mapping.reason;
    const statusKey = mapping.ringStatus;

    if (!headers.includes(reasonKey) || !headers.includes(statusKey)) {
      return null;
    }

    const groups: Record<string, number> = {};
    let totalRejected = 0;

    filteredData.forEach(row => {
      const status = String(row[statusKey] || '').trim().toLowerCase();
      // Only process "Rejected" status
      if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
        const reason = String(row[reasonKey] || '').trim();
        // Ignore blank reasons
        if (reason !== '') {
          groups[reason] = (groups[reason] || 0) + 1;
          totalRejected++;
        }
      }
    });

    const result: RejectionReasonGroup[] = Object.entries(groups).map(([reason, count]) => ({
      reason,
      count
    }));

    return { 
      data: result,
      totalCount: totalRejected
    };
  }, [filteredData, mapping, headers]);

  const filteredAndSorted = useMemo(() => {
    if (!rejectionGroups) return [];

    let list = [...rejectionGroups.data];

    // Apply Search
    if (searchTerm) {
      list = list.filter(item => item.reason.toLowerCase().includes(searchTerm.toLowerCase()));
    }

    // Apply Sort
    list.sort((a, b) => {
      return sortDirection === 'desc' ? b.count - a.count : a.count - b.count;
    });

    return list;
  }, [rejectionGroups, searchTerm, sortDirection]);

  // Identify highest count for highlighting
  const maxCount = useMemo(() => {
    if (!rejectionGroups || rejectionGroups.data.length === 0) return 0;
    return Math.max(...rejectionGroups.data.map(i => i.count));
  }, [rejectionGroups]);

  if (!rejectionGroups) {
    return (
      <div className="bg-[#010a1f] p-8 rounded-2xl border border-[#0a215c] shadow-2xl mt-10">
        <div className="flex items-center gap-4 text-rose-500">
          <AlertTriangle className="w-5 h-5" />
          <h3 className="text-sm font-bold uppercase tracking-widest mono">REASON column not found.</h3>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-[#010a1f] p-8 rounded-2xl border border-[#0a215c] shadow-2xl mt-10 relative overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="absolute top-0 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-rose-500/20 to-transparent" />

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
        <div className="flex items-center gap-4">
          <div className="w-1.5 h-6 bg-rose-500 rounded-sm shadow-[0_0_15px_rgba(244,63,94,0.8)]" />
          <h3 className="text-sm font-bold text-slate-50 uppercase tracking-[0.3em] mono">
            REJECTION DETAILS
          </h3>
        </div>

        <div className="relative w-full md:w-64">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-blue-700" />
          <input
            type="text"
            placeholder="Search Reasons..."
            className="w-full pl-10 pr-4 py-2 bg-[#04143a] border border-[#0a215c] rounded-xl text-sm focus:ring-2 focus:ring-blue-500/50 outline-none transition-all placeholder:text-blue-800"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-hidden rounded-xl border border-[#0a215c]/50">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-[#04143a]/80 border-b border-[#0a215c]">
              <th className="px-6 py-4 text-[10px] font-bold text-blue-500/60 uppercase tracking-widest">Rejection Reason</th>
              <th 
                className="px-6 py-4 text-[10px] font-bold text-blue-500/60 uppercase tracking-widest text-right cursor-pointer hover:bg-blue-900/20 transition-colors"
                onClick={() => setSortDirection(prev => prev === 'desc' ? 'asc' : 'desc')}
              >
                <div className="flex items-center justify-end gap-2">
                  Count
                  {sortDirection === 'desc' ? <ChevronDown className="w-3 h-3" /> : <ChevronUp className="w-3 h-3" />}
                </div>
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-blue-900/10">
            {filteredAndSorted.length > 0 ? (
              filteredAndSorted.map((item, idx) => (
                <tr 
                  key={idx} 
                  className={`${idx % 2 === 0 ? 'bg-transparent' : 'bg-[#04143a]/20'} hover:bg-rose-500/[0.03] transition-colors relative group`}
                >
                  <td className="px-6 py-4 text-sm font-bold text-slate-200 mono">
                    <div className="flex items-center gap-3">
                      {item.count === maxCount && item.count > 0 && (
                        <div className="w-1.5 h-1.5 bg-rose-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(244,63,94,1)]" title="Highest Contributor" />
                      )}
                      {item.reason}
                    </div>
                  </td>
                  <td className={`px-6 py-4 text-sm font-bold text-right mono ${item.count === maxCount ? 'text-rose-400' : 'text-slate-300'}`}>
                    {item.count.toLocaleString()}
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={2} className="px-6 py-12 text-center text-blue-900/40 italic uppercase text-xs tracking-widest">
                  No rejection records identified for current parameters
                </td>
              </tr>
            )}
          </tbody>
          {rejectionGroups.totalCount > 0 && (
            <tfoot>
              <tr className="bg-[#04143a]/40 border-t border-[#0a215c]">
                <td className="px-6 py-3 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mono">TOTAL REJECTED</td>
                <td className="px-6 py-3 text-right text-sm font-black text-rose-500 mono">{rejectionGroups.totalCount.toLocaleString()}</td>
              </tr>
            </tfoot>
          )}
        </table>
      </div>

      <div className="mt-6 flex items-center justify-between px-2">
        <p className="text-[10px] font-bold text-blue-800 uppercase tracking-widest">
          {filteredAndSorted.length} Defect Patterns Detected
        </p>
        <div className="flex items-center gap-1 text-[10px] font-bold text-blue-800 uppercase tracking-widest">
          <ListFilter className="w-3 h-3" /> Real-time Pattern Analysis
        </div>
      </div>
    </div>
  );
};

export default RejectionDetailsSection;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu, AlertCircle, ExternalLink, RefreshCw, BarChart3, Database, Copy, Check } from 'lucide-react';
import { INITIAL_CONFIG } from './constants';
import { SheetConfig, DashboardRow, KPIStats, SKUDetail, RemainingQtyItem } from './types';
import { fetchSheetData, parseDate } from './services/sheetService';
import KPIGrid from './components/KPIGrid';
import FilterSection from './components/FilterSection';
import SKUDetailsSection from './components/SKUDetailsSection';
import RemainingQtySection from './components/RemainingQtySection';
import RejectionDetailsSection from './components/RejectionDetailsSection';
import SettingsMenu from './components/SettingsMenu';
import { isWithinInterval, startOfDay, endOfDay } from 'date-fns';

const App: React.FC = () => {
  const [config, setConfig] = useState<SheetConfig>(() => {
    const saved = localStorage.getItem('qc_dashboard_config');
    return saved ? JSON.parse(saved) : INITIAL_CONFIG;
  });

  const [data, setData] = useState<DashboardRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showCopyToast, setShowCopyToast] = useState(false);

  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });

  // Robust column detection with priority on SKU
  const findHeaderMatch = useCallback((availableHeaders: string[], searchTerms: string[]): string | undefined => {
    if (!availableHeaders.length) return undefined;

    const lowerHeaders = availableHeaders.map(h => h.trim().toLowerCase());

    for (const term of searchTerms) {
      const idx = lowerHeaders.indexOf(term.toLowerCase());
      if (idx !== -1) return availableHeaders[idx];
    }

    const contains = availableHeaders.find(h => 
      searchTerms.some(term => h.toLowerCase().includes(term.toLowerCase()))
    );
    if (contains) return contains;

    return availableHeaders.find(h => {
      const normalized = h.toLowerCase().replace(/[^a-z0-9]/g, '');
      return searchTerms.some(term => {
        const termNorm = term.toLowerCase().replace(/[^a-z0-9]/g, '');
        return normalized.includes(termNorm) || termNorm.includes(normalized);
      });
    });
  }, []);

  const autoDetectMapping = useCallback((availableHeaders: string[]) => {
    const mapping = { ...config.mapping };

    const aliases = {
      sku: ['sku', 'item', 'part', 'article', 'model', 'product', 'code'],
      batchNo: ['batch', 'lot', 'serial'],
      ringStatus: ['status', 'result', 'outcome', 'quality'],
      uid: ['uid', 'id', 'barcode', 'serial'],
      date: ['date', 'time', 'timestamp'],
      inward: ['inward', 'qty', 'count', 'total'],
      reason: ['reason', 'rejection', 'defect', 'cause', 'fault'],
    };

    (Object.entries(aliases) as [keyof typeof aliases, string[]][]).forEach(([key, terms]) => {
      const currentVal = mapping[key as keyof typeof mapping];
      if (!currentVal || !availableHeaders.includes(currentVal)) {
        const detected = findHeaderMatch(availableHeaders, terms);
        if (detected) {
          (mapping as any)[key] = detected;
        }
      }
    });

    return mapping;
  }, [config.mapping, findHeaderMatch]);

  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("CONFIGURATION REQUIRED: Please link a valid public Google Sheet.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const { data: rawData, headers: sheetHeaders } = await fetchSheetData(config.url, config.sheetName);
      setHeaders(sheetHeaders);

      const updatedMapping = autoDetectMapping(sheetHeaders);
      if (JSON.stringify(updatedMapping) !== JSON.stringify(config.mapping)) {
        setConfig(prev => ({ ...prev, mapping: updatedMapping }));
      }

      setData(rawData);

      const batchCol = updatedMapping.batchNo;
      if (batchCol && sheetHeaders.includes(batchCol)) {
        const uniqueBatches = Array.from(new Set(rawData.map(r => String(r[batchCol] || '').trim())))
          .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
        setSelectedBatches(uniqueBatches);
      } else {
        setSelectedBatches([]);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [config.url, config.sheetName, autoDetectMapping]);

  useEffect(() => { 
    if (config.url) loadData(); 
  }, [config.url, config.sheetName]);

  const handleConfigUpdate = (newConfig: SheetConfig) => {
    setConfig(newConfig);
    localStorage.setItem('qc_dashboard_config', JSON.stringify(newConfig));
  };

  const allUniqueBatches = useMemo(() => {
    const batchCol = config.mapping.batchNo;
    if (!batchCol || !headers.includes(batchCol)) return [];
    return Array.from(new Set(data.map(r => String(r[batchCol] || '').trim())))
      .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
  }, [data, config.mapping.batchNo, headers]);

  const filteredData = useMemo(() => {
    const { mapping } = config;
    if (data.length === 0) return [];

    return data.filter(row => {
      if (dateRange.start || dateRange.end) {
        const rowDateStr = String(row[mapping.date] || '');
        const rowDate = parseDate(rowDateStr);
        if (!rowDate) return false;
        const start = dateRange.start ? startOfDay(dateRange.start) : new Date(0);
        const end = dateRange.end ? endOfDay(dateRange.end) : new Date(8640000000000000);
        if (!isWithinInterval(rowDate, { start, end })) return false;
      }
      const batchCol = mapping.batchNo;
      if (batchCol && headers.includes(batchCol) && selectedBatches.length > 0 && selectedBatches.length < allUniqueBatches.length) {
        const rowBatch = String(row[batchCol] || '').trim();
        if (!selectedBatches.includes(rowBatch)) return false;
      }
      return true;
    });
  }, [data, config, dateRange, selectedBatches, headers, allUniqueBatches]);

  const stats: KPIStats = useMemo(() => {
    const { mapping } = config;
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );
    const total = totalData.length;

    const accepted = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    }).length;

    const rejected = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    }).length;

    const inwardCount = filteredData.filter(r => String(r[mapping.inward] || '').trim() !== '').length;
    const wip = Math.max(0, inwardCount - total);
    const yieldVal = total > 0 ? (accepted / total) * 100 : 0;
    return { total, accepted, rejected, wip, yield: yieldVal };
  }, [filteredData, config]);

  const skuDetails = useMemo(() => {
    const { mapping } = config;
    const skuMap: Record<string, { total: number; accepted: number; rejected: number }> = {};

    let skuKey = mapping.sku;
    if (!headers.includes(skuKey)) {
      skuKey = findHeaderMatch(headers, ['sku', 'item', 'part', 'model']) || (headers.length > 0 ? headers[0] : '');
    }

    if (filteredData.length === 0 || !skuKey) {
      return [];
    }

    filteredData.forEach(r => {
      const val = r[skuKey];
      if (val !== undefined && val !== null) {
        const sku = String(val).trim().replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        if (sku !== '') {
          if (!skuMap[sku]) {
            skuMap[sku] = { total: 0, accepted: 0, rejected: 0 };
          }
          skuMap[sku].total += 1;

          const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
          if (['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status)) {
            skuMap[sku].accepted += 1;
          } else if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
            skuMap[sku].rejected += 1;
          }
        }
      }
    });

    return Object.entries(skuMap).map(([sku, s]) => ({
      sku,
      total: s.total,
      accepted: s.accepted,
      rejected: s.rejected,
      yield: s.total > 0 ? (s.accepted / s.total) * 100 : 0
    }));
  }, [filteredData, config, headers, findHeaderMatch]);

  const remainingQtyData = useMemo<RemainingQtyItem[] | null>(() => {
    const hasSkus = headers.includes('SKUs');
    const hasRemainingQty = headers.includes('REMAINING QTY');

    if (!hasSkus || !hasRemainingQty) return null;

    return data
      .map(row => ({
        sku: String(row['SKUs'] || '').trim(),
        qty: Number(row['REMAINING QTY']) || 0
      }))
      .filter(item => item.sku !== '');
  }, [data, headers]);

  const handleCopyReport = () => {
    if (stats.total === 0) {
      alert("No data available");
      return;
    }

    const { mapping } = config;

    // Exact filtering matches used for stats
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );

    // Grouping Accepted SKU details
    const acceptedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    });

    const acceptedGroups: Record<string, number> = {};
    acceptedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown SKU').trim();
      acceptedGroups[sku] = (acceptedGroups[sku] || 0) + 1;
    });

    const acceptedDetailsStr = Object.entries(acceptedGroups)
      .map(([sku, count]) => `${sku}: ${count}`)
      .join('\n');

    // Grouping Rejection Reasons
    const rejectedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    });

    const rejectedGroups: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const reason = String(r[mapping.reason] || 'No Reason Specified').trim();
      rejectedGroups[reason] = (rejectedGroups[reason] || 0) + 1;
    });

    const rejectedDetailsStr = Object.entries(rejectedGroups)
      .map(([reason, count]) => `${reason}: ${count}`)
      .join('\n');

    const reportText = `------------------------------------
BATCH REPORT

TOTAL : ${stats.total}
ACCEPTED : ${stats.accepted}
REJECTED : ${stats.rejected}
YIELD : ${stats.yield.toFixed(1)}%

ACCEPTED DETAILS
${acceptedDetailsStr || 'None'}

REJECTION DETAILS
${rejectedDetailsStr || 'None'}
------------------------------------`;

    navigator.clipboard.writeText(reportText).then(() => {
      setShowCopyToast(true);
      setTimeout(() => setShowCopyToast(false), 3000);
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  return (
    <div className="min-h-screen pb-12 w-full max-w-[100vw]">
      <header className="sticky top-0 z-40 bg-[#010a1f]/80 backdrop-blur-xl border-b border-[#0a215c] shadow-2xl w-full">
        <div className="w-full px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-blue-600 rounded-xl shadow-[0_0_20px_rgba(37,99,235,0.4)]">
                <BarChart3 className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-bold text-white leading-tight tracking-tight uppercase">Quality Analytics</h1>
                <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.4em] mono">Production Intel Engine</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              {data.length > 0 && (
                <button 
                  onClick={handleCopyReport}
                  className="flex items-center gap-2 px-4 py-2 text-xs font-bold text-slate-100 bg-blue-600/20 hover:bg-blue-600/40 rounded-xl transition-all border border-blue-500/30"
                >
                  <Copy className="w-4 h-4" />
                  COPY BATCH REPORT
                </button>
              )}
              {config.url && (
                <button onClick={loadData} className="hidden sm:flex items-center gap-2 px-4 py-2 text-xs font-bold text-blue-400 hover:text-blue-300 hover:bg-blue-950/30 rounded-xl transition-all border border-transparent hover:border-blue-900/50" disabled={loading}>
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  SYNC DATA
                </button>
              )}
              <button onClick={() => setIsSettingsOpen(true)} className="p-3 bg-[#04143a] text-blue-400 hover:text-white hover:bg-blue-900/50 rounded-xl border border-[#0a215c] transition-all">
                <Menu className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full px-4 sm:px-6 lg:px-8 mt-10">
        {error && (
          <div className="mb-10 p-6 bg-rose-950/30 border border-rose-500/30 rounded-2xl flex items-start gap-4 animate-pulse">
            <AlertCircle className="w-6 h-6 text-rose-500 shrink-0 mt-1" />
            <div className="flex-1">
              <h4 className="text-sm font-bold text-rose-400 uppercase tracking-widest">Protocol Failure</h4>
              <p className="text-sm text-slate-300 mt-2 font-medium">{error}</p>
              <button onClick={() => setIsSettingsOpen(true)} className="mt-4 text-xs font-bold text-rose-500 underline hover:text-rose-400 flex items-center gap-2">
                RE-CONFIGURE MAPPING <ExternalLink className="w-3 h-3" />
              </button>
            </div>
          </div>
        )}

        {(!config.url && !loading) ? (
          <div className="py-32 flex flex-col items-center justify-center text-center">
            <div className="w-24 h-24 bg-[#04143a] rounded-3xl flex items-center justify-center mb-8 border border-[#0a215c] shadow-[0_0_30px_rgba(0,0,0,0.5)]">
              <Database className="w-10 h-10 text-blue-400" />
            </div>
            <h2 className="text-3xl font-bold text-white mb-4 uppercase tracking-tighter">Initialize Stream</h2>
            <p className="text-blue-500/60 max-w-sm mx-auto mb-10 text-sm leading-relaxed">
              System standby. Established connection to public Google Sheets required for analytical rendering.
            </p>
            <button onClick={() => setIsSettingsOpen(true)} className="px-10 py-4 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-2xl shadow-[0_10px_30px_rgba(37,99,235,0.3)] transition-all hover:-translate-y-1">
              OPEN CONFIGURATION
            </button>
          </div>
        ) : (
          data.length > 0 && (
            <div className="animate-in fade-in duration-700 space-y-10 w-full">
              <FilterSection batches={allUniqueBatches} selectedBatches={selectedBatches} setSelectedBatches={setSelectedBatches} dateRange={dateRange} setDateRange={setDateRange} />
              <KPIGrid stats={stats} />
              <div className="flex items-center justify-between px-2 bg-[#04143a]/30 p-4 rounded-xl border border-blue-900/20">
                <div className="flex items-center gap-6">
                  <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono">
                    Sheet: <span className="text-blue-400">{config.sheetName}</span> | Status: <span className="text-blue-500 underline decoration-blue-500/30">ONLINE</span>
                  </p>
                  <p className="hidden md:block text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono border-l border-blue-900/30 pl-6">
                    Last Updated: <span className="text-slate-300">{new Date().toLocaleTimeString()}</span>
                  </p>
                </div>
                <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono">
                  Records Found: <span className="text-white bg-[#04143a] px-2 py-0.5 rounded border border-blue-900/30">{filteredData.length}</span>
                </p>
              </div>
              <SKUDetailsSection skuDetails={skuDetails} />
              <RemainingQtySection data={remainingQtyData} />
              <RejectionDetailsSection filteredData={filteredData} mapping={config.mapping} headers={headers} />
            </div>
          )
        )}
      </main>

      {/* Copy Toast Notification */}
      {showCopyToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-4 fade-in duration-300">
          <div className="px-6 py-3 bg-[#04143a] border border-blue-500/50 rounded-2xl shadow-[0_0_30px_rgba(59,130,246,0.3)] flex items-center gap-3 backdrop-blur-xl">
            <div className="w-8 h-8 rounded-full bg-blue-500/20 flex items-center justify-center">
              <Check className="w-4 h-4 text-blue-400" />
            </div>
            <span className="text-sm font-bold text-slate-100 uppercase tracking-widest">Batch Report Copied</span>
          </div>
        </div>
      )}

      <SettingsMenu config={config} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

export default App;

import React from 'react';
import { Layers, CheckCircle, XCircle, Clock, Percent } from 'lucide-react';
import { KPIStats } from '../types';

interface KPIGridProps {
  stats: KPIStats;
}

const KPIGrid: React.FC<KPIGridProps> = ({ stats }) => {
  const cards = [
    { label: 'TOTAL ITEMS', value: stats.total, icon: Layers, color: 'blue' },
    { label: 'ACCEPTED', value: stats.accepted, icon: CheckCircle, color: 'blue' },
    { label: 'REJECTED', value: stats.rejected, icon: XCircle, color: 'rose' },
    { label: 'WIP INVENTORY', value: stats.wip, icon: Clock, color: 'amber' },
    { label: 'OVERALL YIELD', value: `${stats.yield.toFixed(1)}%`, icon: Percent, color: 'cyan' },
  ];

  const getColorClasses = (color: string) => {
    switch(color) {
      case 'blue': return 'text-blue-400 bg-blue-400/10 border-blue-500/20';
      case 'rose': return 'text-rose-400 bg-rose-400/10 border-rose-500/20';
      case 'cyan': return 'text-cyan-400 bg-cyan-400/10 border-cyan-500/20';
      case 'amber': return 'text-amber-400 bg-amber-400/10 border-amber-500/20';
      default: return 'text-blue-400 bg-blue-400/10 border-blue-500/20';
    }
  };

  return (
    <div className="grid grid-cols-[repeat(auto-fit,minmax(280px,1fr))] gap-4 mb-8 w-full">
      {cards.map((card, idx) => (
        <div key={idx} className="p-6 rounded-2xl border border-[#0a215c] bg-[#04143a] hover:border-blue-500/30 transition-all group min-w-0">
          <div className="flex items-center justify-between mb-4">
            <span className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.2em]">{card.label}</span>
            <div className={`p-2 rounded-lg border ${getColorClasses(card.color)}`}>
              <card.icon className="w-4 h-4" />
            </div>
          </div>
          <div className="flex items-baseline">
            <h3 className="text-3xl font-bold text-slate-50 tracking-tighter mono truncate">
              {card.value}
            </h3>
          </div>
        </div>
      ))}
    </div>
  );
};

export default KPIGrid;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu, AlertCircle, ExternalLink, RefreshCw, BarChart3, Database, Copy, Check } from 'lucide-react';
import { INITIAL_CONFIG } from './constants';
import { SheetConfig, DashboardRow, KPIStats, SKUDetail, RemainingQtyItem } from './types';
import { fetchSheetData, parseDate } from './services/sheetService';
import KPIGrid from './components/KPIGrid';
import FilterSection from './components/FilterSection';
import SKUDetailsSection from './components/SKUDetailsSection';
import RemainingQtySection from './components/RemainingQtySection';
import RejectionDetailsSection from './components/RejectionDetailsSection';
import SettingsMenu from './components/SettingsMenu';
import { isWithinInterval, startOfDay, endOfDay } from 'date-fns';

const App: React.FC = () => {
  const [config, setConfig] = useState<SheetConfig>(() => {
    const saved = localStorage.getItem('qc_dashboard_config');
    return saved ? JSON.parse(saved) : INITIAL_CONFIG;
  });

  const [data, setData] = useState<DashboardRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showCopyToast, setShowCopyToast] = useState(false);

  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });

  // Robust column detection with priority on SKU
  const findHeaderMatch = useCallback((availableHeaders: string[], searchTerms: string[]): string | undefined => {
    if (!availableHeaders.length) return undefined;

    const lowerHeaders = availableHeaders.map(h => h.trim().toLowerCase());

    for (const term of searchTerms) {
      const idx = lowerHeaders.indexOf(term.toLowerCase());
      if (idx !== -1) return availableHeaders[idx];
    }

    const contains = availableHeaders.find(h => 
      searchTerms.some(term => h.toLowerCase().includes(term.toLowerCase()))
    );
    if (contains) return contains;

    return availableHeaders.find(h => {
      const normalized = h.toLowerCase().replace(/[^a-z0-9]/g, '');
      return searchTerms.some(term => {
        const termNorm = term.toLowerCase().replace(/[^a-z0-9]/g, '');
        return normalized.includes(termNorm) || termNorm.includes(normalized);
      });
    });
  }, []);

  const autoDetectMapping = useCallback((availableHeaders: string[]) => {
    const mapping = { ...config.mapping };

    const aliases = {
      sku: ['sku', 'item', 'part', 'article', 'model', 'product', 'code'],
      batchNo: ['batch', 'lot', 'serial'],
      ringStatus: ['status', 'result', 'outcome', 'quality'],
      uid: ['uid', 'id', 'barcode', 'serial'],
      date: ['date', 'time', 'timestamp'],
      inward: ['inward', 'qty', 'count', 'total'],
      reason: ['reason', 'rejection', 'defect', 'cause', 'fault'],
    };

    (Object.entries(aliases) as [keyof typeof aliases, string[]][]).forEach(([key, terms]) => {
      const currentVal = mapping[key as keyof typeof mapping];
      if (!currentVal || !availableHeaders.includes(currentVal)) {
        const detected = findHeaderMatch(availableHeaders, terms);
        if (detected) {
          (mapping as any)[key] = detected;
        }
      }
    });

    return mapping;
  }, [config.mapping, findHeaderMatch]);

  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("CONFIGURATION REQUIRED: Please link a valid public Google Sheet.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const { data: rawData, headers: sheetHeaders } = await fetchSheetData(config.url, config.sheetName);
      setHeaders(sheetHeaders);

      const updatedMapping = autoDetectMapping(sheetHeaders);
      if (JSON.stringify(updatedMapping) !== JSON.stringify(config.mapping)) {
        setConfig(prev => ({ ...prev, mapping: updatedMapping }));
      }

      setData(rawData);

      const batchCol = updatedMapping.batchNo;
      if (batchCol && sheetHeaders.includes(batchCol)) {
        const uniqueBatches = Array.from(new Set(rawData.map(r => String(r[batchCol] || '').trim())))
          .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
        setSelectedBatches(uniqueBatches);
      } else {
        setSelectedBatches([]);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [config.url, config.sheetName, autoDetectMapping]);

  useEffect(() => { 
    if (config.url) loadData(); 
  }, [config.url, config.sheetName]);

  const handleConfigUpdate = (newConfig: SheetConfig) => {
    setConfig(newConfig);
    localStorage.setItem('qc_dashboard_config', JSON.stringify(newConfig));
  };

  const allUniqueBatches = useMemo(() => {
    const batchCol = config.mapping.batchNo;
    if (!batchCol || !headers.includes(batchCol)) return [];
    return Array.from(new Set(data.map(r => String(r[batchCol] || '').trim())))
      .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
  }, [data, config.mapping.batchNo, headers]);

  const filteredData = useMemo(() => {
    const { mapping } = config;
    if (data.length === 0) return [];

    return data.filter(row => {
      if (dateRange.start || dateRange.end) {
        const rowDateStr = String(row[mapping.date] || '');
        const rowDate = parseDate(rowDateStr);
        if (!rowDate) return false;
        const start = dateRange.start ? startOfDay(dateRange.start) : new Date(0);
        const end = dateRange.end ? endOfDay(dateRange.end) : new Date(8640000000000000);
        if (!isWithinInterval(rowDate, { start, end })) return false;
      }
      const batchCol = mapping.batchNo;
      if (batchCol && headers.includes(batchCol) && selectedBatches.length > 0 && selectedBatches.length < allUniqueBatches.length) {
        const rowBatch = String(row[batchCol] || '').trim();
        if (!selectedBatches.includes(rowBatch)) return false;
      }
      return true;
    });
  }, [data, config, dateRange, selectedBatches, headers, allUniqueBatches]);

  const stats: KPIStats = useMemo(() => {
    const { mapping } = config;
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );
    const total = totalData.length;

    const accepted = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    }).length;

    const rejected = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    }).length;

    const inwardCount = filteredData.filter(r => String(r[mapping.inward] || '').trim() !== '').length;
    const wip = Math.max(0, inwardCount - total);
    const yieldVal = total > 0 ? (accepted / total) * 100 : 0;
    return { total, accepted, rejected, wip, yield: yieldVal };
  }, [filteredData, config]);

  const skuDetails = useMemo(() => {
    const { mapping } = config;
    const skuMap: Record<string, { total: number; accepted: number; rejected: number }> = {};

    let skuKey = mapping.sku;
    if (!headers.includes(skuKey)) {
      skuKey = findHeaderMatch(headers, ['sku', 'item', 'part', 'model']) || (headers.length > 0 ? headers[0] : '');
    }

    if (filteredData.length === 0 || !skuKey) {
      return [];
    }

    filteredData.forEach(r => {
      const val = r[skuKey];
      if (val !== undefined && val !== null) {
        const sku = String(val).trim().replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        if (sku !== '') {
          if (!skuMap[sku]) {
            skuMap[sku] = { total: 0, accepted: 0, rejected: 0 };
          }
          skuMap[sku].total += 1;

          const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
          if (['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status)) {
            skuMap[sku].accepted += 1;
          } else if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
            skuMap[sku].rejected += 1;
          }
        }
      }
    });

    return Object.entries(skuMap).map(([sku, s]) => ({
      sku,
      total: s.total,
      accepted: s.accepted,
      rejected: s.rejected,
      yield: s.total > 0 ? (s.accepted / s.total) * 100 : 0
    }));
  }, [filteredData, config, headers, findHeaderMatch]);

  const remainingQtyData = useMemo<RemainingQtyItem[] | null>(() => {
    const hasSkus = headers.includes('SKUs');
    const hasRemainingQty = headers.includes('REMAINING QTY');

    if (!hasSkus || !hasRemainingQty) return null;

    return data
      .map(row => ({
        sku: String(row['SKUs'] || '').trim(),
        qty: Number(row['REMAINING QTY']) || 0
      }))
      .filter(item => item.sku !== '');
  }, [data, headers]);

  const handleCopyReport = () => {
    if (stats.total === 0) {
      alert("No data available");
      return;
    }

    const { mapping } = config;

    // Exact filtering matches used for stats
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );

    // Grouping Accepted SKU details
    const acceptedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    });

    const acceptedGroups: Record<string, number> = {};
    acceptedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown SKU').trim();
      acceptedGroups[sku] = (acceptedGroups[sku] || 0) + 1;
    });

    const acceptedDetailsStr = Object.entries(acceptedGroups)
      .map(([sku, count]) => `${sku}: ${count}`)
      .join('\n');

    // Grouping Rejection Reasons
    const rejectedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    });

    const rejectedGroups: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const reason = String(r[mapping.reason] || 'No Reason Specified').trim();
      rejectedGroups[reason] = (rejectedGroups[reason] || 0) + 1;
    });

    const rejectedDetailsStr = Object.entries(rejectedGroups)
      .map(([reason, count]) => `${reason}: ${count}`)
      .join('\n');

    const reportText = `------------------------------------
BATCH REPORT

TOTAL : ${stats.total}
ACCEPTED : ${stats.accepted}
REJECTED : ${stats.rejected}
YIELD : ${stats.yield.toFixed(1)}%

ACCEPTED DETAILS
${acceptedDetailsStr || 'None'}

REJECTION DETAILS
${rejectedDetailsStr || 'None'}
------------------------------------`;

    navigator.clipboard.writeText(reportText).then(() => {
      setShowCopyToast(true);
      setTimeout(() => setShowCopyToast(false), 3000);
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  return (
    <div className="min-h-screen pb-12 w-full max-w-[100vw]">
      <header className="sticky top-0 z-40 bg-[#010a1f]/80 backdrop-blur-xl border-b border-[#0a215c] shadow-2xl w-full">
        <div className="w-full px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-blue-600 rounded-xl shadow-[0_0_20px_rgba(37,99,235,0.4)]">
                <BarChart3 className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-bold text-white leading-tight tracking-tight uppercase">Quality Analytics</h1>
                <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.4em] mono">Production Intel Engine</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              {data.length > 0 && (
                <button 
                  onClick={handleCopyReport}
                  className="flex items-center gap-2 px-4 py-2 text-xs font-bold text-slate-100 bg-blue-600/20 hover:bg-blue-600/40 rounded-xl transition-all border border-blue-500/30"
                >
                  <Copy className="w-4 h-4" />
                  COPY BATCH REPORT
                </button>
              )}
              {config.url && (
                <button onClick={loadData} className="hidden sm:flex items-center gap-2 px-4 py-2 text-xs font-bold text-blue-400 hover:text-blue-300 hover:bg-blue-950/30 rounded-xl transition-all border border-transparent hover:border-blue-900/50" disabled={loading}>
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  SYNC DATA
                </button>
              )}
              <button onClick={() => setIsSettingsOpen(true)} className="p-3 bg-[#04143a] text-blue-400 hover:text-white hover:bg-blue-900/50 rounded-xl border border-[#0a215c] transition-all">
                <Menu className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full px-4 sm:px-6 lg:px-8 mt-10">
        {error && (
          <div className="mb-10 p-6 bg-rose-950/30 border border-rose-500/30 rounded-2xl flex items-start gap-4 animate-pulse">
            <AlertCircle className="w-6 h-6 text-rose-500 shrink-0 mt-1" />
            <div className="flex-1">
              <h4 className="text-sm font-bold text-rose-400 uppercase tracking-widest">Protocol Failure</h4>
              <p className="text-sm text-slate-300 mt-2 font-medium">{error}</p>
              <button onClick={() => setIsSettingsOpen(true)} className="mt-4 text-xs font-bold text-rose-500 underline hover:text-rose-400 flex items-center gap-2">
                RE-CONFIGURE MAPPING <ExternalLink className="w-3 h-3" />
              </button>
            </div>
          </div>
        )}

        {(!config.url && !loading) ? (
          <div className="py-32 flex flex-col items-center justify-center text-center">
            <div className="w-24 h-24 bg-[#04143a] rounded-3xl flex items-center justify-center mb-8 border border-[#0a215c] shadow-[0_0_30px_rgba(0,0,0,0.5)]">
              <Database className="w-10 h-10 text-blue-400" />
            </div>
            <h2 className="text-3xl font-bold text-white mb-4 uppercase tracking-tighter">Initialize Stream</h2>
            <p className="text-blue-500/60 max-sm mx-auto mb-10 text-sm leading-relaxed">
              System standby. Established connection to public Google Sheets required for analytical rendering.
            </p>
            <button onClick={() => setIsSettingsOpen(true)} className="px-10 py-4 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-2xl shadow-[0_10px_30px_rgba(37,99,235,0.3)] transition-all hover:-translate-y-1">
              OPEN CONFIGURATION
            </button>
          </div>
        ) : (
          data.length > 0 && (
            <div className="animate-in fade-in duration-700 space-y-10 w-full">
              <FilterSection batches={allUniqueBatches} selectedBatches={selectedBatches} setSelectedBatches={setSelectedBatches} dateRange={dateRange} setDateRange={setDateRange} />
              <KPIGrid stats={stats} />
              <div className="flex items-center justify-between px-2 bg-[#04143a]/30 p-4 rounded-xl border border-blue-900/20">
                <div className="flex items-center gap-6">
                  <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono">
                    Sheet: <span className="text-blue-400">{config.sheetName}</span> | Status: <span className="text-blue-500 underline decoration-blue-500/30">ONLINE</span>
                  </p>
                  <p className="hidden md:block text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono border-l border-blue-900/30 pl-6">
                    Last Updated: <span className="text-slate-300">{new Date().toLocaleTimeString()}</span>
                  </p>
                </div>
                <p className="text-[10px] font-bold text-blue-500/60 uppercase tracking-[0.3em] mono">
                  Records Found: <span className="text-white bg-[#04143a] px-2 py-0.5 rounded border border-blue-900/30">{filteredData.length}</span>
                </p>
              </div>
              <SKUDetailsSection skuDetails={skuDetails} />

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 items-stretch">
                <RemainingQtySection data={remainingQtyData} />
                <RejectionDetailsSection filteredData={filteredData} mapping={config.mapping} headers={headers} />
              </div>
            </div>
          )
        )}
      </main>

      {/* Copy Toast Notification */}
      {showCopyToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-4 fade-in duration-300">
          <div className="px-6 py-3 bg-[#04143a] border border-blue-500/50 rounded-2xl shadow-[0_0_30px_rgba(59,130,246,0.3)] flex items-center gap-3 backdrop-blur-xl">
            <div className="w-8 h-8 rounded-full bg-blue-500/20 flex items-center justify-center">
              <Check className="w-4 h-4 text-blue-400" />
            </div>
            <span className="text-sm font-bold text-slate-100 uppercase tracking-widest">Batch Report Copied</span>
          </div>
        </div>
      )}

      <SettingsMenu config={config} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

