import React, { useState, useEffect } from 'react';
import { Layers, CheckCircle, XCircle, Clock, Percent } from 'lucide-react';
import { KPIStats } from '../types';

interface KPIGridProps {
  stats: KPIStats;
  loading?: boolean;
}

const CountUp: React.FC<{ end: number | string; duration?: number; suffix?: string }> = ({ end, duration = 600, suffix = '' }) => {
  const numericEnd = typeof end === 'string' ? parseFloat(end) : end;
  const isPercent = suffix === '%';
  const [count, setCount] = useState(0);

  useEffect(() => {
    let startTime: number | null = null;
    const step = (timestamp: number) => {
      if (!startTime) startTime = timestamp;
      const progress = Math.min((timestamp - startTime) / duration, 1);
      const currentCount = progress * numericEnd;
      setCount(currentCount);
      if (progress < 1) {
        window.requestAnimationFrame(step);
      }
    };
    window.requestAnimationFrame(step);
  }, [numericEnd, duration]);

  return <span>{isPercent ? count.toFixed(1) : Math.floor(count).toLocaleString()}{suffix}</span>;
};

const KPIGrid: React.FC<KPIGridProps> = ({ stats, loading }) => {
  const cards = [
    { label: 'TOTAL ITEMS', value: stats.total, icon: Layers, color: 'blue', suffix: '' },
    { label: 'ACCEPTED', value: stats.accepted, icon: CheckCircle, color: 'green', suffix: '' },
    { label: 'REJECTED', value: stats.rejected, icon: XCircle, color: 'rose', suffix: '' },
    { label: 'WIP INVENTORY', value: stats.wip, icon: Clock, color: 'amber', suffix: '' },
    { label: 'OVERALL YIELD', value: stats.yield, icon: Percent, color: 'cyan', suffix: '%' },
  ];

  const getColorClasses = (color: string) => {
    switch(color) {
      case 'blue': return 'text-[#38bdf8] bg-[#38bdf8]/10 border-[#38bdf8]/20';
      case 'green': return 'text-[#22c55e] bg-[#22c55e]/10 border-[#22c55e]/20';
      case 'rose': return 'text-[#ef4444] bg-[#ef4444]/10 border-[#ef4444]/20';
      case 'cyan': return 'text-[#38bdf8] bg-[#38bdf8]/10 border-[#38bdf8]/20';
      case 'amber': return 'text-[#f59e0b] bg-[#f59e0b]/10 border-[#f59e0b]/20';
      default: return 'text-[#38bdf8] bg-[#38bdf8]/10 border-[#38bdf8]/20';
    }
  };

  return (
    <div className="grid grid-cols-[repeat(auto-fit,minmax(240px,1fr))] gap-5 mb-8 w-full">
      {cards.map((card, idx) => (
        <div key={idx} className={`premium-card p-6 flex flex-col justify-between group animated-glow`}>
          {loading ? (
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <div className="h-3 w-20 shimmer rounded-full opacity-20" />
                <div className="h-8 w-8 shimmer rounded-lg opacity-20" />
              </div>
              <div className="h-10 w-32 shimmer rounded-lg opacity-20" />
            </div>
          ) : (
            <>
              <div className="flex items-center justify-between mb-4">
                <span className="text-[11px] font-bold text-[#9ca3af] uppercase tracking-[0.15em]">{card.label}</span>
                <div className={`p-2.5 rounded-xl border ${getColorClasses(card.color)} transition-transform group-hover:rotate-12`}>
                  <card.icon className="w-4 h-4" />
                </div>
              </div>
              <div className="flex items-baseline">
                <h3 className="text-4xl font-black text-white tracking-tighter mono truncate">
                  <CountUp end={card.value} suffix={card.suffix} />
                </h3>
              </div>
              <div className="mt-4 h-1 w-full bg-white/5 rounded-full overflow-hidden">
                <div className={`h-full transition-all duration-1000 ${getColorClasses(card.color).split(' ')[0].replace('text-', 'bg-')}`} style={{ width: card.label === 'OVERALL YIELD' ? `${stats.yield}%` : '100%', opacity: 0.3 }} />
              </div>
            </>
          )}
        </div>
      ))}
    </div>
  );
};

