import React, { useState, useMemo } from 'react';
import { Search, AlertTriangle, ChevronUp, ChevronDown, ListFilter } from 'lucide-react';
import { DashboardRow, ColumnMapping } from '../types';

interface RejectionDetailsSectionProps {
  filteredData: DashboardRow[];
  mapping: ColumnMapping;
  headers: string[];
}

interface RejectionReasonGroup {
  reason: string;
  count: number;
}

const RejectionDetailsSection: React.FC<RejectionDetailsSectionProps> = ({ filteredData, mapping, headers }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('desc');

  const rejectionGroups = useMemo(() => {
    const reasonKey = mapping.reason;
    const statusKey = mapping.ringStatus;

    if (!headers.includes(reasonKey) || !headers.includes(statusKey)) {
      return null;
    }

    const groups: Record<string, number> = {};
    let totalRejected = 0;

    filteredData.forEach(row => {
      const status = String(row[statusKey] || '').trim().toLowerCase();
      if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
        const reason = String(row[reasonKey] || '').trim();
        if (reason !== '') {
          groups[reason] = (groups[reason] || 0) + 1;
          totalRejected++;
        }
      }
    });

    const result: RejectionReasonGroup[] = Object.entries(groups).map(([reason, count]) => ({
      reason,
      count
    }));

    return { 
      data: result,
      totalCount: totalRejected
    };
  }, [filteredData, mapping, headers]);

  const filteredAndSorted = useMemo(() => {
    if (!rejectionGroups) return [];
    let list = [...rejectionGroups.data];
    if (searchTerm) {
      list = list.filter(item => item.reason.toLowerCase().includes(searchTerm.toLowerCase()));
    }
    list.sort((a, b) => sortDirection === 'desc' ? b.count - a.count : a.count - b.count);
    return list;
  }, [rejectionGroups, searchTerm, sortDirection]);

  const maxCount = useMemo(() => {
    if (!rejectionGroups || rejectionGroups.data.length === 0) return 0;
    return Math.max(...rejectionGroups.data.map(i => i.count));
  }, [rejectionGroups]);

  if (!rejectionGroups) {
    return (
      <div className="premium-card p-8 flex items-center justify-center h-full">
        <div className="flex items-center gap-4 text-[#ef4444]">
          <AlertTriangle className="w-5 h-5" />
          <h3 className="text-sm font-bold uppercase tracking-widest mono text-center">REASON column missing.</h3>
        </div>
      </div>
    );
  }

  return (
    <div className="premium-card p-8 flex flex-col h-full animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-8">
        <div className="flex items-center gap-4">
          <div className="w-1.5 h-6 bg-[#ef4444] rounded-full shadow-[0_0_15px_rgba(239,68,68,0.5)]" />
          <h3 className="text-sm font-bold text-[#e5e7eb] uppercase tracking-[0.2em] mono">
            REJECTION ANALYSIS
          </h3>
        </div>

        <div className="relative w-full md:w-64">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[#9ca3af]" />
          <input
            type="text"
            placeholder="Search reasons..."
            className="w-full pl-10 pr-4 py-2 bg-[#0f1117] border border-white/5 rounded-xl text-sm focus:ring-2 focus:ring-[#38bdf8]/50 outline-none transition-all placeholder:text-[#9ca3af]/50"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="flex-1 overflow-hidden">
        <div className="overflow-hidden rounded-xl border border-white/5">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white/[0.02] border-b border-white/5">
                <th className="px-6 py-4 text-[11px] font-bold text-[#9ca3af] uppercase tracking-wider">Pattern</th>
                <th 
                  className="px-6 py-4 text-[11px] font-bold text-[#9ca3af] uppercase tracking-wider text-right cursor-pointer hover:bg-white/[0.05]"
                  onClick={() => setSortDirection(prev => prev === 'desc' ? 'asc' : 'desc')}
                >
                  <div className="flex items-center justify-end gap-2">
                    Count
                    {sortDirection === 'desc' ? <ChevronDown className="w-3 h-3 text-[#38bdf8]" /> : <ChevronUp className="w-3 h-3 text-[#38bdf8]" />}
                  </div>
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {filteredAndSorted.length > 0 ? (
                filteredAndSorted.map((item, idx) => (
                  <tr key={idx} className={`${idx % 2 === 0 ? '' : 'bg-white/[0.01]'} hover:bg-white/[0.03] transition-colors group`}>
                    <td className="px-6 py-4 text-sm font-bold text-white mono">
                      <div className="flex items-center gap-3">
                        {item.count === maxCount && item.count > 0 && (
                          <div className="w-2 h-2 bg-[#ef4444] rounded-full animate-pulse shadow-[0_0_10px_#ef4444]" />
                        )}
                        {item.reason}
                      </div>
                    </td>
                    <td className={`px-6 py-4 text-sm font-black text-right mono ${item.count === maxCount ? 'text-[#ef4444]' : 'text-white/80'}`}>
                      {item.count.toLocaleString()}
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={2} className="px-6 py-12 text-center text-[#9ca3af]/30 italic text-xs uppercase tracking-widest">
                    No rejection data recorded
                  </td>
                </tr>
              )}
            </tbody>
            {rejectionGroups.totalCount > 0 && (
              <tfoot>
                <tr className="bg-white/[0.03] border-t border-white/5">
                  <td className="px-6 py-4 text-[10px] font-black text-[#9ca3af] uppercase tracking-widest mono">TOTAL DETECTED</td>
                  <td className="px-6 py-4 text-right text-sm font-black text-[#ef4444] mono">{rejectionGroups.totalCount.toLocaleString()}</td>
                </tr>
              </tfoot>
            )}
          </table>
        </div>
      </div>
    </div>
  );
};

