          className="flex items-center gap-2 px-4 py-2 text-[10px] font-black text-[#9ca3af] hover:text-white bg-[#0f1117] hover:bg-[#ef4444]/10 border border-white/5 hover:border-[#ef4444]/30 rounded-xl transition-all uppercase tracking-widest"
        >
          <RotateCcw className="w-3 h-3" />
          CLEAR ALL FILTERS
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-end">
        <div className="lg:col-span-8 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="space-y-3 lg:col-span-2">
            <label className="text-[11px] font-bold text-[#9ca3af] uppercase tracking-widest flex items-center gap-2">
               PRESETS
            </label>
            <div className="flex flex-wrap gap-2">
              {presets.map(p => (
                <button
                  key={p.value}
                  onClick={() => handlePreset(p.value)}
                  className="px-3 py-2 text-[10px] font-black rounded-xl border border-white/5 bg-[#0f1117] hover:bg-[#38bdf8]/10 hover:border-[#38bdf8]/30 transition-all text-[#e5e7eb] uppercase tracking-tighter"
                >
                  {p.label}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-[11px] font-bold text-[#9ca3af] uppercase tracking-widest flex items-center gap-2">
               START DATE
            </label>
            <input
              type="date"
              className="w-full px-4 py-2.5 text-sm border border-white/5 rounded-xl focus:ring-2 focus:ring-[#38bdf8]/50 outline-none bg-[#0f1117] text-white mono"
              value={dateRange.start ? format(dateRange.start, 'yyyy-MM-dd') : ''}
              onChange={(e) => setDateRange({ ...dateRange, start: e.target.value ? new Date(e.target.value) : null })}
            />
          </div>

          <div className="space-y-3">
            <label className="text-[11px] font-bold text-[#9ca3af] uppercase tracking-widest flex items-center gap-2">
               END DATE
            </label>
            <input
              type="date"
              className="w-full px-4 py-2.5 text-sm border border-white/5 rounded-xl focus:ring-2 focus:ring-[#38bdf8]/50 outline-none bg-[#0f1117] text-white mono"
              value={dateRange.end ? format(dateRange.end, 'yyyy-MM-dd') : ''}
              onChange={(e) => setDateRange({ ...dateRange, end: e.target.value ? new Date(e.target.value) : null })}
            />
          </div>
        </div>

        <div className="lg:col-span-4 space-y-3">
          <label className="text-[11px] font-bold text-[#9ca3af] uppercase tracking-widest flex items-center gap-2">
             BATCH SELECTOR
          </label>
          <div className="relative">
            <button
              onClick={() => setIsBatchOpen(!isBatchOpen)}
              className="w-full flex items-center justify-between px-5 py-2.5 text-sm border border-white/5 rounded-xl bg-[#0f1117] hover:border-[#38bdf8]/40 transition-colors text-white"
            >
              <span className="truncate font-bold">
                {selectedBatches.length === batches.length ? 'ALL ACTIVE' : `${selectedBatches.length} SELECTED`}
              </span>
              <ChevronDown className="w-4 h-4 text-[#38bdf8]" />
            </button>

            {isBatchOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsBatchOpen(false)} />
                <div className="absolute z-20 top-full left-0 right-0 mt-2 bg-[#161a23] border border-white/10 rounded-2xl shadow-2xl max-h-60 overflow-y-auto p-3 space-y-1">
                  <div className="flex gap-2 p-1 mb-2">
                    <button onClick={() => setSelectedBatches(batches)} className="flex-1 py-2 text-[10px] font-black uppercase tracking-widest text-[#38bdf8] bg-[#38bdf8]/10 rounded-xl hover:bg-[#38bdf8]/20 transition-all border border-[#38bdf8]/20">All</button>
                    <button onClick={() => setSelectedBatches([])} className="flex-1 py-2 text-[10px] font-black uppercase tracking-widest text-[#9ca3af] bg-[#0f1117] rounded-xl hover:bg-white/5 transition-all border border-white/5">None</button>
                  </div>
                  {batches.map(batch => (
                    <div key={batch} className="group flex items-center px-2 hover:bg-white/5 rounded-xl transition-all">
                      <label className="flex-1 flex items-center py-2.5 cursor-pointer text-sm text-[#e5e7eb]">
                        <input 
                          type="checkbox" 
                          className="sr-only" 
                          checked={selectedBatches.includes(batch)} 
                          onChange={() => {
                            if (selectedBatches.includes(batch)) setSelectedBatches(selectedBatches.filter(b => b !== batch));
                            else setSelectedBatches([...selectedBatches, batch]);
                          }} 
                        />
                        <div className={`w-5 h-5 border-2 rounded-lg mr-3 flex items-center justify-center transition-all ${selectedBatches.includes(batch) ? 'bg-[#38bdf8] border-[#38bdf8]' : 'bg-[#0f1117] border-white/10'}`}>
                          {selectedBatches.includes(batch) && <Check className="w-3 h-3 text-[#0f1117] stroke-[4]" />}
                        </div>
                        <span className="font-medium truncate">{batch || '(Blank)'}</span>
                      </label>
                      <button
                        onClick={() => handleFilterOnly(batch)}
                        title="Show only this batch"
                        className="p-2 text-[#38bdf8] hover:bg-[#38bdf8]/10 rounded-lg opacity-0 group-hover:opacity-100 transition-all ml-2"
                      >
                        <Target className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  ))}
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      {/* Internal Reset Notification */}
      {showResetToast && (
        <div className="absolute top-2 right-1/2 translate-x-1/2 z-30 animate-in slide-in-from-top-2 fade-in duration-300">
          <div className="px-4 py-2 bg-[#22c55e]/10 border border-[#22c55e]/30 rounded-full flex items-center gap-2 backdrop-blur-md">
            <Check className="w-3 h-3 text-[#22c55e]" />
            <span className="text-[10px] font-black text-white uppercase tracking-widest">Filters cleared</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default FilterSection;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu, AlertCircle, ExternalLink, RefreshCw, BarChart3, Database, Copy, Check } from 'lucide-react';
import { INITIAL_CONFIG } from './constants';
import { SheetConfig, DashboardRow, KPIStats, SKUDetail, RemainingQtyItem } from './types';
import { fetchSheetData, parseDate } from './services/sheetService';
import KPIGrid from './components/KPIGrid';
import FilterSection from './components/FilterSection';
import SKUDetailsSection from './components/SKUDetailsSection';
import RemainingQtySection from './components/RemainingQtySection';
import RejectionDetailsSection from './components/RejectionDetailsSection';
import SettingsMenu from './components/SettingsMenu';
import { isWithinInterval, startOfDay, endOfDay } from 'date-fns';

const App: React.FC = () => {
  const [config, setConfig] = useState<SheetConfig>(() => {
    const saved = localStorage.getItem('qc_dashboard_config');
    return saved ? JSON.parse(saved) : INITIAL_CONFIG;
  });

  const [data, setData] = useState<DashboardRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showCopyToast, setShowCopyToast] = useState(false);

  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });
  const [uidSearch, setUidSearch] = useState('');

  // Robust column detection with priority on SKU
  const findHeaderMatch = useCallback((availableHeaders: string[], searchTerms: string[]): string | undefined => {
    if (!availableHeaders.length) return undefined;

    const lowerHeaders = availableHeaders.map(h => h.trim().toLowerCase());

    for (const term of searchTerms) {
      const idx = lowerHeaders.indexOf(term.toLowerCase());
      if (idx !== -1) return availableHeaders[idx];
    }

    const contains = availableHeaders.find(h => 
      searchTerms.some(term => h.toLowerCase().includes(term.toLowerCase()))
    );
    if (contains) return contains;

    return availableHeaders.find(h => {
      const normalized = h.toLowerCase().replace(/[^a-z0-9]/g, '');
      return searchTerms.some(term => {
        const termNorm = term.toLowerCase().replace(/[^a-z0-9]/g, '');
        return normalized.includes(termNorm) || termNorm.includes(normalized);
      });
    });
  }, []);

  const autoDetectMapping = useCallback((availableHeaders: string[]) => {
    const mapping = { ...config.mapping };

    const aliases = {
      sku: ['sku', 'item', 'part', 'article', 'model', 'product', 'code'],
      batchNo: ['batch', 'lot', 'serial'],
      ringStatus: ['status', 'result', 'outcome', 'quality'],
      uid: ['uid', 'id', 'barcode', 'serial'],
      date: ['date', 'time', 'timestamp'],
      inward: ['inward', 'qty', 'count', 'total'],
      reason: ['reason', 'rejection', 'defect', 'cause', 'fault'],
    };

    (Object.entries(aliases) as [keyof typeof aliases, string[]][]).forEach(([key, terms]) => {
      const currentVal = mapping[key as keyof typeof mapping];
      if (!currentVal || !availableHeaders.includes(currentVal)) {
        const detected = findHeaderMatch(availableHeaders, terms);
        if (detected) {
          (mapping as any)[key] = detected;
        }
      }
    });

    return mapping;
  }, [config.mapping, findHeaderMatch]);

  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("CONFIGURATION REQUIRED: Please link a valid public Google Sheet.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const { data: rawData, headers: sheetHeaders } = await fetchSheetData(config.url, config.sheetName);
      setHeaders(sheetHeaders);

      const updatedMapping = autoDetectMapping(sheetHeaders);
      if (JSON.stringify(updatedMapping) !== JSON.stringify(config.mapping)) {
        setConfig(prev => ({ ...prev, mapping: updatedMapping }));
      }

      setData(rawData);

      const batchCol = updatedMapping.batchNo;
      if (batchCol && sheetHeaders.includes(batchCol)) {
        const uniqueBatches = Array.from(new Set(rawData.map(r => String(r[batchCol] || '').trim())))
          .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
        setSelectedBatches(uniqueBatches);
      } else {
        setSelectedBatches([]);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [config.url, config.sheetName, autoDetectMapping]);

  useEffect(() => { 
    if (config.url) loadData(); 
  }, [config.url, config.sheetName]);

  const handleConfigUpdate = (newConfig: SheetConfig) => {
    setConfig(newConfig);
    localStorage.setItem('qc_dashboard_config', JSON.stringify(newConfig));
  };

  const allUniqueBatches = useMemo(() => {
    const batchCol = config.mapping.batchNo;
    if (!batchCol || !headers.includes(batchCol)) return [];
    return Array.from(new Set(data.map(r => String(r[batchCol] || '').trim())))
      .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
  }, [data, config.mapping.batchNo, headers]);

  const filteredData = useMemo(() => {
    const { mapping } = config;
    if (data.length === 0) return [];

    return data.filter(row => {
      // Date Filter
      if (dateRange.start || dateRange.end) {
        const rowDateStr = String(row[mapping.date] || '');
        const rowDate = parseDate(rowDateStr);
        if (!rowDate) return false;
        const start = dateRange.start ? startOfDay(dateRange.start) : new Date(0);
        const end = dateRange.end ? endOfDay(dateRange.end) : new Date(8640000000000000);
        if (!isWithinInterval(rowDate, { start, end })) return false;
      }

      // Batch Filter
      const batchCol = mapping.batchNo;
      if (batchCol && headers.includes(batchCol) && selectedBatches.length > 0 && selectedBatches.length < allUniqueBatches.length) {
        const rowBatch = String(row[batchCol] || '').trim();
        if (!selectedBatches.includes(rowBatch)) return false;
      }

      // UID Search Filter
      if (uidSearch.trim()) {
        const uidCol = mapping.uid;
        const rowUid = String(row[uidCol] || '').toLowerCase();
        if (!rowUid.includes(uidSearch.toLowerCase().trim())) return false;
      }

      return true;
    });
  }, [data, config, dateRange, selectedBatches, uidSearch, headers, allUniqueBatches]);

  const stats: KPIStats = useMemo(() => {
    const { mapping } = config;
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );
    const total = totalData.length;

    const accepted = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    }).length;

    const rejected = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    }).length;

    const inwardCount = filteredData.filter(r => String(r[mapping.inward] || '').trim() !== '').length;
    const wip = Math.max(0, inwardCount - total);
    const yieldVal = total > 0 ? (accepted / total) * 100 : 0;
    return { total, accepted, rejected, wip, yield: yieldVal };
  }, [filteredData, config]);

  const skuDetails = useMemo(() => {
    const { mapping } = config;
    const skuMap: Record<string, { total: number; accepted: number; rejected: number }> = {};

    let skuKey = mapping.sku;
    if (!headers.includes(skuKey)) {
      skuKey = findHeaderMatch(headers, ['sku', 'item', 'part', 'model']) || (headers.length > 0 ? headers[0] : '');
    }

    if (filteredData.length === 0 || !skuKey) {
      return [];
    }

    filteredData.forEach(r => {
      const val = r[skuKey];
      if (val !== undefined && val !== null) {
        const sku = String(val).trim().replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        if (sku !== '') {
          if (!skuMap[sku]) {
            skuMap[sku] = { total: 0, accepted: 0, rejected: 0 };
          }
          skuMap[sku].total += 1;

          const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
          if (['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status)) {
            skuMap[sku].accepted += 1;
          } else if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
            skuMap[sku].rejected += 1;
          }
        }
      }
    });

    return Object.entries(skuMap).map(([sku, s]) => ({
      sku,
      total: s.total,
      accepted: s.accepted,
      rejected: s.rejected,
      yield: s.total > 0 ? (s.accepted / s.total) * 100 : 0
    }));
  }, [filteredData, config, headers, findHeaderMatch]);

  const remainingQtyData = useMemo<RemainingQtyItem[] | null>(() => {
    const hasSkus = headers.includes('SKUs');
    const hasRemainingQty = headers.includes('REMAINING QTY');

    if (!hasSkus || !hasRemainingQty) return null;

    return data
      .map(row => ({
        sku: String(row['SKUs'] || '').trim(),
        qty: Number(row['REMAINING QTY']) || 0
      }))
      .filter(item => item.sku !== '');
  }, [data, headers]);

  const handleCopyReport = () => {
    if (stats.total === 0) {
      alert("No data available");
      return;
    }

    const { mapping } = config;

    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );

    const acceptedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    });

    const acceptedGroups: Record<string, number> = {};
    acceptedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown SKU').trim();
      acceptedGroups[sku] = (acceptedGroups[sku] || 0) + 1;
    });

    const acceptedDetailsStr = Object.entries(acceptedGroups)
      .map(([sku, count]) => `${sku}: ${count}`)
      .join('\n');

    const rejectedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    });

    const rejectedGroups: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const reason = String(r[mapping.reason] || 'No Reason Specified').trim();
      rejectedGroups[reason] = (rejectedGroups[reason] || 0) + 1;
    });

    const rejectedDetailsStr = Object.entries(rejectedGroups)
      .map(([reason, count]) => `${reason}: ${count}`)
      .join('\n');

    const reportText = `------------------------------------
BATCH REPORT

TOTAL : ${stats.total}
ACCEPTED : ${stats.accepted}
REJECTED : ${stats.rejected}
YIELD : ${stats.yield.toFixed(1)}%

ACCEPTED DETAILS
${acceptedDetailsStr || 'None'}

REJECTION DETAILS
${rejectedDetailsStr || 'None'}
------------------------------------`;

    navigator.clipboard.writeText(reportText).then(() => {
      setShowCopyToast(true);
      setTimeout(() => setShowResetToast(false), 3000);
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  return (
    <div className="min-h-screen pb-12 w-full max-w-[100vw] bg-[#0f1117]">
      <header className="sticky top-0 z-40 bg-[#161a23]/90 backdrop-blur-xl border-b border-white/5 shadow-2xl w-full">
        <div className="w-full px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-[#22c55e] rounded-2xl shadow-[0_0_20px_rgba(34,197,94,0.3)]">
                <BarChart3 className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-black text-white leading-tight tracking-tight uppercase">Dashboard</h1>
                <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.4em] mono">Quality Analytics Pro</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              {data.length > 0 && (
                <button 
                  onClick={handleCopyReport}
                  className="flex items-center gap-2 px-5 py-2.5 text-xs font-bold text-[#e5e7eb] bg-[#22c55e]/10 hover:bg-[#22c55e]/20 rounded-xl transition-all border border-[#22c55e]/30"
                >
                  <Copy className="w-4 h-4 text-[#22c55e]" />
                  BATCH REPORT
                </button>
              )}
              {config.url && (
                <button onClick={loadData} className="hidden sm:flex items-center gap-2 px-5 py-2.5 text-xs font-bold text-[#38bdf8] hover:bg-[#38bdf8]/10 rounded-xl transition-all border border-[#38bdf8]/20" disabled={loading}>
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  SYNC
                </button>
              )}
              <button onClick={() => setIsSettingsOpen(true)} className="p-3 bg-[#1e232d] text-[#e5e7eb] hover:bg-[#2a313d] rounded-2xl border border-white/5 transition-all">
                <Menu className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full px-4 sm:px-6 lg:px-8 mt-10">
        {error && (
          <div className="mb-10 p-6 bg-[#ef4444]/10 border border-[#ef4444]/30 rounded-2xl flex items-start gap-4">
            <AlertCircle className="w-6 h-6 text-[#ef4444] shrink-0 mt-1" />
            <div className="flex-1">
              <h4 className="text-sm font-bold text-[#ef4444] uppercase tracking-widest">System Error</h4>
              <p className="text-sm text-[#9ca3af] mt-2 font-medium">{error}</p>
            </div>
          </div>
        )}

        {(!config.url && !loading) ? (
          <div className="py-32 flex flex-col items-center justify-center text-center">
            <div className="w-24 h-24 bg-[#161a23] rounded-3xl flex items-center justify-center mb-8 border border-white/5 shadow-2xl">
              <Database className="w-10 h-10 text-[#38bdf8]" />
            </div>
            <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter">No Stream Detected</h2>
            <p className="text-[#9ca3af] max-sm mx-auto mb-10 text-sm leading-relaxed">
              Connect to a valid Google Sheet to initialize analytical rendering.
            </p>
            <button onClick={() => setIsSettingsOpen(true)} className="px-10 py-4 bg-[#38bdf8] hover:bg-[#0ea5e9] text-white font-bold rounded-2xl shadow-xl transition-all">
              OPEN CONFIG
            </button>
          </div>
        ) : (
          <div className="animate-in fade-in duration-700 space-y-10 w-full">
            <FilterSection 
              batches={allUniqueBatches} 
              selectedBatches={selectedBatches} 
              setSelectedBatches={setSelectedBatches} 
              dateRange={dateRange} 
              setDateRange={setDateRange}
              uidSearch={uidSearch}
              setUidSearch={setUidSearch}
            />
            <KPIGrid stats={stats} loading={loading} />

            {data.length > 0 && (
              <>
                <div className="flex items-center justify-between px-6 py-4 bg-[#161a23] rounded-2xl border border-white/5">
                  <div className="flex items-center gap-6">
                    <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono">
                      Source: <span className="text-[#38bdf8]">{config.sheetName}</span>
                    </p>
                    <p className="hidden md:block text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono border-l border-white/10 pl-6">
                      Updated: <span className="text-white">{new Date().toLocaleTimeString()}</span>
                    </p>
                  </div>
                  <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono">
                    Total Records: <span className="text-white bg-white/5 px-2 py-0.5 rounded ml-2">{filteredData.length}</span>
                  </p>
                </div>

                <SKUDetailsSection skuDetails={skuDetails} />

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-stretch pb-10">
                  <RemainingQtySection data={remainingQtyData} />
                  <RejectionDetailsSection filteredData={filteredData} mapping={config.mapping} headers={headers} />
                </div>
              </>
            )}
          </div>
        )}
      </main>

      {showCopyToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-4 fade-in duration-300">
          <div className="px-8 py-4 bg-[#161a23] border border-[#22c55e]/30 rounded-2xl shadow-2xl flex items-center gap-3 backdrop-blur-xl">
            <Check className="w-5 h-5 text-[#22c55e]" />
            <span className="text-sm font-bold text-white uppercase tracking-widest">Report Copied to Clipboard</span>
          </div>
        </div>
      )}

      <SettingsMenu config={config} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Calendar, Filter, Check, ChevronDown, Clock, Target, RotateCcw, X, Search } from 'lucide-react';
import { format, subDays, startOfMonth, endOfMonth } from 'date-fns';

interface FilterSectionProps {
  batches: string[];
  selectedBatches: string[];
  setSelectedBatches: (batches: string[]) => void;
  dateRange: { start: Date | null; end: Date | null };
  setDateRange: (range: { start: Date | null; end: Date | null }) => void;
  uidSearch: string;
  setUidSearch: (search: string) => void;
}

const FilterSection: React.FC<FilterSectionProps> = ({
  batches,
  selectedBatches,
  setSelectedBatches,
  dateRange,
  setDateRange,
  uidSearch,
  setUidSearch
}) => {
  const [isBatchOpen, setIsBatchOpen] = useState(false);
  const [showResetToast, setShowResetToast] = useState(false);

  const presets = [
    { label: 'ALL TIME', value: 'all' },
    { label: 'YESTERDAY', value: 'yesterday' },
    { label: 'TODAY', value: 'today' },
    { label: '7 DAYS', value: '7d' },
    { label: '30 DAYS', value: '30d' },
    { label: 'MONTH', value: 'month' },
  ];

  const handlePreset = (type: string) => {
    const today = new Date();
    switch (type) {
      case 'yesterday': {
        const yesterday = subDays(today, 1);
        setDateRange({ start: yesterday, end: yesterday });
        break;
      }
      case 'today': setDateRange({ start: today, end: today }); break;
      case '7d': setDateRange({ start: subDays(today, 7), end: today }); break;
      case '30d': setDateRange({ start: subDays(today, 30), end: today }); break;
      case 'month': setDateRange({ start: startOfMonth(today), end: endOfMonth(today) }); break;
      default: setDateRange({ start: null, end: null });
    }
  };

  const handleFilterOnly = (batch: string) => {
    setSelectedBatches([batch]);
    setIsBatchOpen(false);
  };

  const handleClearAll = () => {
    setDateRange({ start: null, end: null });
    setSelectedBatches(batches);
    setUidSearch('');
    setShowResetToast(true);
    setTimeout(() => setShowResetToast(false), 2000);
  };

  return (
    <div className="relative mb-8 bg-[#161a23] p-8 rounded-2xl border border-white/5 shadow-2xl animate-in fade-in duration-500">
      {/* Header with Search and Clear All Button */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
        <div className="flex items-center gap-3">
          <Filter className="w-4 h-4 text-[#38bdf8]" />
          <h2 className="text-xs font-black text-white uppercase tracking-[0.2em] mono">Filter Panel</h2>
        </div>

        <div className="flex flex-wrap items-center gap-4 w-full md:w-auto">
          {/* UID Search Bar */}
          <div className="relative flex-1 md:w-64 min-w-[200px]">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-[#38bdf8]" />
            <input
              type="text"
              placeholder="Search UID..."
              className="w-full pl-10 pr-10 py-2.5 bg-[#0f1117] border border-white/5 rounded-xl text-sm text-white focus:ring-2 focus:ring-[#38bdf8]/50 outline-none transition-all placeholder:text-[#9ca3af]/50 mono"
              value={uidSearch}
              onChange={(e) => setUidSearch(e.target.value)}
            />
            {uidSearch && (
              <button
                onClick={() => setUidSearch('')}
                className="absolute right-3 top-1/2 -translate-y-1/2 p-1 text-[#9ca3af] hover:text-[#ef4444] transition-colors"
              >
                <X className="w-3.5 h-3.5" />
              </button>
            )}
          </div>

          <button
            onClick={handleClearAll}
            className="flex items-center gap-2 px-4 py-2.5 text-[10px] font-black text-[#9ca3af] hover:text-white bg-[#0f1117] hover:bg-[#ef4444]/10 border border-white/5 hover:border-[#ef4444]/30 rounded-xl transition-all uppercase tracking-widest"
          >
            <RotateCcw className="w-3 h-3" />
            CLEAR ALL
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-end">
        <div className="lg:col-span-8 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="space-y-3 lg:col-span-2">
            <label className="text-[11px] font-bold text-[#9ca3af] uppercase tracking-widest flex items-center gap-2">
               PRESETS
            </label>
            <div className="flex flex-wrap gap-2">
              {presets.map(p => (
                <button
                  key={p.value}
                  onClick={() => handlePreset(p.value)}
                  className="px-3 py-2 text-[10px] font-black rounded-xl border border-white/5 bg-[#0f1117] hover:bg-[#38bdf8]/10 hover:border-[#38bdf8]/30 transition-all text-[#e5e7eb] uppercase tracking-tighter"
                >
                  {p.label}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-3">
            <label className="text-[11px] font-bold text-[#9ca3af] uppercase tracking-widest flex items-center gap-2">
               START DATE
            </label>
            <input
              type="date"
              className="w-full px-4 py-2.5 text-sm border border-white/5 rounded-xl focus:ring-2 focus:ring-[#38bdf8]/50 outline-none bg-[#0f1117] text-white mono"
              value={dateRange.start ? format(dateRange.start, 'yyyy-MM-dd') : ''}
              onChange={(e) => setDateRange({ ...dateRange, start: e.target.value ? new Date(e.target.value) : null })}
            />
          </div>

          <div className="space-y-3">
            <label className="text-[11px] font-bold text-[#9ca3af] uppercase tracking-widest flex items-center gap-2">
               END DATE
            </label>
            <input
              type="date"
              className="w-full px-4 py-2.5 text-sm border border-white/5 rounded-xl focus:ring-2 focus:ring-[#38bdf8]/50 outline-none bg-[#0f1117] text-white mono"
              value={dateRange.end ? format(dateRange.end, 'yyyy-MM-dd') : ''}
              onChange={(e) => setDateRange({ ...dateRange, end: e.target.value ? new Date(e.target.value) : null })}
            />
          </div>
        </div>

        <div className="lg:col-span-4 space-y-3">
          <label className="text-[11px] font-bold text-[#9ca3af] uppercase tracking-widest flex items-center gap-2">
             BATCH SELECTOR
          </label>
          <div className="relative">
            <button
              onClick={() => setIsBatchOpen(!isBatchOpen)}
              className="w-full flex items-center justify-between px-5 py-2.5 text-sm border border-white/5 rounded-xl bg-[#0f1117] hover:border-[#38bdf8]/40 transition-colors text-white"
            >
              <span className="truncate font-bold">
                {selectedBatches.length === batches.length ? 'ALL ACTIVE' : `${selectedBatches.length} SELECTED`}
              </span>
              <ChevronDown className="w-4 h-4 text-[#38bdf8]" />
            </button>

            {isBatchOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsBatchOpen(false)} />
                <div className="absolute z-20 top-full left-0 right-0 mt-2 bg-[#161a23] border border-white/10 rounded-2xl shadow-2xl max-h-60 overflow-y-auto p-3 space-y-1">
                  <div className="flex gap-2 p-1 mb-2">
                    <button onClick={() => setSelectedBatches(batches)} className="flex-1 py-2 text-[10px] font-black uppercase tracking-widest text-[#38bdf8] bg-[#38bdf8]/10 rounded-xl hover:bg-[#38bdf8]/20 transition-all border border-[#38bdf8]/20">All</button>
                    <button onClick={() => setSelectedBatches([])} className="flex-1 py-2 text-[10px] font-black uppercase tracking-widest text-[#9ca3af] bg-[#0f1117] rounded-xl hover:bg-white/5 transition-all border border-white/5">None</button>
                  </div>
                  {batches.map(batch => (
                    <div key={batch} className="group flex items-center px-2 hover:bg-white/5 rounded-xl transition-all">
                      <label className="flex-1 flex items-center py-2.5 cursor-pointer text-sm text-[#e5e7eb]">
                        <input 
                          type="checkbox" 
                          className="sr-only" 
                          checked={selectedBatches.includes(batch)} 
                          onChange={() => {
                            if (selectedBatches.includes(batch)) setSelectedBatches(selectedBatches.filter(b => b !== batch));
                            else setSelectedBatches([...selectedBatches, batch]);
                          }} 
                        />
                        <div className={`w-5 h-5 border-2 rounded-lg mr-3 flex items-center justify-center transition-all ${selectedBatches.includes(batch) ? 'bg-[#38bdf8] border-[#38bdf8]' : 'bg-[#0f1117] border-white/10'}`}>
                          {selectedBatches.includes(batch) && <Check className="w-3 h-3 text-[#0f1117] stroke-[4]" />}
                        </div>
                        <span className="font-medium truncate">{batch || '(Blank)'}</span>
                      </label>
                      <button
                        onClick={() => handleFilterOnly(batch)}
                        title="Show only this batch"
                        className="p-2 text-[#38bdf8] hover:bg-[#38bdf8]/10 rounded-lg opacity-0 group-hover:opacity-100 transition-all ml-2"
                      >
                        <Target className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  ))}
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      {/* Internal Reset Notification */}
      {showResetToast && (
        <div className="absolute top-2 right-1/2 translate-x-1/2 z-30 animate-in slide-in-from-top-2 fade-in duration-300">
          <div className="px-4 py-2 bg-[#22c55e]/10 border border-[#22c55e]/30 rounded-full flex items-center gap-2 backdrop-blur-md">
            <Check className="w-3 h-3 text-[#22c55e]" />
            <span className="text-[10px] font-black text-white uppercase tracking-widest">Filters cleared</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default FilterSection;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu, AlertCircle, ExternalLink, RefreshCw, BarChart3, Database, Copy, Check } from 'lucide-react';
import { INITIAL_CONFIG } from './constants';
import { SheetConfig, DashboardRow, KPIStats, SKUDetail, RemainingQtyItem } from './types';
import { fetchSheetData, parseDate } from './services/sheetService';
import KPIGrid from './components/KPIGrid';
import FilterSection from './components/FilterSection';
import SKUDetailsSection from './components/SKUDetailsSection';
import RemainingQtySection from './components/RemainingQtySection';
import RejectionDetailsSection from './components/RejectionDetailsSection';
import SettingsMenu from './components/SettingsMenu';
import { isWithinInterval, startOfDay, endOfDay } from 'date-fns';

const App: React.FC = () => {
  const [config, setConfig] = useState<SheetConfig>(() => {
    const saved = localStorage.getItem('qc_dashboard_config');
    return saved ? JSON.parse(saved) : INITIAL_CONFIG;
  });

  const [data, setData] = useState<DashboardRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showCopyToast, setShowCopyToast] = useState(false);

  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });
  const [uidSearch, setUidSearch] = useState('');

  // Robust column detection with priority on SKU
  const findHeaderMatch = useCallback((availableHeaders: string[], searchTerms: string[]): string | undefined => {
    if (!availableHeaders.length) return undefined;

    const lowerHeaders = availableHeaders.map(h => h.trim().toLowerCase());

    for (const term of searchTerms) {
      const idx = lowerHeaders.indexOf(term.toLowerCase());
      if (idx !== -1) return availableHeaders[idx];
    }

    const contains = availableHeaders.find(h => 
      searchTerms.some(term => h.toLowerCase().includes(term.toLowerCase()))
    );
    if (contains) return contains;

    return availableHeaders.find(h => {
      const normalized = h.toLowerCase().replace(/[^a-z0-9]/g, '');
      return searchTerms.some(term => {
        const termNorm = term.toLowerCase().replace(/[^a-z0-9]/g, '');
        return normalized.includes(termNorm) || termNorm.includes(normalized);
      });
    });
  }, []);

  const autoDetectMapping = useCallback((availableHeaders: string[]) => {
    const mapping = { ...config.mapping };

    const aliases = {
      sku: ['sku', 'item', 'part', 'article', 'model', 'product', 'code'],
      batchNo: ['batch', 'lot', 'serial'],
      ringStatus: ['status', 'result', 'outcome', 'quality'],
      uid: ['uid', 'id', 'barcode', 'serial'],
      date: ['date', 'time', 'timestamp'],
      inward: ['inward', 'qty', 'count', 'total'],
      reason: ['reason', 'rejection', 'defect', 'cause', 'fault'],
    };

    (Object.entries(aliases) as [keyof typeof aliases, string[]][]).forEach(([key, terms]) => {
      const currentVal = mapping[key as keyof typeof mapping];
      if (!currentVal || !availableHeaders.includes(currentVal)) {
        const detected = findHeaderMatch(availableHeaders, terms);
        if (detected) {
          (mapping as any)[key] = detected;
        }
      }
    });

    return mapping;
  }, [config.mapping, findHeaderMatch]);

  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("CONFIGURATION REQUIRED: Please link a valid public Google Sheet.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const { data: rawData, headers: sheetHeaders } = await fetchSheetData(config.url, config.sheetName);
      setHeaders(sheetHeaders);

      const updatedMapping = autoDetectMapping(sheetHeaders);
      if (JSON.stringify(updatedMapping) !== JSON.stringify(config.mapping)) {
        setConfig(prev => ({ ...prev, mapping: updatedMapping }));
      }

      setData(rawData);

      const batchCol = updatedMapping.batchNo;
      if (batchCol && sheetHeaders.includes(batchCol)) {
        const uniqueBatches = Array.from(new Set(rawData.map(r => String(r[batchCol] || '').trim())))
          .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
        setSelectedBatches(uniqueBatches);
      } else {
        setSelectedBatches([]);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [config.url, config.sheetName, autoDetectMapping]);

  useEffect(() => { 
    if (config.url) loadData(); 
  }, [config.url, config.sheetName]);

  const handleConfigUpdate = (newConfig: SheetConfig) => {
    setConfig(newConfig);
    localStorage.setItem('qc_dashboard_config', JSON.stringify(newConfig));
  };

  const allUniqueBatches = useMemo(() => {
    const batchCol = config.mapping.batchNo;
    if (!batchCol || !headers.includes(batchCol)) return [];
    return Array.from(new Set(data.map(r => String(r[batchCol] || '').trim())))
      .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
  }, [data, config.mapping.batchNo, headers]);

  const filteredData = useMemo(() => {
    const { mapping } = config;
    if (data.length === 0) return [];

    return data.filter(row => {
      // Date Filter
      if (dateRange.start || dateRange.end) {
        const rowDateStr = String(row[mapping.date] || '');
        const rowDate = parseDate(rowDateStr);
        if (!rowDate) return false;
        const start = dateRange.start ? startOfDay(dateRange.start) : new Date(0);
        const end = dateRange.end ? endOfDay(dateRange.end) : new Date(8640000000000000);
        if (!isWithinInterval(rowDate, { start, end })) return false;
      }

      // Batch Filter
      const batchCol = mapping.batchNo;
      if (batchCol && headers.includes(batchCol) && selectedBatches.length > 0 && selectedBatches.length < allUniqueBatches.length) {
        const rowBatch = String(row[batchCol] || '').trim();
        if (!selectedBatches.includes(rowBatch)) return false;
      }

      // UID Search Filter
      if (uidSearch.trim()) {
        const uidCol = mapping.uid;
        const rowUid = String(row[uidCol] || '').toLowerCase();
        if (!rowUid.includes(uidSearch.toLowerCase().trim())) return false;
      }

      return true;
    });
  }, [data, config, dateRange, selectedBatches, uidSearch, headers, allUniqueBatches]);

  const stats: KPIStats = useMemo(() => {
    const { mapping } = config;
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );
    const total = totalData.length;

    const accepted = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    }).length;

    const rejected = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    }).length;

    const inwardCount = filteredData.filter(r => String(r[mapping.inward] || '').trim() !== '').length;
    const wip = Math.max(0, inwardCount - total);
    const yieldVal = total > 0 ? (accepted / total) * 100 : 0;
    return { total, accepted, rejected, wip, yield: yieldVal };
  }, [filteredData, config]);

  const skuDetails = useMemo(() => {
    const { mapping } = config;
    const skuMap: Record<string, { total: number; accepted: number; rejected: number }> = {};

    let skuKey = mapping.sku;
    if (!headers.includes(skuKey)) {
      skuKey = findHeaderMatch(headers, ['sku', 'item', 'part', 'model']) || (headers.length > 0 ? headers[0] : '');
    }

    if (filteredData.length === 0 || !skuKey) {
      return [];
    }

    filteredData.forEach(r => {
      const val = r[skuKey];
      if (val !== undefined && val !== null) {
        const sku = String(val).trim().replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        if (sku !== '') {
          if (!skuMap[sku]) {
            skuMap[sku] = { total: 0, accepted: 0, rejected: 0 };
          }
          skuMap[sku].total += 1;

          const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
          if (['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status)) {
            skuMap[sku].accepted += 1;
          } else if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
            skuMap[sku].rejected += 1;
          }
        }
      }
    });

    return Object.entries(skuMap).map(([sku, s]) => ({
      sku,
      total: s.total,
      accepted: s.accepted,
      rejected: s.rejected,
      yield: s.total > 0 ? (s.accepted / s.total) * 100 : 0
    }));
  }, [filteredData, config, headers, findHeaderMatch]);

  const remainingQtyData = useMemo<RemainingQtyItem[] | null>(() => {
    const hasSkus = headers.includes('SKUs');
    const hasRemainingQty = headers.includes('REMAINING QTY');

    if (!hasSkus || !hasRemainingQty) return null;

    return data
      .map(row => ({
        sku: String(row['SKUs'] || '').trim(),
        qty: Number(row['REMAINING QTY']) || 0
      }))
      .filter(item => item.sku !== '');
  }, [data, headers]);

  const handleCopyReport = () => {
    if (stats.total === 0) {
      alert("No data available");
      return;
    }

    const { mapping } = config;

    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );

    const acceptedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    });

    const acceptedGroups: Record<string, number> = {};
    acceptedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown SKU').trim();
      acceptedGroups[sku] = (acceptedGroups[sku] || 0) + 1;
    });

    const acceptedDetailsStr = Object.entries(acceptedGroups)
      .map(([sku, count]) => `${sku}: ${count}`)
      .join('\n');

    const rejectedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    });

    const rejectedGroups: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const reason = String(r[mapping.reason] || 'No Reason Specified').trim();
      rejectedGroups[reason] = (rejectedGroups[reason] || 0) + 1;
    });

    const rejectedDetailsStr = Object.entries(rejectedGroups)
      .map(([reason, count]) => `${reason}: ${count}`)
      .join('\n');

    const reportText = `------------------------------------
BATCH REPORT

TOTAL : ${stats.total}
ACCEPTED : ${stats.accepted}
REJECTED : ${stats.rejected}
YIELD : ${stats.yield.toFixed(1)}%

ACCEPTED DETAILS
${acceptedDetailsStr || 'None'}

REJECTION DETAILS
${rejectedDetailsStr || 'None'}
------------------------------------`;

    navigator.clipboard.writeText(reportText).then(() => {
      setShowCopyToast(true);
      // Fixed: Change setShowResetToast to setShowCopyToast to fix reference error
      setTimeout(() => setShowCopyToast(false), 3000);
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  return (
    <div className="min-h-screen pb-12 w-full max-w-[100vw] bg-[#0f1117]">
      <header className="sticky top-0 z-40 bg-[#161a23]/90 backdrop-blur-xl border-b border-white/5 shadow-2xl w-full">
        <div className="w-full px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-[#22c55e] rounded-2xl shadow-[0_0_20px_rgba(34,197,94,0.3)]">
                <BarChart3 className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-black text-white leading-tight tracking-tight uppercase">Dashboard</h1>
                <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.4em] mono">Quality Analytics Pro</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              {data.length > 0 && (
                <button 
                  onClick={handleCopyReport}
                  className="flex items-center gap-2 px-5 py-2.5 text-xs font-bold text-[#e5e7eb] bg-[#22c55e]/10 hover:bg-[#22c55e]/20 rounded-xl transition-all border border-[#22c55e]/30"
                >
                  <Copy className="w-4 h-4 text-[#22c55e]" />
                  BATCH REPORT
                </button>
              )}
              {config.url && (
                <button onClick={loadData} className="hidden sm:flex items-center gap-2 px-5 py-2.5 text-xs font-bold text-[#38bdf8] hover:bg-[#38bdf8]/10 rounded-xl transition-all border border-[#38bdf8]/20" disabled={loading}>
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  SYNC
                </button>
              )}
              <button onClick={() => setIsSettingsOpen(true)} className="p-3 bg-[#1e232d] text-[#e5e7eb] hover:bg-[#2a313d] rounded-2xl border border-white/5 transition-all">
                <Menu className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full px-4 sm:px-6 lg:px-8 mt-10">
        {error && (
          <div className="mb-10 p-6 bg-[#ef4444]/10 border border-[#ef4444]/30 rounded-2xl flex items-start gap-4">
            <AlertCircle className="w-6 h-6 text-[#ef4444] shrink-0 mt-1" />
            <div className="flex-1">
              <h4 className="text-sm font-bold text-[#ef4444] uppercase tracking-widest">System Error</h4>
              <p className="text-sm text-[#9ca3af] mt-2 font-medium">{error}</p>
            </div>
          </div>
        )}

        {(!config.url && !loading) ? (
          <div className="py-32 flex flex-col items-center justify-center text-center">
            <div className="w-24 h-24 bg-[#161a23] rounded-3xl flex items-center justify-center mb-8 border border-white/5 shadow-2xl">
              <Database className="w-10 h-10 text-[#38bdf8]" />
            </div>
            <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter">No Stream Detected</h2>
            <p className="text-[#9ca3af] max-sm mx-auto mb-10 text-sm leading-relaxed">
              Connect to a valid Google Sheet to initialize analytical rendering.
            </p>
            <button onClick={() => setIsSettingsOpen(true)} className="px-10 py-4 bg-[#38bdf8] hover:bg-[#0ea5e9] text-white font-bold rounded-2xl shadow-xl transition-all">
              OPEN CONFIG
            </button>
          </div>
        ) : (
          <div className="animate-in fade-in duration-700 space-y-10 w-full">
            <FilterSection 
              batches={allUniqueBatches} 
              selectedBatches={selectedBatches} 
              setSelectedBatches={setSelectedBatches} 
              dateRange={dateRange} 
              setDateRange={setDateRange}
              uidSearch={uidSearch}
              setUidSearch={setUidSearch}
            />
            <KPIGrid stats={stats} loading={loading} />

            {data.length > 0 && (
              <>
                <div className="flex items-center justify-between px-6 py-4 bg-[#161a23] rounded-2xl border border-white/5">
                  <div className="flex items-center gap-6">
                    <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono">
                      Source: <span className="text-[#38bdf8]">{config.sheetName}</span>
                    </p>
                    <p className="hidden md:block text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono border-l border-white/10 pl-6">
                      Updated: <span className="text-white">{new Date().toLocaleTimeString()}</span>
                    </p>
                  </div>
                  <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono">
                    Total Records: <span className="text-white bg-white/5 px-2 py-0.5 rounded ml-2">{filteredData.length}</span>
                  </p>
                </div>

                <SKUDetailsSection skuDetails={skuDetails} />

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-stretch pb-10">
                  <RemainingQtySection data={remainingQtyData} />
                  <RejectionDetailsSection filteredData={filteredData} mapping={config.mapping} headers={headers} />
                </div>
              </>
            )}
          </div>
        )}
      </main>

      {showCopyToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-4 fade-in duration-300">
          <div className="px-8 py-4 bg-[#161a23] border border-[#22c55e]/30 rounded-2xl shadow-2xl flex items-center gap-3 backdrop-blur-xl">
            <Check className="w-5 h-5 text-[#22c55e]" />
            <span className="text-sm font-bold text-white uppercase tracking-widest">Report Copied to Clipboard</span>
          </div>
        </div>
      )}

      <SettingsMenu config={config} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu, AlertCircle, ExternalLink, RefreshCw, BarChart3, Database, Copy, Check } from 'lucide-react';
import { INITIAL_CONFIG } from './constants';
import { SheetConfig, DashboardRow, KPIStats, SKUDetail, RemainingQtyItem } from './types';
import { fetchSheetData, parseDate } from './services/sheetService';
import KPIGrid from './components/KPIGrid';
import FilterSection from './components/FilterSection';
import SKUDetailsSection from './components/SKUDetailsSection';
import RemainingQtySection from './components/RemainingQtySection';
import RejectionDetailsSection from './components/RejectionDetailsSection';
import SettingsMenu from './components/SettingsMenu';
import { isWithinInterval, startOfDay, endOfDay } from 'date-fns';

const App: React.FC = () => {
  const [config, setConfig] = useState<SheetConfig>(() => {
    const saved = localStorage.getItem('qc_dashboard_config');
    return saved ? JSON.parse(saved) : INITIAL_CONFIG;
  });

  const [data, setData] = useState<DashboardRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showCopyToast, setShowCopyToast] = useState(false);

  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });
  const [uidSearch, setUidSearch] = useState('');

  // Robust column detection with priority on SKU
  const findHeaderMatch = useCallback((availableHeaders: string[], searchTerms: string[]): string | undefined => {
    if (!availableHeaders.length) return undefined;

    const lowerHeaders = availableHeaders.map(h => h.trim().toLowerCase());

    for (const term of searchTerms) {
      const idx = lowerHeaders.indexOf(term.toLowerCase());
      if (idx !== -1) return availableHeaders[idx];
    }

    const contains = availableHeaders.find(h => 
      searchTerms.some(term => h.toLowerCase().includes(term.toLowerCase()))
    );
    if (contains) return contains;

    return availableHeaders.find(h => {
      const normalized = h.toLowerCase().replace(/[^a-z0-9]/g, '');
      return searchTerms.some(term => {
        const termNorm = term.toLowerCase().replace(/[^a-z0-9]/g, '');
        return normalized.includes(termNorm) || termNorm.includes(normalized);
      });
    });
  }, []);

  const autoDetectMapping = useCallback((availableHeaders: string[]) => {
    const mapping = { ...config.mapping };

    const aliases = {
      sku: ['sku', 'item', 'part', 'article', 'model', 'product', 'code'],
      batchNo: ['batch', 'lot', 'serial'],
      ringStatus: ['status', 'result', 'outcome', 'quality'],
      uid: ['uid', 'id', 'barcode', 'serial'],
      date: ['date', 'time', 'timestamp'],
      inward: ['inward', 'qty', 'count', 'total'],
      reason: ['reason', 'rejection', 'defect', 'cause', 'fault'],
    };

    (Object.entries(aliases) as [keyof typeof aliases, string[]][]).forEach(([key, terms]) => {
      const currentVal = mapping[key as keyof typeof mapping];
      if (!currentVal || !availableHeaders.includes(currentVal)) {
        const detected = findHeaderMatch(availableHeaders, terms);
        if (detected) {
          (mapping as any)[key] = detected;
        }
      }
    });

    return mapping;
  }, [config.mapping, findHeaderMatch]);

  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("CONFIGURATION REQUIRED: Please link a valid public Google Sheet.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const { data: rawData, headers: sheetHeaders } = await fetchSheetData(config.url, config.sheetName);
      setHeaders(sheetHeaders);

      const updatedMapping = autoDetectMapping(sheetHeaders);
      if (JSON.stringify(updatedMapping) !== JSON.stringify(config.mapping)) {
        setConfig(prev => ({ ...prev, mapping: updatedMapping }));
      }

      setData(rawData);

      const batchCol = updatedMapping.batchNo;
      if (batchCol && sheetHeaders.includes(batchCol)) {
        const uniqueBatches = Array.from(new Set(rawData.map(r => String(r[batchCol] || '').trim())))
          .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
        setSelectedBatches(uniqueBatches);
      } else {
        setSelectedBatches([]);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [config.url, config.sheetName, autoDetectMapping]);

  useEffect(() => { 
    if (config.url) loadData(); 
  }, [config.url, config.sheetName]);

  const handleConfigUpdate = (newConfig: SheetConfig) => {
    setConfig(newConfig);
    localStorage.setItem('qc_dashboard_config', JSON.stringify(newConfig));
  };

  const allUniqueBatches = useMemo(() => {
    const batchCol = config.mapping.batchNo;
    if (!batchCol || !headers.includes(batchCol)) return [];
    return Array.from(new Set(data.map(r => String(r[batchCol] || '').trim())))
      .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
  }, [data, config.mapping.batchNo, headers]);

  const filteredData = useMemo(() => {
    const { mapping } = config;
    if (data.length === 0) return [];

    return data.filter(row => {
      // Date Filter
      if (dateRange.start || dateRange.end) {
        const rowDateStr = String(row[mapping.date] || '');
        const rowDate = parseDate(rowDateStr);
        if (!rowDate) return false;
        const start = dateRange.start ? startOfDay(dateRange.start) : new Date(0);
        const end = dateRange.end ? endOfDay(dateRange.end) : new Date(8640000000000000);
        if (!isWithinInterval(rowDate, { start, end })) return false;
      }

      // Batch Filter
      const batchCol = mapping.batchNo;
      if (batchCol && headers.includes(batchCol) && selectedBatches.length > 0 && selectedBatches.length < allUniqueBatches.length) {
        const rowBatch = String(row[batchCol] || '').trim();
        if (!selectedBatches.includes(rowBatch)) return false;
      }

      // UID Search Filter
      if (uidSearch.trim()) {
        const uidCol = mapping.uid;
        const rowUid = String(row[uidCol] || '').toLowerCase();
        if (!rowUid.includes(uidSearch.toLowerCase().trim())) return false;
      }

      return true;
    });
  }, [data, config, dateRange, selectedBatches, uidSearch, headers, allUniqueBatches]);

  const stats: KPIStats = useMemo(() => {
    const { mapping } = config;
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );
    const total = totalData.length;

    const accepted = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    }).length;

    const rejected = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    }).length;

    const inwardCount = filteredData.filter(r => String(r[mapping.inward] || '').trim() !== '').length;
    const wip = Math.max(0, inwardCount - total);
    const yieldVal = total > 0 ? (accepted / total) * 100 : 0;
    return { total, accepted, rejected, wip, yield: yieldVal };
  }, [filteredData, config]);

  const skuDetails = useMemo(() => {
    const { mapping } = config;
    const skuMap: Record<string, { total: number; accepted: number; rejected: number }> = {};

    let skuKey = mapping.sku;
    if (!headers.includes(skuKey)) {
      skuKey = findHeaderMatch(headers, ['sku', 'item', 'part', 'model']) || (headers.length > 0 ? headers[0] : '');
    }

    if (filteredData.length === 0 || !skuKey) {
      return [];
    }

    filteredData.forEach(r => {
      const val = r[skuKey];
      if (val !== undefined && val !== null) {
        const sku = String(val).trim().replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        if (sku !== '') {
          if (!skuMap[sku]) {
            skuMap[sku] = { total: 0, accepted: 0, rejected: 0 };
          }
          skuMap[sku].total += 1;

          const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
          if (['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status)) {
            skuMap[sku].accepted += 1;
          } else if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
            skuMap[sku].rejected += 1;
          }
        }
      }
    });

    return Object.entries(skuMap).map(([sku, s]) => ({
      sku,
      total: s.total,
      accepted: s.accepted,
      rejected: s.rejected,
      yield: s.total > 0 ? (s.accepted / s.total) * 100 : 0
    }));
  }, [filteredData, config, headers, findHeaderMatch]);

  const remainingQtyData = useMemo<RemainingQtyItem[] | null>(() => {
    const hasSkus = headers.includes('SKUs');
    const hasRemainingQty = headers.includes('REMAINING QTY');

    if (!hasSkus || !hasRemainingQty) return null;

    return data
      .map(row => ({
        sku: String(row['SKUs'] || '').trim(),
        qty: Number(row['REMAINING QTY']) || 0
      }))
      .filter(item => item.sku !== '');
  }, [data, headers]);

  const handleCopyReport = () => {
    if (stats.total === 0) {
      alert("No data available");
      return;
    }

    const { mapping } = config;

    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );

    const acceptedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    });

    const acceptedGroups: Record<string, number> = {};
    acceptedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown SKU').trim();
      acceptedGroups[sku] = (acceptedGroups[sku] || 0) + 1;
    });

    const acceptedDetailsStr = Object.entries(acceptedGroups)
      .map(([sku, count]) => `${sku}: ${count}`)
      .join('\n');

    const rejectedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    });

    const rejectedGroups: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const reason = String(r[mapping.reason] || 'No Reason Specified').trim();
      rejectedGroups[reason] = (rejectedGroups[reason] || 0) + 1;
    });

    const rejectedDetailsStr = Object.entries(rejectedGroups)
      .map(([reason, count]) => `${reason}: ${count}`)
      .join('\n');

    const reportText = `------------------------------------
BATCH REPORT

TOTAL : ${stats.total}
ACCEPTED : ${stats.accepted}
REJECTED : ${stats.rejected}
YIELD : ${stats.yield.toFixed(1)}%

ACCEPTED DETAILS
${acceptedDetailsStr || 'None'}

REJECTION DETAILS
${rejectedDetailsStr || 'None'}
------------------------------------`;

    navigator.clipboard.writeText(reportText).then(() => {
      setShowCopyToast(true);
      // Fixed: Change setShowResetToast to setShowCopyToast to fix reference error
      setTimeout(() => setShowCopyToast(false), 3000);
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  return (
    <div className="min-h-screen pb-12 w-full max-w-[100vw] bg-[#0f1117]">
      <header className="sticky top-0 z-40 bg-[#161a23]/90 backdrop-blur-xl border-b border-white/5 shadow-2xl w-full">
        <div className="w-full px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-[#22c55e] rounded-2xl shadow-[0_0_20px_rgba(34,197,94,0.3)]">
                <BarChart3 className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-black text-white leading-tight tracking-tight uppercase">Dashboard</h1>
                <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.4em] mono">Quality Analytics Pro</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              {data.length > 0 && (
                <button 
                  onClick={handleCopyReport}
                  className="flex items-center gap-2 px-5 py-2.5 text-xs font-bold text-[#e5e7eb] bg-[#22c55e]/10 hover:bg-[#22c55e]/20 rounded-xl transition-all border border-[#22c55e]/30"
                >
                  <Copy className="w-4 h-4 text-[#22c55e]" />
                  BATCH REPORT
                </button>
              )}
              {config.url && (
                <button onClick={loadData} className="hidden sm:flex items-center gap-2 px-5 py-2.5 text-xs font-bold text-[#38bdf8] hover:bg-[#38bdf8]/10 rounded-xl transition-all border border-[#38bdf8]/20" disabled={loading}>
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  SYNC
                </button>
              )}
              <button onClick={() => setIsSettingsOpen(true)} className="p-3 bg-[#1e232d] text-[#e5e7eb] hover:bg-[#2a313d] rounded-2xl border border-white/5 transition-all">
                <Menu className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full px-4 sm:px-6 lg:px-8 mt-10">
        {error && (
          <div className="mb-10 p-6 bg-[#ef4444]/10 border border-[#ef4444]/30 rounded-2xl flex items-start gap-4">
            <AlertCircle className="w-6 h-6 text-[#ef4444] shrink-0 mt-1" />
            <div className="flex-1">
              <h4 className="text-sm font-bold text-[#ef4444] uppercase tracking-widest">System Error</h4>
              <p className="text-sm text-[#9ca3af] mt-2 font-medium">{error}</p>
            </div>
          </div>
        )}

        {(!config.url && !loading) ? (
          <div className="py-32 flex flex-col items-center justify-center text-center">
            <div className="w-24 h-24 bg-[#161a23] rounded-3xl flex items-center justify-center mb-8 border border-white/5 shadow-2xl">
              <Database className="w-10 h-10 text-[#38bdf8]" />
            </div>
            <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter">No Stream Detected</h2>
            <p className="text-[#9ca3af] max-sm mx-auto mb-10 text-sm leading-relaxed">
              Connect to a valid Google Sheet to initialize analytical rendering.
            </p>
            <button onClick={() => setIsSettingsOpen(true)} className="px-10 py-4 bg-[#38bdf8] hover:bg-[#0ea5e9] text-white font-bold rounded-2xl shadow-xl transition-all">
              OPEN CONFIG
            </button>
          </div>
        ) : (
          <div className="animate-in fade-in duration-700 space-y-10 w-full">
            <FilterSection 
              batches={allUniqueBatches} 
              selectedBatches={selectedBatches} 
              setSelectedBatches={setSelectedBatches} 
              dateRange={dateRange} 
              setDateRange={setDateRange}
              uidSearch={uidSearch}
              setUidSearch={setUidSearch}
            />
            <KPIGrid stats={stats} loading={loading} />

            {data.length > 0 && (
              <>
                <div className="flex items-center justify-between px-6 py-4 bg-[#161a23] rounded-2xl border border-white/5">
                  <div className="flex items-center gap-6">
                    <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono">
                      Source: <span className="text-[#38bdf8]">{config.sheetName}</span>
                    </p>
                    <p className="hidden md:block text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono border-l border-white/10 pl-6">
                      Updated: <span className="text-white">{new Date().toLocaleTimeString()}</span>
                    </p>
                  </div>
                  <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono">
                    Total Records: <span className="text-white bg-white/5 px-2 py-0.5 rounded ml-2">{filteredData.length}</span>
                  </p>
                </div>

                <SKUDetailsSection skuDetails={skuDetails} />

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-stretch pb-10">
                  <RemainingQtySection data={remainingQtyData} />
                  <RejectionDetailsSection filteredData={filteredData} mapping={config.mapping} headers={headers} />
                </div>
              </>
            )}
          </div>
        )}
      </main>

      {showCopyToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-4 fade-in duration-300">
          <div className="px-8 py-4 bg-[#161a23] border border-[#22c55e]/30 rounded-2xl shadow-2xl flex items-center gap-3 backdrop-blur-xl">
            <Check className="w-5 h-5 text-[#22c55e]" />
            <span className="text-sm font-bold text-white uppercase tracking-widest">Report Copied to Clipboard</span>
          </div>
        </div>
      )}

      <SettingsMenu config={config} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

export default App;

import React from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';
import { AlertCircle, TrendingUp } from 'lucide-react';

interface SKUTrendChartProps {
  data: any[];
  skuList: string[];
  isMissingColumns: boolean;
}

const COLORS = [
  '#38bdf8', '#22c55e', '#ef4444', '#f59e0b', '#a855f7', 
  '#ec4899', '#06b6d4', '#84cc16', '#f97316', '#6366f1',
  '#10b981', '#f43f5e', '#8b5cf6', '#d946ef', '#14b8a6'
];

const SKUTrendChart: React.FC<SKUTrendChartProps> = ({ data, skuList, isMissingColumns }) => {
  if (isMissingColumns) {
    return (
      <div className="premium-card p-8 min-h-[400px] flex flex-col items-center justify-center text-rose-500">
        <AlertCircle className="w-10 h-10 mb-4 opacity-50" />
        <p className="text-sm font-bold uppercase tracking-widest">Required Columns (DATE/SKU) Missing</p>
      </div>
    );
  }

  if (data.length === 0) {
    return (
      <div className="premium-card p-8 min-h-[400px] flex flex-col items-center justify-center text-[#9ca3af]/40">
        <TrendingUp className="w-10 h-10 mb-4 opacity-20" />
        <p className="text-xs font-bold uppercase tracking-[0.2em] italic">No SKU trend data available</p>
      </div>
    );
  }

  return (
    <div className="premium-card p-8 animate-in fade-in duration-700">
      <div className="flex items-center gap-4 mb-8">
        <div className="w-1.5 h-6 bg-[#38bdf8] rounded-full shadow-[0_0_15px_rgba(56,189,248,0.5)]" />
        <h3 className="text-sm font-bold text-[#e5e7eb] uppercase tracking-[0.2em] mono">
          SKU TREND BY DATE
        </h3>
      </div>

      <div className="h-[450px] w-full">
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={data} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
            <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" vertical={false} />
            <XAxis 
              dataKey="date" 
              stroke="#4b5563" 
              fontSize={10} 
              tickMargin={10}
              tickFormatter={(str) => {
                const d = new Date(str);
                return d.toLocaleDateString(undefined, { day: '2-digit', month: 'short' });
              }}
              className="mono"
            />
            <YAxis 
              stroke="#4b5563" 
              fontSize={10} 
              className="mono"
              allowDecimals={false}
            />
            <Tooltip 
              contentStyle={{ 
                backgroundColor: '#161a23', 
                border: '1px solid rgba(255,255,255,0.1)', 
                borderRadius: '12px',
                fontSize: '12px',
                boxShadow: '0 10px 30px rgba(0,0,0,0.5)'
              }}
              itemStyle={{ fontWeight: 'bold' }}
              labelStyle={{ color: '#9ca3af', marginBottom: '8px', fontSize: '10px', textTransform: 'uppercase' }}
            />
            <Legend 
              wrapperStyle={{ 
                paddingTop: '20px',
                maxHeight: '100px',
                overflowY: 'auto',
                fontSize: '10px'
              }} 
            />
            {skuList.map((sku, index) => (
              <Line
                key={sku}
                type="monotone"
                dataKey={sku}
                stroke={COLORS[index % COLORS.length]}
                strokeWidth={2.5}
                dot={{ r: 3, strokeWidth: 2, fill: '#161a23' }}
                activeDot={{ r: 6, strokeWidth: 0 }}
                animationDuration={1500}
                connectNulls
              />
            ))}
          </LineChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default SKUTrendChart;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu, AlertCircle, ExternalLink, RefreshCw, BarChart3, Database, Copy, Check } from 'lucide-react';
import { INITIAL_CONFIG } from './constants';
import { SheetConfig, DashboardRow, KPIStats, SKUDetail, RemainingQtyItem } from './types';
import { fetchSheetData, parseDate } from './services/sheetService';
import KPIGrid from './components/KPIGrid';
import FilterSection from './components/FilterSection';
import SKUDetailsSection from './components/SKUDetailsSection';
import RemainingQtySection from './components/RemainingQtySection';
import RejectionDetailsSection from './components/RejectionDetailsSection';
import SKUTrendChart from './components/SKUTrendChart';
import SettingsMenu from './components/SettingsMenu';
import { isWithinInterval, startOfDay, endOfDay, format } from 'date-fns';

const App: React.FC = () => {
  const [config, setConfig] = useState<SheetConfig>(() => {
    const saved = localStorage.getItem('qc_dashboard_config');
    return saved ? JSON.parse(saved) : INITIAL_CONFIG;
  });

  const [data, setData] = useState<DashboardRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showCopyToast, setShowCopyToast] = useState(false);

  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });
  const [uidSearch, setUidSearch] = useState('');

  // Robust column detection with priority on SKU
  const findHeaderMatch = useCallback((availableHeaders: string[], searchTerms: string[]): string | undefined => {
    if (!availableHeaders.length) return undefined;

    const lowerHeaders = availableHeaders.map(h => h.trim().toLowerCase());

    for (const term of searchTerms) {
      const idx = lowerHeaders.indexOf(term.toLowerCase());
      if (idx !== -1) return availableHeaders[idx];
    }

    const contains = availableHeaders.find(h => 
      searchTerms.some(term => h.toLowerCase().includes(term.toLowerCase()))
    );
    if (contains) return contains;

    return availableHeaders.find(h => {
      const normalized = h.toLowerCase().replace(/[^a-z0-9]/g, '');
      return searchTerms.some(term => {
        const termNorm = term.toLowerCase().replace(/[^a-z0-9]/g, '');
        return normalized.includes(termNorm) || termNorm.includes(normalized);
      });
    });
  }, []);

  const autoDetectMapping = useCallback((availableHeaders: string[]) => {
    const mapping = { ...config.mapping };

    const aliases = {
      sku: ['sku', 'item', 'part', 'article', 'model', 'product', 'code'],
      batchNo: ['batch', 'lot', 'serial'],
      ringStatus: ['status', 'result', 'outcome', 'quality'],
      uid: ['uid', 'id', 'barcode', 'serial'],
      date: ['date', 'time', 'timestamp'],
      inward: ['inward', 'qty', 'count', 'total'],
      reason: ['reason', 'rejection', 'defect', 'cause', 'fault'],
    };

    (Object.entries(aliases) as [keyof typeof aliases, string[]][]).forEach(([key, terms]) => {
      const currentVal = mapping[key as keyof typeof mapping];
      if (!currentVal || !availableHeaders.includes(currentVal)) {
        const detected = findHeaderMatch(availableHeaders, terms);
        if (detected) {
          (mapping as any)[key] = detected;
        }
      }
    });

    return mapping;
  }, [config.mapping, findHeaderMatch]);

  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("CONFIGURATION REQUIRED: Please link a valid public Google Sheet.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const { data: rawData, headers: sheetHeaders } = await fetchSheetData(config.url, config.sheetName);
      setHeaders(sheetHeaders);

      const updatedMapping = autoDetectMapping(sheetHeaders);
      if (JSON.stringify(updatedMapping) !== JSON.stringify(config.mapping)) {
        setConfig(prev => ({ ...prev, mapping: updatedMapping }));
      }

      setData(rawData);

      const batchCol = updatedMapping.batchNo;
      if (batchCol && sheetHeaders.includes(batchCol)) {
        const uniqueBatches = Array.from(new Set(rawData.map(r => String(r[batchCol] || '').trim())))
          .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
        setSelectedBatches(uniqueBatches);
      } else {
        setSelectedBatches([]);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [config.url, config.sheetName, autoDetectMapping]);

  useEffect(() => { 
    if (config.url) loadData(); 
  }, [config.url, config.sheetName]);

  const handleConfigUpdate = (newConfig: SheetConfig) => {
    setConfig(newConfig);
    localStorage.setItem('qc_dashboard_config', JSON.stringify(newConfig));
  };

  const allUniqueBatches = useMemo(() => {
    const batchCol = config.mapping.batchNo;
    if (!batchCol || !headers.includes(batchCol)) return [];
    return Array.from(new Set(data.map(r => String(r[batchCol] || '').trim())))
      .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
  }, [data, config.mapping.batchNo, headers]);

  const filteredData = useMemo(() => {
    const { mapping } = config;
    if (data.length === 0) return [];

    return data.filter(row => {
      // Date Filter
      if (dateRange.start || dateRange.end) {
        const rowDateStr = String(row[mapping.date] || '');
        const rowDate = parseDate(rowDateStr);
        if (!rowDate) return false;
        const start = dateRange.start ? startOfDay(dateRange.start) : new Date(0);
        const end = dateRange.end ? endOfDay(dateRange.end) : new Date(8640000000000000);
        if (!isWithinInterval(rowDate, { start, end })) return false;
      }

      // Batch Filter
      const batchCol = mapping.batchNo;
      if (batchCol && headers.includes(batchCol) && selectedBatches.length > 0 && selectedBatches.length < allUniqueBatches.length) {
        const rowBatch = String(row[batchCol] || '').trim();
        if (!selectedBatches.includes(rowBatch)) return false;
      }

      // UID Search Filter
      if (uidSearch.trim()) {
        const uidCol = mapping.uid;
        const rowUid = String(row[uidCol] || '').toLowerCase();
        if (!rowUid.includes(uidSearch.toLowerCase().trim())) return false;
      }

      return true;
    });
  }, [data, config, dateRange, selectedBatches, uidSearch, headers, allUniqueBatches]);

  const stats: KPIStats = useMemo(() => {
    const { mapping } = config;
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );
    const total = totalData.length;

    const accepted = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    }).length;

    const rejected = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    }).length;

    const inwardCount = filteredData.filter(r => String(r[mapping.inward] || '').trim() !== '').length;
    const wip = Math.max(0, inwardCount - total);
    const yieldVal = total > 0 ? (accepted / total) * 100 : 0;
    return { total, accepted, rejected, wip, yield: yieldVal };
  }, [filteredData, config]);

  const skuDetails = useMemo(() => {
    const { mapping } = config;
    const skuMap: Record<string, { total: number; accepted: number; rejected: number }> = {};

    let skuKey = mapping.sku;
    if (!headers.includes(skuKey)) {
      skuKey = findHeaderMatch(headers, ['sku', 'item', 'part', 'model']) || (headers.length > 0 ? headers[0] : '');
    }

    if (filteredData.length === 0 || !skuKey) {
      return [];
    }

    filteredData.forEach(r => {
      const val = r[skuKey];
      if (val !== undefined && val !== null) {
        const sku = String(val).trim().replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        if (sku !== '') {
          if (!skuMap[sku]) {
            skuMap[sku] = { total: 0, accepted: 0, rejected: 0 };
          }
          skuMap[sku].total += 1;

          const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
          if (['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status)) {
            skuMap[sku].accepted += 1;
          } else if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
            skuMap[sku].rejected += 1;
          }
        }
      }
    });

    return Object.entries(skuMap).map(([sku, s]) => ({
      sku,
      total: s.total,
      accepted: s.accepted,
      rejected: s.rejected,
      yield: s.total > 0 ? (s.accepted / s.total) * 100 : 0
    }));
  }, [filteredData, config, headers, findHeaderMatch]);

  const trendDataAggregation = useMemo(() => {
    const { mapping } = config;
    const dateKey = mapping.date;
    const skuKey = mapping.sku;

    if (!headers.includes(dateKey) || !headers.includes(skuKey)) {
      return { data: [], skus: [], isMissing: true };
    }

    const grouped: Record<string, Record<string, number>> = {};
    const uniqueSkus = new Set<string>();

    filteredData.forEach(row => {
      const dateStr = String(row[dateKey] || '').trim();
      const skuStr = String(row[skuKey] || '').trim();

      if (!dateStr || !skuStr) return;

      const parsed = parseDate(dateStr);
      if (!parsed) return;

      const formattedDate = format(parsed, 'yyyy-MM-dd');
      uniqueSkus.add(skuStr);

      if (!grouped[formattedDate]) grouped[formattedDate] = {};
      grouped[formattedDate][skuStr] = (grouped[formattedDate][skuStr] || 0) + 1;
    });

    const sortedDates = Object.keys(grouped).sort();
    const result = sortedDates.map(date => ({
      date,
      ...grouped[date]
    }));

    return { 
      data: result, 
      skus: Array.from(uniqueSkus).sort(), 
      isMissing: false 
    };
  }, [filteredData, config, headers]);

  const remainingQtyData = useMemo<RemainingQtyItem[] | null>(() => {
    const hasSkus = headers.includes('SKUs');
    const hasRemainingQty = headers.includes('REMAINING QTY');

    if (!hasSkus || !hasRemainingQty) return null;

    return data
      .map(row => ({
        sku: String(row['SKUs'] || '').trim(),
        qty: Number(row['REMAINING QTY']) || 0
      }))
      .filter(item => item.sku !== '');
  }, [data, headers]);

  const handleCopyReport = () => {
    if (stats.total === 0) {
      alert("No data available");
      return;
    }

    const { mapping } = config;

    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );

    const acceptedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    });

    const acceptedGroups: Record<string, number> = {};
    acceptedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown SKU').trim();
      acceptedGroups[sku] = (acceptedGroups[sku] || 0) + 1;
    });

    const acceptedDetailsStr = Object.entries(acceptedGroups)
      .map(([sku, count]) => `${sku}: ${count}`)
      .join('\n');

    const rejectedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    });

    const rejectedGroups: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const reason = String(r[mapping.reason] || 'No Reason Specified').trim();
      rejectedGroups[reason] = (rejectedGroups[reason] || 0) + 1;
    });

    const rejectedDetailsStr = Object.entries(rejectedGroups)
      .map(([reason, count]) => `${reason}: ${count}`)
      .join('\n');

    const reportText = `------------------------------------
BATCH REPORT

TOTAL : ${stats.total}
ACCEPTED : ${stats.accepted}
REJECTED : ${stats.rejected}
YIELD : ${stats.yield.toFixed(1)}%

ACCEPTED DETAILS
${acceptedDetailsStr || 'None'}

REJECTION DETAILS
${rejectedDetailsStr || 'None'}
------------------------------------`;

    navigator.clipboard.writeText(reportText).then(() => {
      setShowCopyToast(true);
      setTimeout(() => setShowCopyToast(false), 3000);
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  return (
    <div className="min-h-screen pb-12 w-full max-w-[100vw] bg-[#0f1117]">
      <header className="sticky top-0 z-40 bg-[#161a23]/90 backdrop-blur-xl border-b border-white/5 shadow-2xl w-full">
        <div className="w-full px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-[#22c55e] rounded-2xl shadow-[0_0_20px_rgba(34,197,94,0.3)]">
                <BarChart3 className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="text-xl font-black text-white leading-tight tracking-tight uppercase">Dashboard</h1>
                <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.4em] mono">Quality Analytics Pro</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              {data.length > 0 && (
                <button 
                  onClick={handleCopyReport}
                  className="flex items-center gap-2 px-5 py-2.5 text-xs font-bold text-[#e5e7eb] bg-[#22c55e]/10 hover:bg-[#22c55e]/20 rounded-xl transition-all border border-[#22c55e]/30"
                >
                  <Copy className="w-4 h-4 text-[#22c55e]" />
                  BATCH REPORT
                </button>
              )}
              {config.url && (
                <button onClick={loadData} className="hidden sm:flex items-center gap-2 px-5 py-2.5 text-xs font-bold text-[#38bdf8] hover:bg-[#38bdf8]/10 rounded-xl transition-all border border-[#38bdf8]/20" disabled={loading}>
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  SYNC
                </button>
              )}
              <button onClick={() => setIsSettingsOpen(true)} className="p-3 bg-[#1e232d] text-[#e5e7eb] hover:bg-[#2a313d] rounded-2xl border border-white/5 transition-all">
                <Menu className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full px-4 sm:px-6 lg:px-8 mt-10">
        {error && (
          <div className="mb-10 p-6 bg-[#ef4444]/10 border border-[#ef4444]/30 rounded-2xl flex items-start gap-4">
            <AlertCircle className="w-6 h-6 text-[#ef4444] shrink-0 mt-1" />
            <div className="flex-1">
              <h4 className="text-sm font-bold text-[#ef4444] uppercase tracking-widest">System Error</h4>
              <p className="text-sm text-[#9ca3af] mt-2 font-medium">{error}</p>
            </div>
          </div>
        )}

        {(!config.url && !loading) ? (
          <div className="py-32 flex flex-col items-center justify-center text-center">
            <div className="w-24 h-24 bg-[#161a23] rounded-3xl flex items-center justify-center mb-8 border border-white/5 shadow-2xl">
              <Database className="w-10 h-10 text-[#38bdf8]" />
            </div>
            <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter">No Stream Detected</h2>
            <p className="text-[#9ca3af] max-sm mx-auto mb-10 text-sm leading-relaxed">
              Connect to a valid Google Sheet to initialize analytical rendering.
            </p>
            <button onClick={() => setIsSettingsOpen(true)} className="px-10 py-4 bg-[#38bdf8] hover:bg-[#0ea5e9] text-white font-bold rounded-2xl shadow-xl transition-all">
              OPEN CONFIG
            </button>
          </div>
        ) : (
          <div className="animate-in fade-in duration-700 space-y-10 w-full">
            <FilterSection 
              batches={allUniqueBatches} 
              selectedBatches={selectedBatches} 
              setSelectedBatches={setSelectedBatches} 
              dateRange={dateRange} 
              setDateRange={setDateRange}
              uidSearch={uidSearch}
              setUidSearch={setUidSearch}
            />
            <KPIGrid stats={stats} loading={loading} />

            {data.length > 0 && (
              <>
                <div className="flex items-center justify-between px-6 py-4 bg-[#161a23] rounded-2xl border border-white/5">
                  <div className="flex items-center gap-6">
                    <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono">
                      Source: <span className="text-[#38bdf8]">{config.sheetName}</span>
                    </p>
                    <p className="hidden md:block text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono border-l border-white/10 pl-6">
                      Updated: <span className="text-white">{new Date().toLocaleTimeString()}</span>
                    </p>
                  </div>
                  <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono">
                    Total Records: <span className="text-white bg-white/5 px-2 py-0.5 rounded ml-2">{filteredData.length}</span>
                  </p>
                </div>

                <SKUDetailsSection skuDetails={skuDetails} />

                <SKUTrendChart 
                  data={trendDataAggregation.data} 
                  skuList={trendDataAggregation.skus} 
                  isMissingColumns={trendDataAggregation.isMissing} 
                />

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-stretch pb-10">
                  <RemainingQtySection data={remainingQtyData} />
                  <RejectionDetailsSection filteredData={filteredData} mapping={config.mapping} headers={headers} />
                </div>
              </>
            )}
          </div>
        )}
      </main>

      {showCopyToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-4 fade-in duration-300">
          <div className="px-8 py-4 bg-[#161a23] border border-[#22c55e]/30 rounded-2xl shadow-2xl flex items-center gap-3 backdrop-blur-xl">
            <Check className="w-5 h-5 text-[#22c55e]" />
            <span className="text-sm font-bold text-white uppercase tracking-widest">Report Copied to Clipboard</span>
          </div>
        </div>
      )}

      <SettingsMenu config={config} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Menu, AlertCircle, ExternalLink, RefreshCw, BarChart3, Database, Copy, Check } from 'lucide-react';
import { INITIAL_CONFIG } from './constants';
import { SheetConfig, DashboardRow, KPIStats, SKUDetail, RemainingQtyItem } from './types';
import { fetchSheetData, parseDate } from './services/sheetService';
import KPIGrid from './components/KPIGrid';
import FilterSection from './components/FilterSection';
import SKUDetailsSection from './components/SKUDetailsSection';
import RemainingQtySection from './components/RemainingQtySection';
import RejectionDetailsSection from './components/RejectionDetailsSection';
import SKUTrendChart from './components/SKUTrendChart';
import SettingsMenu from './components/SettingsMenu';
import { isWithinInterval, startOfDay, endOfDay, format } from 'date-fns';

const App: React.FC = () => {
  const [config, setConfig] = useState<SheetConfig>(() => {
    const saved = localStorage.getItem('qc_dashboard_config');
    return saved ? JSON.parse(saved) : INITIAL_CONFIG;
  });

  const [data, setData] = useState<DashboardRow[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [showCopyToast, setShowCopyToast] = useState(false);

  const [selectedBatches, setSelectedBatches] = useState<string[]>([]);
  const [dateRange, setDateRange] = useState<{ start: Date | null; end: Date | null }>({ start: null, end: null });
  const [uidSearch, setUidSearch] = useState('');

  // Robust column detection with priority on SKU
  const findHeaderMatch = useCallback((availableHeaders: string[], searchTerms: string[]): string | undefined => {
    if (!availableHeaders.length) return undefined;

    const lowerHeaders = availableHeaders.map(h => h.trim().toLowerCase());

    for (const term of searchTerms) {
      const idx = lowerHeaders.indexOf(term.toLowerCase());
      if (idx !== -1) return availableHeaders[idx];
    }

    const contains = availableHeaders.find(h => 
      searchTerms.some(term => h.toLowerCase().includes(term.toLowerCase()))
    );
    if (contains) return contains;

    return availableHeaders.find(h => {
      const normalized = h.toLowerCase().replace(/[^a-z0-9]/g, '');
      return searchTerms.some(term => {
        const termNorm = term.toLowerCase().replace(/[^a-z0-9]/g, '');
        return normalized.includes(termNorm) || termNorm.includes(normalized);
      });
    });
  }, []);

  const autoDetectMapping = useCallback((availableHeaders: string[]) => {
    const mapping = { ...config.mapping };

    const aliases = {
      sku: ['sku', 'item', 'part', 'article', 'model', 'product', 'code'],
      batchNo: ['batch', 'lot', 'serial'],
      ringStatus: ['status', 'result', 'outcome', 'quality'],
      uid: ['uid', 'id', 'barcode', 'serial'],
      date: ['date', 'time', 'timestamp'],
      inward: ['inward', 'qty', 'count', 'total'],
      reason: ['reason', 'rejection', 'defect', 'cause', 'fault'],
    };

    (Object.entries(aliases) as [keyof typeof aliases, string[]][]).forEach(([key, terms]) => {
      const currentVal = mapping[key as keyof typeof mapping];
      if (!currentVal || !availableHeaders.includes(currentVal)) {
        const detected = findHeaderMatch(availableHeaders, terms);
        if (detected) {
          (mapping as any)[key] = detected;
        }
      }
    });

    return mapping;
  }, [config.mapping, findHeaderMatch]);

  const loadData = useCallback(async () => {
    if (!config.url) {
      setError("CONFIGURATION REQUIRED: Please link a valid public Google Sheet.");
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const { data: rawData, headers: sheetHeaders } = await fetchSheetData(config.url, config.sheetName);
      setHeaders(sheetHeaders);

      const updatedMapping = autoDetectMapping(sheetHeaders);
      if (JSON.stringify(updatedMapping) !== JSON.stringify(config.mapping)) {
        setConfig(prev => ({ ...prev, mapping: updatedMapping }));
      }

      setData(rawData);

      const batchCol = updatedMapping.batchNo;
      if (batchCol && sheetHeaders.includes(batchCol)) {
        const uniqueBatches = Array.from(new Set(rawData.map(r => String(r[batchCol] || '').trim())))
          .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
        setSelectedBatches(uniqueBatches);
      } else {
        setSelectedBatches([]);
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [config.url, config.sheetName, autoDetectMapping]);

  useEffect(() => { 
    if (config.url) loadData(); 
  }, [config.url, config.sheetName]);

  const handleConfigUpdate = (newConfig: SheetConfig) => {
    setConfig(newConfig);
    localStorage.setItem('qc_dashboard_config', JSON.stringify(newConfig));
  };

  const allUniqueBatches = useMemo(() => {
    const batchCol = config.mapping.batchNo;
    if (!batchCol || !headers.includes(batchCol)) return [];
    return Array.from(new Set(data.map(r => String(r[batchCol] || '').trim())))
      .sort((a: string, b: string) => b.localeCompare(a, undefined, { numeric: true, sensitivity: 'base' }));
  }, [data, config.mapping.batchNo, headers]);

  const filteredData = useMemo(() => {
    const { mapping } = config;
    if (data.length === 0) return [];

    return data.filter(row => {
      // Date Filter
      if (dateRange.start || dateRange.end) {
        const rowDateStr = String(row[mapping.date] || '');
        const rowDate = parseDate(rowDateStr);
        if (!rowDate) return false;
        const start = dateRange.start ? startOfDay(dateRange.start) : new Date(0);
        const end = dateRange.end ? endOfDay(dateRange.end) : new Date(8640000000000000);
        if (!isWithinInterval(rowDate, { start, end })) return false;
      }

      // Batch Filter
      const batchCol = mapping.batchNo;
      if (batchCol && headers.includes(batchCol) && selectedBatches.length > 0 && selectedBatches.length < allUniqueBatches.length) {
        const rowBatch = String(row[batchCol] || '').trim();
        if (!selectedBatches.includes(rowBatch)) return false;
      }

      // UID Search Filter
      if (uidSearch.trim()) {
        const uidCol = mapping.uid;
        const rowUid = String(row[uidCol] || '').toLowerCase();
        if (!rowUid.includes(uidSearch.toLowerCase().trim())) return false;
      }

      return true;
    });
  }, [data, config, dateRange, selectedBatches, uidSearch, headers, allUniqueBatches]);

  const stats: KPIStats = useMemo(() => {
    const { mapping } = config;
    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );
    const total = totalData.length;

    const accepted = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    }).length;

    const rejected = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    }).length;

    const inwardCount = filteredData.filter(r => String(r[mapping.inward] || '').trim() !== '').length;
    const wip = Math.max(0, inwardCount - total);
    const yieldVal = total > 0 ? (accepted / total) * 100 : 0;
    return { total, accepted, rejected, wip, yield: yieldVal };
  }, [filteredData, config]);

  const skuDetails = useMemo(() => {
    const { mapping } = config;
    const skuMap: Record<string, { total: number; accepted: number; rejected: number }> = {};

    let skuKey = mapping.sku;
    if (!headers.includes(skuKey)) {
      skuKey = findHeaderMatch(headers, ['sku', 'item', 'part', 'model']) || (headers.length > 0 ? headers[0] : '');
    }

    if (filteredData.length === 0 || !skuKey) {
      return [];
    }

    filteredData.forEach(r => {
      const val = r[skuKey];
      if (val !== undefined && val !== null) {
        const sku = String(val).trim().replace(/[\u0000-\u001F\u007F-\u009F]/g, ""); 
        if (sku !== '') {
          if (!skuMap[sku]) {
            skuMap[sku] = { total: 0, accepted: 0, rejected: 0 };
          }
          skuMap[sku].total += 1;

          const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
          if (['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status)) {
            skuMap[sku].accepted += 1;
          } else if (['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status)) {
            skuMap[sku].rejected += 1;
          }
        }
      }
    });

    return Object.entries(skuMap).map(([sku, s]) => ({
      sku,
      total: s.total,
      accepted: s.accepted,
      rejected: s.rejected,
      yield: s.total > 0 ? (s.accepted / s.total) * 100 : 0
    }));
  }, [filteredData, config, headers, findHeaderMatch]);

  const trendDataAggregation = useMemo(() => {
    const { mapping } = config;
    const dateKey = mapping.date;
    const skuKey = mapping.sku;

    if (!headers.includes(dateKey) || !headers.includes(skuKey)) {
      return { data: [], skus: [], isMissing: true };
    }

    const grouped: Record<string, Record<string, number>> = {};
    const uniqueSkus = new Set<string>();

    filteredData.forEach(row => {
      const dateStr = String(row[dateKey] || '').trim();
      const skuStr = String(row[skuKey] || '').trim();

      if (!dateStr || !skuStr) return;

      const parsed = parseDate(dateStr);
      if (!parsed) return;

      const formattedDate = format(parsed, 'yyyy-MM-dd');
      uniqueSkus.add(skuStr);

      if (!grouped[formattedDate]) grouped[formattedDate] = {};
      grouped[formattedDate][skuStr] = (grouped[formattedDate][skuStr] || 0) + 1;
    });

    const sortedDates = Object.keys(grouped).sort();
    const result = sortedDates.map(date => ({
      date,
      ...grouped[date]
    }));

    return { 
      data: result, 
      skus: Array.from(uniqueSkus).sort(), 
      isMissing: false 
    };
  }, [filteredData, config, headers]);

  const remainingQtyData = useMemo<RemainingQtyItem[] | null>(() => {
    const hasSkus = headers.includes('SKUs');
    const hasRemainingQty = headers.includes('REMAINING QTY');

    if (!hasSkus || !hasRemainingQty) return null;

    return data
      .map(row => ({
        sku: String(row['SKUs'] || '').trim(),
        qty: Number(row['REMAINING QTY']) || 0
      }))
      .filter(item => item.sku !== '');
  }, [data, headers]);

  const handleCopyReport = () => {
    if (stats.total === 0) {
      alert("No data available");
      return;
    }

    const { mapping } = config;

    const totalData = filteredData.filter(r => 
      String(r[mapping.uid] || '').trim() !== '' || 
      String(r[mapping.sku] || '').trim() !== ''
    );

    const acceptedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['accepted', 'ok', 'pass', '1', 'true', 'yes'].includes(status);
    });

    const acceptedGroups: Record<string, number> = {};
    acceptedRows.forEach(r => {
      const sku = String(r[mapping.sku] || 'Unknown SKU').trim();
      acceptedGroups[sku] = (acceptedGroups[sku] || 0) + 1;
    });

    const acceptedDetailsStr = Object.entries(acceptedGroups)
      .map(([sku, count]) => `${sku}: ${count}`)
      .join('\n');

    const rejectedRows = totalData.filter(r => {
      const status = String(r[mapping.ringStatus] || '').trim().toLowerCase();
      return ['rejected', 'nok', 'fail', '0', 'false', 'no'].includes(status);
    });

    const rejectedGroups: Record<string, number> = {};
    rejectedRows.forEach(r => {
      const reason = String(r[mapping.reason] || 'No Reason Specified').trim();
      rejectedGroups[reason] = (rejectedGroups[reason] || 0) + 1;
    });

    const rejectedDetailsStr = Object.entries(rejectedGroups)
      .map(([reason, count]) => `${reason}: ${count}`)
      .join('\n');

    const reportText = `------------------------------------
BATCH REPORT

TOTAL : ${stats.total}
ACCEPTED : ${stats.accepted}
REJECTED : ${stats.rejected}
YIELD : ${stats.yield.toFixed(1)}%

ACCEPTED DETAILS
${acceptedDetailsStr || 'None'}

REJECTION DETAILS
${rejectedDetailsStr || 'None'}
------------------------------------`;

    navigator.clipboard.writeText(reportText).then(() => {
      setShowCopyToast(true);
      setTimeout(() => setShowCopyToast(false), 3000);
    }).catch(err => {
      console.error('Failed to copy: ', err);
    });
  };

  return (
    <div className="min-h-screen pb-12 w-full max-w-[100vw] bg-[#0f1117]">
      <header className="sticky top-0 z-40 bg-[#161a23]/90 backdrop-blur-xl border-b border-white/5 shadow-2xl w-full">
        <div className="w-full px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-[#1a1c22] rounded-2xl shadow-[0_0_20px_rgba(34,197,94,0.2)] border border-[#22c55e]/20 p-2.5 flex items-center justify-center overflow-hidden">
                <svg viewBox="0 0 100 100" className="w-full h-full text-white fill-current">
                   <rect x="25" y="30" width="50" height="20" />
                   <path d="M25 50 L40 70 L60 70 L75 50 Z" />
                </svg>
              </div>
              <div>
                <h1 className="text-xl font-black text-white leading-tight tracking-tight uppercase">Dashboard</h1>
                <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.4em] mono">Quality Analytics Pro</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              {data.length > 0 && (
                <button 
                  onClick={handleCopyReport}
                  className="flex items-center gap-2 px-5 py-2.5 text-xs font-bold text-[#e5e7eb] bg-[#22c55e]/10 hover:bg-[#22c55e]/20 rounded-xl transition-all border border-[#22c55e]/30"
                >
                  <Copy className="w-4 h-4 text-[#22c55e]" />
                  BATCH REPORT
                </button>
              )}
              {config.url && (
                <button onClick={loadData} className="hidden sm:flex items-center gap-2 px-5 py-2.5 text-xs font-bold text-[#38bdf8] hover:bg-[#38bdf8]/10 rounded-xl transition-all border border-[#38bdf8]/20" disabled={loading}>
                  <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
                  SYNC
                </button>
              )}
              <button onClick={() => setIsSettingsOpen(true)} className="p-3 bg-[#1e232d] text-[#e5e7eb] hover:bg-[#2a313d] rounded-2xl border border-white/5 transition-all">
                <Menu className="w-6 h-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="w-full px-4 sm:px-6 lg:px-8 mt-10">
        {error && (
          <div className="mb-10 p-6 bg-[#ef4444]/10 border border-[#ef4444]/30 rounded-2xl flex items-start gap-4">
            <AlertCircle className="w-6 h-6 text-[#ef4444] shrink-0 mt-1" />
            <div className="flex-1">
              <h4 className="text-sm font-bold text-[#ef4444] uppercase tracking-widest">System Error</h4>
              <p className="text-sm text-[#9ca3af] mt-2 font-medium">{error}</p>
            </div>
          </div>
        )}

        {(!config.url && !loading) ? (
          <div className="py-32 flex flex-col items-center justify-center text-center">
            <div className="w-24 h-24 bg-[#161a23] rounded-3xl flex items-center justify-center mb-8 border border-white/5 shadow-2xl">
              <Database className="w-10 h-10 text-[#38bdf8]" />
            </div>
            <h2 className="text-3xl font-black text-white mb-4 uppercase tracking-tighter">No Stream Detected</h2>
            <p className="text-[#9ca3af] max-sm mx-auto mb-10 text-sm leading-relaxed">
              Connect to a valid Google Sheet to initialize analytical rendering.
            </p>
            <button onClick={() => setIsSettingsOpen(true)} className="px-10 py-4 bg-[#38bdf8] hover:bg-[#0ea5e9] text-white font-bold rounded-2xl shadow-xl transition-all">
              OPEN CONFIG
            </button>
          </div>
        ) : (
          <div className="animate-in fade-in duration-700 space-y-10 w-full">
            <FilterSection 
              batches={allUniqueBatches} 
              selectedBatches={selectedBatches} 
              setSelectedBatches={setSelectedBatches} 
              dateRange={dateRange} 
              setDateRange={setDateRange}
              uidSearch={uidSearch}
              setUidSearch={setUidSearch}
            />
            <KPIGrid stats={stats} loading={loading} />

            {data.length > 0 && (
              <>
                <div className="flex items-center justify-between px-6 py-4 bg-[#161a23] rounded-2xl border border-white/5">
                  <div className="flex items-center gap-6">
                    <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono">
                      Source: <span className="text-[#38bdf8]">{config.sheetName}</span>
                    </p>
                    <p className="hidden md:block text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono border-l border-white/10 pl-6">
                      Updated: <span className="text-white">{new Date().toLocaleTimeString()}</span>
                    </p>
                  </div>
                  <p className="text-[10px] font-bold text-[#9ca3af] uppercase tracking-[0.2em] mono">
                    Total Records: <span className="text-white bg-white/5 px-2 py-0.5 rounded ml-2">{filteredData.length}</span>
                  </p>
                </div>

                <SKUDetailsSection skuDetails={skuDetails} />

                <SKUTrendChart 
                  data={trendDataAggregation.data} 
                  skuList={trendDataAggregation.skus} 
                  isMissingColumns={trendDataAggregation.isMissing} 
                />

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-stretch pb-10">
                  <RemainingQtySection data={remainingQtyData} />
                  <RejectionDetailsSection filteredData={filteredData} mapping={config.mapping} headers={headers} />
                </div>
              </>
            )}
          </div>
        )}
      </main>

      {showCopyToast && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-4 fade-in duration-300">
          <div className="px-8 py-4 bg-[#161a23] border border-[#22c55e]/30 rounded-2xl shadow-2xl flex items-center gap-3 backdrop-blur-xl">
            <Check className="w-5 h-5 text-[#22c55e]" />
            <span className="text-sm font-bold text-white uppercase tracking-widest">Report Copied to Clipboard</span>
          </div>
        </div>
      )}

      <SettingsMenu config={config} headers={headers} onUpdate={handleConfigUpdate} isOpen={isSettingsOpen} setIsOpen={setIsSettingsOpen} isRefreshing={loading} />
    </div>
  );
};

export default App;
